SCRIPTS = {'FULL_OPEN_SEA_FIXED10HOLES_ENV_SWEEP.py': '#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n"""\nFULL_OPEN_SEA_HOLECOUNT_SWEEP_FIXED_TOTAL.py\n\nPurpose\n-------\nFull rewritten one-file pipeline for testing CHANGE and DIVERSITY after open-sea release.\n\nThis script does all steps in one run:\n1. Generate protocell-like 3D delayed-field components in multiple physically separated pores.\n2. Build multiple separated pores first, then release the multi-pore state into open sea.\n   This avoids the invalid design of waiting for multiple components inside a single fusing pore.\n3. Save open-sea snapshots automatically as compressed NPZ files.\n4. Detect membrane-like components from B/T fields at every open-sea sample.\n5. Track components by voxel-level overlap.\n6. Quantify component-level temporal change.\n7. Quantify population-level morphological/internal/motility diversity.\n8. Write CSVs, figures, and a consolidated Markdown report.\n\nThis script deliberately does NOT test evolution, selection, adaptation, species formation,\nfitness improvement, or genetic inheritance. It tests only:\n- change over time\n- diversity among components\n- diversity change after release into open sea\n\nExpected command\n----------------\ncd ~/Desktop\npython3 -u FULL_OPEN_SEA_HOLECOUNT_SWEEP_FIXED_TOTAL.py \\\n  --mode full \\\n  --outdir ~/Desktop/full_open_sea_change_diversity_results \\\n  2>&1 | tee ~/Desktop/full_open_sea_change_diversity.log\n\nModes\n-----\nsmoke : very small check, fast\nquick : moderate run\nfull  : closest to the paper-scale assay with multi-component release trigger\n\nOutputs\n-------\noutdir/\n  run_progress.log\n  analysis_parameters.json\n  open_sea_snapshots/\n    open_sea_step_000000.npz\n    ...\n  component_traits_over_time.csv\n  component_overlap_audit.csv\n  component_events.csv\n  population_diversity_timeseries.csv\n  component_change_summary.csv\n  pca_component_trait_space.csv\n  change_and_diversity_report.md\n  figures/\n    component_count_timeseries.png\n    diversity_timeseries.png\n    pca_trait_space.png\n    largest_component_volume_timeseries.png\n\nVersion\n-------\n2026-06-05-holecount-sweep-fixed-total\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport csv\nimport json\nimport math\nimport os\nimport sys\nimport time\nimport traceback\nfrom dataclasses import dataclass, asdict\nfrom pathlib import Path\nfrom typing import Any, Dict, Iterable, List, Optional, Tuple\n\nimport numpy as np\n\ntry:\n    from scipy import ndimage as ndi\n    SCIPY_AVAILABLE = True\nexcept Exception:\n    ndi = None\n    SCIPY_AVAILABLE = False\n\ntry:\n    import matplotlib\n    matplotlib.use("Agg")\n    import matplotlib.pyplot as plt\n    MATPLOTLIB_AVAILABLE = True\nexcept Exception:\n    plt = None\n    MATPLOTLIB_AVAILABLE = False\n\n\nVERSION = "2026-06-05-holecount-sweep-fixed-total-numpy2-fixed"\n\n\n# =============================================================================\n# Utility\n# =============================================================================\n\nclass ProgressLogger:\n    def __init__(self, outdir: Path):\n        self.t0 = time.time()\n        self.outdir = outdir\n        self.outdir.mkdir(parents=True, exist_ok=True)\n        self.log_path = outdir / "run_progress.log"\n        self.fp = open(self.log_path, "w", encoding="utf-8")\n\n    def log(self, msg: str) -> None:\n        elapsed = time.time() - self.t0\n        line = f"[{elapsed:9.1f}s] {msg}"\n        print(line, flush=True)\n        self.fp.write(line + "\\n")\n        self.fp.flush()\n\n    def close(self) -> None:\n        try:\n            self.fp.close()\n        except Exception:\n            pass\n\n\ndef json_safe(value: Any) -> Any:\n    """Recursively convert Path/NumPy values so json.dump never fails."""\n    if isinstance(value, Path):\n        return str(value.expanduser())\n    if isinstance(value, np.ndarray):\n        return value.tolist()\n    if isinstance(value, np.integer):\n        return int(value)\n    if isinstance(value, np.floating):\n        return float(value)\n    if isinstance(value, np.bool_):\n        return bool(value)\n    if isinstance(value, dict):\n        return {str(k): json_safe(v) for k, v in value.items()}\n    if isinstance(value, (list, tuple)):\n        return [json_safe(v) for v in value]\n    return value\n\n\ndef ensure_dir(p: Path) -> Path:\n    p.mkdir(parents=True, exist_ok=True)\n    return p\n\n\ndef write_csv(path: Path, rows: List[Dict[str, Any]], fieldnames: Optional[List[str]] = None) -> None:\n    path.parent.mkdir(parents=True, exist_ok=True)\n    if fieldnames is None:\n        keys = []\n        seen = set()\n        for row in rows:\n            for k in row.keys():\n                if k not in seen:\n                    keys.append(k)\n                    seen.add(k)\n        fieldnames = keys\n    with open(path, "w", newline="", encoding="utf-8") as f:\n        w = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")\n        w.writeheader()\n        for row in rows:\n            w.writerow({k: json_safe(row.get(k, "")) for k in fieldnames})\n\n\ndef read_npz(path: Path) -> Dict[str, np.ndarray]:\n    with np.load(path, allow_pickle=False) as data:\n        return {k: data[k] for k in data.files}\n\n\ndef sigmoid(x: np.ndarray | float) -> np.ndarray | float:\n    return 1.0 / (1.0 + np.exp(-x))\n\n\ndef clip01(a: np.ndarray) -> np.ndarray:\n    return np.clip(a, 0.0, 1.0)\n\n\ndef laplacian6(a: np.ndarray) -> np.ndarray:\n    return (\n        np.roll(a, 1, axis=0) + np.roll(a, -1, axis=0)\n        + np.roll(a, 1, axis=1) + np.roll(a, -1, axis=1)\n        + np.roll(a, 1, axis=2) + np.roll(a, -1, axis=2)\n        - 6.0 * a\n    )\n\n\ndef mean6(a: np.ndarray) -> np.ndarray:\n    return (\n        np.roll(a, 1, axis=0) + np.roll(a, -1, axis=0)\n        + np.roll(a, 1, axis=1) + np.roll(a, -1, axis=1)\n        + np.roll(a, 1, axis=2) + np.roll(a, -1, axis=2)\n    ) / 6.0\n\n\ndef grad3(a: np.ndarray) -> Tuple[np.ndarray, np.ndarray, np.ndarray]:\n    gx = 0.5 * (np.roll(a, -1, axis=0) - np.roll(a, 1, axis=0))\n    gy = 0.5 * (np.roll(a, -1, axis=1) - np.roll(a, 1, axis=1))\n    gz = 0.5 * (np.roll(a, -1, axis=2) - np.roll(a, 1, axis=2))\n    return gx, gy, gz\n\n\ndef gradmag3(a: np.ndarray) -> np.ndarray:\n    gx, gy, gz = grad3(a)\n    return np.sqrt(gx * gx + gy * gy + gz * gz)\n\n\ndef advect_upwind(a: np.ndarray, vx: np.ndarray, vy: np.ndarray, vz: np.ndarray) -> np.ndarray:\n    # Stable, low-order upwind advection.\n    ax_back = a - np.roll(a, 1, axis=0)\n    ax_forw = np.roll(a, -1, axis=0) - a\n    ay_back = a - np.roll(a, 1, axis=1)\n    ay_forw = np.roll(a, -1, axis=1) - a\n    az_back = a - np.roll(a, 1, axis=2)\n    az_forw = np.roll(a, -1, axis=2) - a\n    return -(\n        np.where(vx >= 0, vx * ax_back, vx * ax_forw)\n        + np.where(vy >= 0, vy * ay_back, vy * ay_forw)\n        + np.where(vz >= 0, vz * az_back, vz * az_forw)\n    )\n\n\ndef sponge_mask(shape: Tuple[int, int, int], width: int = 5) -> np.ndarray:\n    n = shape[0]\n    grid = np.indices(shape)\n    dist = np.minimum.reduce([\n        grid[0], grid[1], grid[2],\n        n - 1 - grid[0], n - 1 - grid[1], n - 1 - grid[2]\n    ]).astype(np.float32)\n    s = np.clip((width - dist) / max(width, 1), 0.0, 1.0)\n    return s\n\n\ndef normalize(a: np.ndarray, eps: float = 1e-12) -> np.ndarray:\n    lo = float(np.min(a))\n    hi = float(np.max(a))\n    if hi - lo < eps:\n        return np.zeros_like(a, dtype=np.float32)\n    return ((a - lo) / (hi - lo)).astype(np.float32)\n\n\n# =============================================================================\n# Environment and simulation\n# =============================================================================\n\n@dataclass\nclass SimConfig:\n    seed: int\n    hole_count: int\n    fixed_total_pore: bool\n    reference_hole_count: int\n    confined_n: int\n    open_n: int\n    pre_steps: int\n    gen_steps: int\n    open_steps: int\n    sample_every: int\n    dt: float\n    b_threshold: float\n    t_threshold: float\n    min_component_voxels: int\n    min_lumen_voxels: int\n    source_regime: str\n    recenter: bool\n    save_float16: bool\n    release_min_components: int\n    release_check_every: int\n    release_min_gen_step: int\n    release_max_largest_fraction: float\n    release_fallback: str\n\n\ndef gaussian_mixture_3d(n: int, rng: np.random.Generator, count: int, sigma_range: Tuple[float, float]) -> np.ndarray:\n    x, y, z = np.indices((n, n, n), dtype=np.float32)\n    field = np.zeros((n, n, n), dtype=np.float32)\n    for _ in range(count):\n        cx, cy, cz = rng.uniform(0.15 * n, 0.85 * n, size=3)\n        sx = rng.uniform(sigma_range[0] * n, sigma_range[1] * n)\n        sy = rng.uniform(sigma_range[0] * n, sigma_range[1] * n)\n        sz = rng.uniform(sigma_range[0] * n, sigma_range[1] * n)\n        amp = rng.uniform(0.6, 1.2)\n        d = ((x - cx) / sx) ** 2 + ((y - cy) / sy) ** 2 + ((z - cz) / sz) ** 2\n        field += amp * np.exp(-0.5 * d).astype(np.float32)\n    return normalize(field)\n\n\n@dataclass\nclass Environment3D:\n    pore: np.ndarray\n    mineral: np.ndarray\n    residence: np.ndarray\n    vent: np.ndarray\n    pressure: np.ndarray\n    vx: np.ndarray\n    vy: np.ndarray\n    vz: np.ndarray\n    shear: np.ndarray\n    source_shape: np.ndarray\n\n\ndef multipore_centers(n: int, hole_count: int) -> List[Tuple[float, float, float]]:\n    """Deterministic, physically separated pore centers.\n\n    Centers are selected by farthest-point sampling from a 3 x 3 x 3 candidate grid.\n    This keeps the placement rule fixed across 4, 6, and 8-hole conditions and avoids\n    post hoc visual tuning.\n    """\n    if hole_count < 1:\n        raise ValueError("hole_count must be >= 1")\n    if hole_count > 12:\n        raise ValueError("hole_count > 12 is intentionally disallowed for this assay")\n    levels = np.array([0.24, 0.50, 0.76], dtype=np.float64) * float(n)\n    candidates = np.array([(x, y, z) for x in levels for y in levels for z in levels], dtype=np.float64)\n    # Prefer separated corner-like basins first; then add farthest remaining points.\n    chosen = [np.array([0.24*n, 0.24*n, 0.24*n], dtype=np.float64)]\n    while len(chosen) < hole_count:\n        best_i = None\n        best_d = -1.0\n        for i, c in enumerate(candidates):\n            if any(np.linalg.norm(c - q) < 1e-9 for q in chosen):\n                continue\n            d = min(float(np.linalg.norm(c - q)) for q in chosen)\n            # mild center penalty prevents early central bridging when alternatives are equivalent\n            center_penalty = 0.03 * float(np.linalg.norm(c - np.array([0.5*n, 0.5*n, 0.5*n])))\n            score = d + center_penalty\n            if score > best_d:\n                best_d = score\n                best_i = i\n        chosen.append(candidates[best_i])\n    return [tuple(float(v) for v in c) for c in chosen]\n\n\ndef separated_gaussian_pores(\n    n: int,\n    rng: np.random.Generator,\n    hole_count: int,\n    fixed_total_pore: bool = True,\n    reference_hole_count: int = 4,\n) -> Tuple[np.ndarray, np.ndarray, np.ndarray]:\n    """Return pore field, mineral field, and strict pore mask for separated holes.\n\n    If fixed_total_pore=True, per-hole radius is scaled by\n    (reference_hole_count / hole_count)^(1/3). This approximately fixes total pore/\n    resource volume while varying the number of holes.\n    """\n    x, y, z = np.indices((n, n, n), dtype=np.float32)\n    pore = np.zeros((n, n, n), dtype=np.float32)\n    mineral = np.zeros_like(pore)\n    strict_mask = np.zeros_like(pore)\n    centers = multipore_centers(n, hole_count)\n    radius_scale = (float(reference_hole_count) / float(hole_count)) ** (1.0 / 3.0) if fixed_total_pore else 1.0\n    # Clamp prevents tiny holes becoming numerically unstable at high hole counts.\n    radius_scale = float(np.clip(radius_scale, 0.68, 1.18))\n    for j, (cx, cy, cz) in enumerate(centers):\n        sx = rng.uniform(0.060 * n, 0.080 * n) * radius_scale\n        sy = rng.uniform(0.060 * n, 0.080 * n) * radius_scale\n        sz = rng.uniform(0.060 * n, 0.080 * n) * radius_scale\n        d = ((x - cx) / sx) ** 2 + ((y - cy) / sy) ** 2 + ((z - cz) / sz) ** 2\n        g = np.exp(-0.5 * d).astype(np.float32)\n        pore = np.maximum(pore, g)\n        mineral = np.maximum(mineral, (0.85 + 0.10 * rng.random()) * g)\n        strict_mask = np.maximum(strict_mask, (g > 0.16).astype(np.float32))\n    pore = normalize(pore)\n    mineral = normalize(mineral)\n    return pore.astype(np.float32), mineral.astype(np.float32), strict_mask.astype(np.float32)\n\n\ndef make_confined_environment(n: int, rng: np.random.Generator, cfg: SimConfig) -> Environment3D:\n    # Multi-pore environment: separated microtopographic holes rather than one\n    # continuous fusing basin. Hole count is an experimental condition.\n    pore, mineral, pore_mask = separated_gaussian_pores(\n        n,\n        rng,\n        hole_count=cfg.hole_count,\n        fixed_total_pore=cfg.fixed_total_pore,\n        reference_hole_count=cfg.reference_hole_count,\n    )\n    rough = normalize(gradmag3(pore))\n\n    # High residence only inside the separated holes. Outside the holes, residence\n    # stays low to prevent the whole lattice from becoming one membrane sheet.\n    residence = clip01(0.025 + pore_mask * (0.72 * pore + 0.28 * mineral) - 0.10 * rough)\n    vent = clip01(pore_mask * (0.08 + 0.70 * pore + 0.22 * mineral) + 0.01 * rng.random((n, n, n), dtype=np.float32))\n\n    # Pressure/shear barrier outside holes reduces bridging between basins.\n    outside = 1.0 - pore_mask\n    pressure = clip01(0.20 * normalize(gradmag3(pore)) + 0.55 * outside + 0.05 * rng.random((n, n, n), dtype=np.float32))\n\n    base = rng.normal(0, 1, size=3)\n    base = base / (np.linalg.norm(base) + 1e-12)\n    flow_speed = 0.014\n    atten = np.clip(1.0 - 0.80 * residence + 0.35 * outside, 0.15, 1.25)\n    vx = (flow_speed * base[0] * atten + 0.003 * rng.normal(size=(n, n, n))).astype(np.float32)\n    vy = (flow_speed * base[1] * atten + 0.003 * rng.normal(size=(n, n, n))).astype(np.float32)\n    vz = (flow_speed * base[2] * atten + 0.003 * rng.normal(size=(n, n, n))).astype(np.float32)\n    shear = clip01(normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz)) + 0.35 * outside)\n\n    source_shape = clip01(pore_mask * normalize(0.55 * vent + 0.35 * pore + 0.10 * mineral))\n    return Environment3D(pore, mineral, residence, vent, pressure, vx, vy, vz, shear, source_shape)\n\n\ndef make_open_environment(n: int, rng: np.random.Generator, source_regime: str) -> Environment3D:\n    # Open sea: weak spatial structure, directional flow, peripheral sponge handled separately.\n    pore = np.zeros((n, n, n), dtype=np.float32)\n    mineral = np.zeros_like(pore)\n    residence = np.full_like(pore, 0.04, dtype=np.float32)\n    vent = np.zeros_like(pore)\n    pressure = normalize(gaussian_mixture_3d(n, rng, max(2, n // 18), (0.15, 0.30)))\n\n    base = rng.normal(0, 1, size=3)\n    base = base / (np.linalg.norm(base) + 1e-12)\n    speed = 0.030\n    vx = (speed * base[0] + 0.006 * rng.normal(size=(n, n, n))).astype(np.float32)\n    vy = (speed * base[1] + 0.006 * rng.normal(size=(n, n, n))).astype(np.float32)\n    vz = (speed * base[2] + 0.006 * rng.normal(size=(n, n, n))).astype(np.float32)\n    shear = normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz))\n\n    if source_regime == "continuous":\n        source_shape = normalize(gaussian_mixture_3d(n, rng, max(3, n // 16), (0.12, 0.25)))\n    elif source_regime == "low":\n        source_shape = 0.15 * normalize(gaussian_mixture_3d(n, rng, max(3, n // 16), (0.12, 0.25)))\n    elif source_regime == "none":\n        source_shape = np.zeros((n, n, n), dtype=np.float32)\n    else:\n        raise ValueError(f"unknown source_regime: {source_regime}")\n\n    return Environment3D(pore, mineral, residence, vent, pressure, vx, vy, vz, shear, source_shape.astype(np.float32))\n\n\n@dataclass\nclass Fields:\n    R: np.ndarray\n    L: np.ndarray\n    H: np.ndarray\n    X: np.ndarray\n    M: np.ndarray\n    B: np.ndarray\n    T: np.ndarray\n\n\ndef init_fields(n: int, rng: np.random.Generator, env: Environment3D) -> Fields:\n    noise = lambda scale: (scale * rng.random((n, n, n), dtype=np.float32)).astype(np.float32)\n    # Keep background lipid/resource low. Otherwise the outside space slowly fills\n    # and separated pores bridge into one component.\n    local = np.clip(env.source_shape + 0.50 * env.mineral + 0.35 * env.residence, 0.0, 1.0).astype(np.float32)\n    R = clip01(0.035 + 0.60 * env.source_shape + 0.06 * noise(1.0)).astype(np.float32)\n    H = clip01(0.025 + 0.52 * env.vent + 0.04 * noise(1.0)).astype(np.float32)\n    X = clip01(0.015 + 0.018 * noise(1.0)).astype(np.float32)\n    L = clip01(0.018 + 0.62 * env.mineral + 0.30 * env.residence + 0.035 * noise(1.0)).astype(np.float32)\n    M = (0.035 * rng.normal(size=(n, n, n)) * (0.25 + local)).astype(np.float32)\n    B = clip01(0.004 + 0.035 * env.mineral + 0.010 * noise(1.0)).astype(np.float32)\n    T = clip01(0.002 + 0.014 * env.mineral + 0.005 * noise(1.0)).astype(np.float32)\n    return Fields(R=R, L=L, H=H, X=X, M=M, B=B, T=T)\n\n\ndef permeability(B: np.ndarray, T: np.ndarray, pressure: np.ndarray) -> np.ndarray:\n    P = np.exp(-3.0 * T - 1.8 * B - 0.55 * pressure)\n    return np.clip(P, 0.04, 1.0).astype(np.float32)\n\n\ndef update_fields(f: Fields, env: Environment3D, rng: np.random.Generator, cfg: SimConfig, phase: str) -> None:\n    dt = cfg.dt\n    B, T, M, R, L, H, X = f.B, f.T, f.M, f.R, f.L, f.H, f.X\n    P = permeability(B, T, env.pressure)\n\n    # Effective diffusion.\n    interface = gradmag3(B + 0.5 * T)\n    diff_mod = np.clip(P * (1.0 - 0.35 * B) + 0.10 * env.residence, 0.02, 1.0).astype(np.float32)\n    D_R = 0.065 * diff_mod\n    D_L = 0.035 * diff_mod\n    D_H = 0.052 * diff_mod\n    D_X = 0.060 * diff_mod\n    D_M = 0.024 * diff_mod\n\n    if phase == "confined_pre":\n        SR = 0.018 * env.source_shape\n        SH = 0.015 * env.vent\n        SX = np.zeros_like(R)\n        flow_strength = 0.30\n    elif phase == "confined_gen":\n        SR = 0.040 * env.source_shape\n        SH = 0.028 * env.vent\n        SX = 0.010 * normalize(gradmag3(env.source_shape))\n        flow_strength = 0.70\n    elif phase == "open":\n        SR = 0.035 * env.source_shape\n        SH = 0.008 * env.source_shape\n        SX = np.zeros_like(R)\n        flow_strength = 1.00\n    else:\n        raise ValueError(phase)\n\n    adv_R = advect_upwind(R, env.vx, env.vy, env.vz)\n    adv_L = advect_upwind(L, env.vx, env.vy, env.vz)\n    adv_H = advect_upwind(H, env.vx, env.vy, env.vz)\n    adv_X = advect_upwind(X, env.vx, env.vy, env.vz)\n    adv_M = advect_upwind(M, env.vx, env.vy, env.vz)\n    adv_B = advect_upwind(B, env.vx, env.vy, env.vz)\n    adv_T = advect_upwind(T, env.vx, env.vy, env.vz)\n\n    # Resource/hydrothermal/waste/lipid.\n    lipid_consumption = 0.055 * L * (0.35 * B + 0.65 * T + 0.05)\n    lipid_release = 0.026 * X * (B + 0.5 * T)\n\n    dR = D_R * laplacian6(R) + flow_strength * 0.018 * adv_R + SR - 0.010 * R - 0.020 * R * (B + 0.25 * np.abs(M))\n    dH = D_H * laplacian6(H) + flow_strength * 0.018 * adv_H + SH - 0.009 * H - 0.010 * H * B\n    dX = D_X * laplacian6(X) + flow_strength * 0.018 * adv_X + SX + 0.018 * (R * B + H * T) - 0.028 * X\n    dL = D_L * laplacian6(L) + flow_strength * 0.018 * adv_L - lipid_consumption + lipid_release - 0.009 * L\n\n    # Delayed-retention field surrogate: local M recurrence plus field forcing.\n    # This is not an evolutionary or reward term. It only preserves delayed local-field dynamics.\n    gamma_i = 1.0 + 0.40 * T + 0.15 * X + 0.25 * env.shear\n    beta_i = 2.0 + 0.50 * T - 0.45 * P - 0.20 * env.shear\n    M_neighbor = mean6(M)\n    noise = 0.045 * rng.normal(size=M.shape).astype(np.float32)\n    dM = (\n        D_M * laplacian6(M)\n        + flow_strength * 0.018 * adv_M\n        - gamma_i * M\n        + beta_i * np.tanh(M_neighbor)\n        + 0.024 * R\n        - 0.017 * X\n        + noise\n    )\n\n    # Membrane density and thickness.\n    chem = 0.45 * R + 0.35 * H - 0.30 * X + 0.25 * L\n    chem_grad = gradmag3(chem)\n    basal_agg = 0.018 * L * (R + 0.2)\n    residence_agg = 0.085 * L * env.residence\n    mineral_agg = 0.040 * L * env.mineral\n    interface_agg = 0.055 * L * interface\n    self_agg = 0.050 * B * (1.0 - B)\n    cohesion = 0.045 * (mean6(B) - B)\n    m_feedback = 0.018 * np.tanh(np.abs(M)) * L\n    frag = 0.060 * B * (0.60 * X + 0.50 * env.shear + 0.35 * gradmag3(env.pressure))\n    turnover_B = 0.009 * B\n    water_carry_B = flow_strength * 0.010 * adv_B\n\n    dB = basal_agg + residence_agg + mineral_agg + interface_agg + self_agg + cohesion + m_feedback - frag - turnover_B + water_carry_B\n\n    thick_growth = (\n        0.055 * L * B\n        + 0.080 * B * np.maximum(mean6(B) - 0.10, 0.0)\n        + 0.016 * np.abs(M) * B\n        + 0.020 * env.pressure * B\n    )\n    thick_loss = (\n        0.058 * env.shear * T\n        + 0.038 * gradmag3(env.pressure) * T\n        + 0.090 * sigmoid(18.0 * (T - 0.34)) * T\n        + 0.024 * interface * T\n        + 0.016 * T\n    )\n    smooth_T = 0.014 * (mean6(T) - T)\n    water_carry_T = flow_strength * 0.010 * adv_T\n    dT = thick_growth - thick_loss + smooth_T + water_carry_T\n\n    f.R = clip01(R + dt * dR).astype(np.float32)\n    f.H = clip01(H + dt * dH).astype(np.float32)\n    f.X = clip01(X + dt * dX).astype(np.float32)\n    f.L = clip01(L + dt * dL).astype(np.float32)\n    f.M = np.clip(M + dt * dM, -8.0, 8.0).astype(np.float32)\n    f.B = clip01(B + dt * dB).astype(np.float32)\n    f.T = clip01(T + dt * dT).astype(np.float32)\n\n    # Absorbing peripheral sponge for open sea.\n    if phase == "open":\n        s = sponge_mask(f.B.shape, width=5)\n        absorption = 0.12 * s\n        for name in ["R", "L", "H", "X", "B", "T"]:\n            arr = getattr(f, name)\n            setattr(f, name, (arr * (1.0 - absorption)).astype(np.float32))\n        f.M = (f.M * (1.0 - absorption)).astype(np.float32)\n\n\ndef detect_labels(mask: np.ndarray) -> Tuple[np.ndarray, int]:\n    if SCIPY_AVAILABLE:\n        structure = np.ones((3, 3, 3), dtype=np.int8)\n        labels, nlab = ndi.label(mask, structure=structure)\n        return labels.astype(np.int32, copy=False), int(nlab)\n\n    # Fallback connected components. Slower but dependency-free.\n    labels = np.zeros(mask.shape, dtype=np.int32)\n    n = mask.shape[0]\n    current = 0\n    coords = np.argwhere(mask)\n    neigh = [(dx, dy, dz) for dx in (-1, 0, 1) for dy in (-1, 0, 1) for dz in (-1, 0, 1) if not (dx == dy == dz == 0)]\n    for x, y, z in coords:\n        if labels[x, y, z] != 0:\n            continue\n        current += 1\n        stack = [(int(x), int(y), int(z))]\n        labels[x, y, z] = current\n        while stack:\n            cx, cy, cz = stack.pop()\n            for dx, dy, dz in neigh:\n                nx, ny, nz = cx + dx, cy + dy, cz + dz\n                if 0 <= nx < n and 0 <= ny < n and 0 <= nz < n and mask[nx, ny, nz] and labels[nx, ny, nz] == 0:\n                    labels[nx, ny, nz] = current\n                    stack.append((nx, ny, nz))\n    return labels, current\n\n\ndef filter_small_labels(labels: np.ndarray, min_size: int) -> Tuple[np.ndarray, Dict[int, int]]:\n    if labels.max() == 0:\n        return labels.astype(np.int32), {}\n    counts = np.bincount(labels.ravel())\n    keep_old = np.where(counts >= min_size)[0]\n    keep_old = keep_old[keep_old != 0]\n    out = np.zeros_like(labels, dtype=np.int32)\n    size_map = {}\n    new_id = 0\n    for old in keep_old:\n        new_id += 1\n        out[labels == old] = new_id\n        size_map[new_id] = int(counts[old])\n    return out, size_map\n\n\ndef summarize_components_for_release(B: np.ndarray, T: np.ndarray, cfg: SimConfig) -> Dict[str, Any]:\n    """Return component count and largest fraction under the fixed membrane definition."""\n    mask = (B >= cfg.b_threshold) & (T >= cfg.t_threshold)\n    labels, _ = detect_labels(mask)\n    labels, sizes = filter_small_labels(labels, cfg.min_component_voxels)\n    total = int(sum(sizes.values()))\n    count = int(len(sizes))\n    largest = int(max(sizes.values())) if sizes else 0\n    frac = float(largest / total) if total > 0 else 0.0\n    return {\n        "component_count": count,\n        "total_membrane_voxels": total,\n        "largest_component_voxels": largest,\n        "largest_component_fraction": frac,\n    }\n\n\ndef release_trigger_met(summary: Dict[str, Any], cfg: SimConfig) -> bool:\n    """Fixed trigger: release only when multiple components exist before saturation."""\n    if int(summary["component_count"]) < int(cfg.release_min_components):\n        return False\n    max_frac = float(cfg.release_max_largest_fraction)\n    if max_frac > 0 and float(summary["largest_component_fraction"]) > max_frac:\n        return False\n    return True\n\n\ndef largest_component_centroid(B: np.ndarray, T: np.ndarray, cfg: SimConfig) -> Optional[np.ndarray]:\n    mask = (B >= cfg.b_threshold) & (T >= cfg.t_threshold)\n    labels, _ = detect_labels(mask)\n    labels, sizes = filter_small_labels(labels, cfg.min_component_voxels)\n    if not sizes:\n        return None\n    lab = max(sizes, key=sizes.get)\n    pts = np.argwhere(labels == lab)\n    if pts.size == 0:\n        return None\n    w = (B[labels == lab] + T[labels == lab] + 1e-6).astype(np.float64)\n    c = np.average(pts.astype(np.float64), axis=0, weights=w)\n    return c\n\n\ndef recenter_fields_if_needed(f: Fields, cfg: SimConfig, logger: ProgressLogger, step: int, margin: int = 14) -> Tuple[int, int, int]:\n    if not cfg.recenter:\n        return (0, 0, 0)\n    c = largest_component_centroid(f.B, f.T, cfg)\n    if c is None:\n        return (0, 0, 0)\n    n = f.B.shape[0]\n    center = np.array([n // 2, n // 2, n // 2], dtype=np.float64)\n    low_margin = np.min(c)\n    high_margin = np.min((n - 1) - c)\n    if low_margin >= margin and high_margin >= margin:\n        return (0, 0, 0)\n    shift = np.round(center - c).astype(int)\n    if np.linalg.norm(shift) < 6:\n        return (0, 0, 0)\n    for name in ["R", "L", "H", "X", "M", "B", "T"]:\n        arr = getattr(f, name)\n        setattr(f, name, np.roll(arr, shift=tuple(shift), axis=(0, 1, 2)).astype(np.float32))\n    logger.log(f"open step {step}: recentered fields by shift={tuple(int(x) for x in shift)}")\n    return tuple(int(x) for x in shift)\n\n\ndef embed_center(f: Fields, open_n: int) -> Fields:\n    old_n = f.B.shape[0]\n    if open_n < old_n:\n        raise ValueError("open_n must be >= confined_n")\n    start = (open_n - old_n) // 2\n    sl = slice(start, start + old_n)\n\n    def embed(arr: np.ndarray, fill: float = 0.0) -> np.ndarray:\n        out = np.full((open_n, open_n, open_n), fill, dtype=np.float32)\n        out[sl, sl, sl] = arr.astype(np.float32)\n        return out\n\n    return Fields(\n        R=embed(f.R, 0.04),\n        L=embed(f.L, 0.00),\n        H=embed(f.H, 0.02),\n        X=embed(f.X, 0.00),\n        M=embed(f.M, 0.00),\n        B=embed(f.B, 0.00),\n        T=embed(f.T, 0.00),\n    )\n\n\ndef save_snapshot(snapdir: Path, step: int, f: Fields, cfg: SimConfig, recenter_shift: Tuple[int, int, int] = (0, 0, 0)) -> None:\n    snapdir.mkdir(parents=True, exist_ok=True)\n    dtype = np.float16 if cfg.save_float16 else np.float32\n    np.savez_compressed(\n        snapdir / f"open_sea_step_{step:06d}.npz",\n        step=np.array(step, dtype=np.int32),\n        recenter_shift=np.array(recenter_shift, dtype=np.int32),\n        B=f.B.astype(dtype),\n        T=f.T.astype(dtype),\n        M=f.M.astype(dtype),\n        R=f.R.astype(dtype),\n        X=f.X.astype(dtype),\n    )\n\n\n# =============================================================================\n# Component trait extraction and tracking\n# =============================================================================\n\nTRAIT_COLUMNS = [\n    "volume",\n    "surface_area",\n    "compactness",\n    "elongation",\n    "planarity",\n    "bbox_x",\n    "bbox_y",\n    "bbox_z",\n    "mean_B",\n    "mean_T",\n    "var_T",\n    "mean_abs_M",\n    "std_abs_M",\n    "mean_R",\n    "mean_X",\n    "lumen_count",\n    "lumen_volume",\n    "lumen_volume_fraction",\n    "step_displacement",\n    "cumulative_path",\n    "net_displacement",\n    "persistence_ratio",\n]\n\n\ndef component_surface_area(mask: np.ndarray) -> int:\n    # 6-neighbor exposed faces.\n    vol = int(mask.sum())\n    if vol == 0:\n        return 0\n    area = 0\n    for axis in range(3):\n        area += int(np.sum(mask & (~np.roll(mask, 1, axis=axis))))\n        area += int(np.sum(mask & (~np.roll(mask, -1, axis=axis))))\n    return area\n\n\ndef component_shape_traits(points: np.ndarray, max_points: int = 6000) -> Tuple[float, float, Tuple[int, int, int]]:\n    if points.shape[0] < 3:\n        return 0.0, 0.0, (0, 0, 0)\n    mins = points.min(axis=0)\n    maxs = points.max(axis=0)\n    bbox = tuple(int(x) for x in (maxs - mins + 1))\n\n    pts = points\n    if pts.shape[0] > max_points:\n        idx = np.linspace(0, pts.shape[0] - 1, max_points).astype(int)\n        pts = pts[idx]\n    centered = pts.astype(np.float64) - pts.mean(axis=0, keepdims=True)\n    cov = centered.T @ centered / max(len(pts) - 1, 1)\n    vals = np.linalg.eigvalsh(cov)\n    vals = np.sort(np.maximum(vals, 0.0))[::-1]\n    l1, l2, l3 = vals + 1e-12\n    elongation = float((l1 - l2) / l1)\n    planarity = float((l2 - l3) / l1)\n    return elongation, planarity, bbox\n\n\ndef lumen_traits(component_mask: np.ndarray, min_lumen_voxels: int) -> Tuple[int, int]:\n    # Internal lumens inside component bounding box. Non-membrane regions not connected to bbox border.\n    if component_mask.sum() == 0:\n        return 0, 0\n    coords = np.argwhere(component_mask)\n    mins = np.maximum(coords.min(axis=0) - 1, 0)\n    maxs = np.minimum(coords.max(axis=0) + 2, np.array(component_mask.shape))\n    sub = component_mask[mins[0]:maxs[0], mins[1]:maxs[1], mins[2]:maxs[2]]\n    non = ~sub\n\n    labels, nlab = detect_labels(non)\n    if nlab == 0:\n        return 0, 0\n\n    border_labels = set()\n    for face in [\n        labels[0, :, :], labels[-1, :, :],\n        labels[:, 0, :], labels[:, -1, :],\n        labels[:, :, 0], labels[:, :, -1],\n    ]:\n        border_labels.update(int(x) for x in np.unique(face) if x != 0)\n\n    counts = np.bincount(labels.ravel())\n    lumen_count = 0\n    lumen_volume = 0\n    for lab in range(1, len(counts)):\n        if lab in border_labels:\n            continue\n        c = int(counts[lab])\n        if c >= min_lumen_voxels:\n            lumen_count += 1\n            lumen_volume += c\n    return lumen_count, lumen_volume\n\n\n@dataclass\nclass TrackState:\n    track_id: int\n    first_step: int\n    last_step: int\n    first_centroid_x: float\n    first_centroid_y: float\n    first_centroid_z: float\n    prev_centroid_x: float\n    prev_centroid_y: float\n    prev_centroid_z: float\n    cumulative_path: float\n    observations: int\n\n\nclass ComponentTracker:\n    def __init__(self, min_overlap_voxels: int = 5):\n        self.next_track_id = 1\n        self.prev_labels: Optional[np.ndarray] = None\n        self.prev_label_to_track: Dict[int, int] = {}\n        self.tracks: Dict[int, TrackState] = {}\n        self.min_overlap_voxels = int(min_overlap_voxels)\n\n    def assign_tracks(\n        self,\n        step: int,\n        labels: np.ndarray,\n        centroids: Dict[int, Tuple[float, float, float]],\n    ) -> Tuple[Dict[int, int], List[Dict[str, Any]], List[Dict[str, Any]]]:\n        events: List[Dict[str, Any]] = []\n        overlap_rows: List[Dict[str, Any]] = []\n        curr_labels = [int(x) for x in np.unique(labels) if x != 0]\n        curr_to_track: Dict[int, int] = {}\n\n        if self.prev_labels is None:\n            for lab in curr_labels:\n                tid = self._new_track(step, centroids[lab])\n                curr_to_track[lab] = tid\n                events.append({"step": step, "event_type": "emergence", "track_id": tid, "component_label": lab})\n            self.prev_labels = labels.copy()\n            self.prev_label_to_track = curr_to_track\n            return curr_to_track, events, overlap_rows\n\n        prev = self.prev_labels\n        curr = labels\n        n_curr = int(curr.max()) + 1\n        both = (prev > 0) & (curr > 0)\n        pairs: List[Tuple[int, int, int]] = []\n        if np.any(both):\n            code = prev[both].astype(np.int64) * n_curr + curr[both].astype(np.int64)\n            uniq, counts = np.unique(code, return_counts=True)\n            for u, c in zip(uniq, counts):\n                pl = int(u // n_curr)\n                cl = int(u % n_curr)\n                if int(c) >= self.min_overlap_voxels:\n                    pairs.append((pl, cl, int(c)))\n                    overlap_rows.append({\n                        "step": step,\n                        "prev_label": pl,\n                        "curr_label": cl,\n                        "prev_track_id": self.prev_label_to_track.get(pl, -1),\n                        "overlap_voxels": int(c),\n                    })\n\n        by_curr: Dict[int, List[Tuple[int, int]]] = {}\n        by_prev: Dict[int, List[Tuple[int, int]]] = {}\n        for pl, cl, c in pairs:\n            by_curr.setdefault(cl, []).append((pl, c))\n            by_prev.setdefault(pl, []).append((cl, c))\n\n        assigned_prev_for_curr: Dict[int, int] = {}\n        for cl in curr_labels:\n            candidates = by_curr.get(cl, [])\n            if candidates:\n                candidates.sort(key=lambda x: x[1], reverse=True)\n                best_prev, best_overlap = candidates[0]\n                prev_tid = self.prev_label_to_track.get(best_prev)\n                if prev_tid is not None:\n                    curr_to_track[cl] = prev_tid\n                    assigned_prev_for_curr[cl] = best_prev\n                    self._update_track(prev_tid, step, centroids[cl])\n                    events.append({\n                        "step": step,\n                        "event_type": "continuation",\n                        "track_id": prev_tid,\n                        "component_label": cl,\n                        "parent_prev_label": best_prev,\n                        "overlap_voxels": best_overlap,\n                    })\n                    if len(candidates) > 1:\n                        events.append({\n                            "step": step,\n                            "event_type": "fusion_into_component",\n                            "track_id": prev_tid,\n                            "component_label": cl,\n                            "n_previous_components": len(candidates),\n                        })\n                else:\n                    tid = self._new_track(step, centroids[cl])\n                    curr_to_track[cl] = tid\n                    events.append({"step": step, "event_type": "emergence", "track_id": tid, "component_label": cl})\n            else:\n                tid = self._new_track(step, centroids[cl])\n                curr_to_track[cl] = tid\n                events.append({"step": step, "event_type": "emergence", "track_id": tid, "component_label": cl})\n\n        # Fission: one previous component overlapping multiple current components.\n        for pl, currs in by_prev.items():\n            if len(currs) >= 2:\n                prev_tid = self.prev_label_to_track.get(pl, -1)\n                events.append({\n                    "step": step,\n                    "event_type": "fission_from_previous",\n                    "parent_track_id": prev_tid,\n                    "prev_label": pl,\n                    "n_current_components": len(currs),\n                    "child_track_ids": ";".join(str(curr_to_track.get(cl, -1)) for cl, _ in currs),\n                })\n\n        # Extinction: previous labels with no overlap.\n        prev_labels = [int(x) for x in np.unique(prev) if x != 0]\n        prev_with_child = set(by_prev.keys())\n        for pl in prev_labels:\n            if pl not in prev_with_child:\n                tid = self.prev_label_to_track.get(pl, -1)\n                events.append({\n                    "step": step,\n                    "event_type": "extinction_or_disappearance",\n                    "track_id": tid,\n                    "prev_label": pl,\n                })\n\n        self.prev_labels = labels.copy()\n        self.prev_label_to_track = curr_to_track\n        return curr_to_track, events, overlap_rows\n\n    def _new_track(self, step: int, centroid: Tuple[float, float, float]) -> int:\n        tid = self.next_track_id\n        self.next_track_id += 1\n        cx, cy, cz = centroid\n        self.tracks[tid] = TrackState(\n            track_id=tid,\n            first_step=step,\n            last_step=step,\n            first_centroid_x=float(cx),\n            first_centroid_y=float(cy),\n            first_centroid_z=float(cz),\n            prev_centroid_x=float(cx),\n            prev_centroid_y=float(cy),\n            prev_centroid_z=float(cz),\n            cumulative_path=0.0,\n            observations=1,\n        )\n        return tid\n\n    def _update_track(self, tid: int, step: int, centroid: Tuple[float, float, float]) -> None:\n        st = self.tracks[tid]\n        cx, cy, cz = centroid\n        d = math.sqrt(\n            (float(cx) - st.prev_centroid_x) ** 2\n            + (float(cy) - st.prev_centroid_y) ** 2\n            + (float(cz) - st.prev_centroid_z) ** 2\n        )\n        st.cumulative_path += d\n        st.prev_centroid_x = float(cx)\n        st.prev_centroid_y = float(cy)\n        st.prev_centroid_z = float(cz)\n        st.last_step = step\n        st.observations += 1\n\n\ndef extract_component_traits_from_snapshot(\n    snapshot_path: Path,\n    cfg: SimConfig,\n    tracker: ComponentTracker,\n    logger: Optional[ProgressLogger] = None,\n) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], List[Dict[str, Any]]]:\n    data = read_npz(snapshot_path)\n    step = int(np.array(data["step"]).item()) if "step" in data else int(snapshot_path.stem.split("_")[-1])\n    B = data["B"].astype(np.float32)\n    T = data["T"].astype(np.float32)\n    M = data["M"].astype(np.float32)\n    R = data.get("R", np.zeros_like(B)).astype(np.float32)\n    X = data.get("X", np.zeros_like(B)).astype(np.float32)\n\n    mask = (B >= cfg.b_threshold) & (T >= cfg.t_threshold)\n    labels, _ = detect_labels(mask)\n    labels, sizes = filter_small_labels(labels, cfg.min_component_voxels)\n\n    centroids: Dict[int, Tuple[float, float, float]] = {}\n    prelim: Dict[int, Dict[str, Any]] = {}\n\n    labs = [int(x) for x in np.unique(labels) if x != 0]\n    for lab in labs:\n        cmask = labels == lab\n        pts = np.argwhere(cmask)\n        vol = int(pts.shape[0])\n        w = (B[cmask] + T[cmask] + 1e-6).astype(np.float64)\n        centroid = np.average(pts.astype(np.float64), axis=0, weights=w)\n        cx, cy, cz = (float(centroid[0]), float(centroid[1]), float(centroid[2]))\n        centroids[lab] = (cx, cy, cz)\n\n        surface = component_surface_area(cmask)\n        compactness = float((vol ** (2.0 / 3.0)) / (surface + 1e-12))\n        elongation, planarity, bbox = component_shape_traits(pts)\n        lumen_count, lumen_volume = lumen_traits(cmask, cfg.min_lumen_voxels)\n        prelim[lab] = {\n            "step": step,\n            "component_label": lab,\n            "volume": vol,\n            "surface_area": surface,\n            "compactness": compactness,\n            "elongation": elongation,\n            "planarity": planarity,\n            "bbox_x": bbox[0],\n            "bbox_y": bbox[1],\n            "bbox_z": bbox[2],\n            "centroid_x": cx,\n            "centroid_y": cy,\n            "centroid_z": cz,\n            "mean_B": float(np.mean(B[cmask])),\n            "mean_T": float(np.mean(T[cmask])),\n            "var_T": float(np.var(T[cmask])),\n            "mean_abs_M": float(np.mean(np.abs(M[cmask]))),\n            "std_abs_M": float(np.std(np.abs(M[cmask]))),\n            "mean_R": float(np.mean(R[cmask])),\n            "mean_X": float(np.mean(X[cmask])),\n            "lumen_count": int(lumen_count),\n            "lumen_volume": int(lumen_volume),\n            "lumen_volume_fraction": float(lumen_volume / max(vol, 1)),\n        }\n\n    curr_to_track, events, overlap_rows = tracker.assign_tracks(step, labels, centroids)\n\n    rows: List[Dict[str, Any]] = []\n    for lab, row in prelim.items():\n        tid = curr_to_track[lab]\n        st = tracker.tracks[tid]\n        cx, cy, cz = centroids[lab]\n        prev_d = math.sqrt(\n            (cx - st.prev_centroid_x) ** 2\n            + (cy - st.prev_centroid_y) ** 2\n            + (cz - st.prev_centroid_z) ** 2\n        )\n        # After tracker update, prev_centroid is current. The step displacement is recovered from event if possible.\n        # For first observation it is zero. For continued tracks, use current cumulative minus previous path is unavailable;\n        # therefore compute step displacement from current and previous event not stored. Keep a conservative value:\n        step_displacement = 0.0\n        if st.observations > 1:\n            # Use final event overlap as continuation marker; exact step distance is reconstructed later in change summary.\n            step_displacement = np.nan\n\n        net = math.sqrt(\n            (cx - st.first_centroid_x) ** 2\n            + (cy - st.first_centroid_y) ** 2\n            + (cz - st.first_centroid_z) ** 2\n        )\n        row["track_id"] = tid\n        row["track_first_step"] = st.first_step\n        row["track_observations"] = st.observations\n        row["cumulative_path"] = float(st.cumulative_path)\n        row["net_displacement"] = float(net)\n        row["persistence_ratio"] = float(net / st.cumulative_path) if st.cumulative_path > 1e-12 else 0.0\n        row["step_displacement"] = step_displacement\n        rows.append(row)\n\n    return rows, events, overlap_rows\n\n\ndef compute_population_diversity(component_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:\n    if not component_rows:\n        return []\n\n    # Build global z-score from all component observations.\n    X = np.array([[float(r.get(c, 0.0)) if r.get(c, "") != "" and not isinstance(r.get(c), str) else 0.0 for c in TRAIT_COLUMNS] for r in component_rows], dtype=np.float64)\n    X = np.nan_to_num(X, nan=0.0, posinf=0.0, neginf=0.0)\n    mu = X.mean(axis=0)\n    sd = X.std(axis=0)\n    sd[sd < 1e-12] = 1.0\n    Z = (X - mu) / sd\n\n    for i, r in enumerate(component_rows):\n        r["_zvec"] = Z[i]\n\n    rows: List[Dict[str, Any]] = []\n    steps = sorted(set(int(r["step"]) for r in component_rows))\n    for step in steps:\n        idx = [i for i, r in enumerate(component_rows) if int(r["step"]) == step]\n        n = len(idx)\n        sub = Z[idx, :]\n        if n <= 1:\n            mean_pairwise = 0.0\n            median_pairwise = 0.0\n            trait_dispersion = 0.0\n        else:\n            # Efficient pairwise distance for moderate component counts.\n            diffs = sub[:, None, :] - sub[None, :, :]\n            dmat = np.sqrt(np.sum(diffs * diffs, axis=2))\n            tri = dmat[np.triu_indices(n, k=1)]\n            mean_pairwise = float(np.mean(tri)) if tri.size else 0.0\n            median_pairwise = float(np.median(tri)) if tri.size else 0.0\n            trait_dispersion = float(np.mean(np.sum((sub - sub.mean(axis=0)) ** 2, axis=1)))\n\n        volumes = [float(component_rows[i]["volume"]) for i in idx]\n        mean_abs_M = [float(component_rows[i]["mean_abs_M"]) for i in idx]\n        mean_T = [float(component_rows[i]["mean_T"]) for i in idx]\n        lumens = [float(component_rows[i]["lumen_count"]) for i in idx]\n\n        rows.append({\n            "step": step,\n            "component_count": n,\n            "total_component_volume": float(np.sum(volumes)),\n            "largest_component_volume": float(np.max(volumes)) if volumes else 0.0,\n            "mean_pairwise_trait_distance": mean_pairwise,\n            "median_pairwise_trait_distance": median_pairwise,\n            "trait_dispersion": trait_dispersion,\n            "volume_cv": float(np.std(volumes) / (np.mean(volumes) + 1e-12)) if volumes else 0.0,\n            "mean_T_cv": float(np.std(mean_T) / (np.mean(mean_T) + 1e-12)) if mean_T else 0.0,\n            "mean_abs_M_cv": float(np.std(mean_abs_M) / (np.mean(mean_abs_M) + 1e-12)) if mean_abs_M else 0.0,\n            "lumen_count_mean": float(np.mean(lumens)) if lumens else 0.0,\n            "lumen_count_max": float(np.max(lumens)) if lumens else 0.0,\n        })\n    return rows\n\n\ndef compute_change_summary(component_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:\n    if not component_rows:\n        return []\n    by_track: Dict[int, List[Dict[str, Any]]] = {}\n    for r in component_rows:\n        by_track.setdefault(int(r["track_id"]), []).append(r)\n\n    rows: List[Dict[str, Any]] = []\n    for tid, rs in sorted(by_track.items()):\n        rs = sorted(rs, key=lambda x: int(x["step"]))\n        first = rs[0]\n        last = rs[-1]\n        coords = np.array([[float(r["centroid_x"]), float(r["centroid_y"]), float(r["centroid_z"])] for r in rs], dtype=np.float64)\n        if len(coords) > 1:\n            step_distances = np.sqrt(np.sum(np.diff(coords, axis=0) ** 2, axis=1))\n            path = float(np.sum(step_distances))\n        else:\n            path = 0.0\n        net = float(np.sqrt(np.sum((coords[-1] - coords[0]) ** 2)))\n        row = {\n            "track_id": tid,\n            "n_observations": len(rs),\n            "first_step": int(first["step"]),\n            "last_step": int(last["step"]),\n            "duration_steps": int(last["step"]) - int(first["step"]),\n            "path_length": path,\n            "net_displacement": net,\n            "persistence_ratio": float(net / path) if path > 1e-12 else 0.0,\n        }\n        for c in [\n            "volume", "surface_area", "compactness", "elongation", "planarity",\n            "mean_B", "mean_T", "var_T", "mean_abs_M", "std_abs_M",\n            "mean_R", "mean_X", "lumen_count", "lumen_volume_fraction"\n        ]:\n            row[f"{c}_first"] = first.get(c, 0.0)\n            row[f"{c}_last"] = last.get(c, 0.0)\n            row[f"{c}_delta"] = float(last.get(c, 0.0)) - float(first.get(c, 0.0))\n            vals = [float(r.get(c, 0.0)) for r in rs]\n            row[f"{c}_mean"] = float(np.mean(vals)) if vals else 0.0\n            row[f"{c}_sd"] = float(np.std(vals)) if vals else 0.0\n        rows.append(row)\n    return rows\n\n\ndef compute_pca_rows(component_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:\n    if not component_rows:\n        return []\n    X = np.array([[float(r.get(c, 0.0)) if r.get(c, "") != "" and not isinstance(r.get(c), str) else 0.0 for c in TRAIT_COLUMNS] for r in component_rows], dtype=np.float64)\n    X = np.nan_to_num(X, nan=0.0, posinf=0.0, neginf=0.0)\n    mu = X.mean(axis=0)\n    sd = X.std(axis=0)\n    sd[sd < 1e-12] = 1.0\n    Z = (X - mu) / sd\n    if Z.shape[0] < 2:\n        pcs = np.zeros((Z.shape[0], 2), dtype=np.float64)\n        explained = [0.0, 0.0]\n    else:\n        U, S, Vt = np.linalg.svd(Z, full_matrices=False)\n        pcs = U[:, :2] * S[:2]\n        var = S * S\n        total = float(np.sum(var))\n        explained = [float(var[i] / total) if total > 0 and i < len(var) else 0.0 for i in range(2)]\n    rows = []\n    for r, pc in zip(component_rows, pcs):\n        rows.append({\n            "step": int(r["step"]),\n            "track_id": int(r["track_id"]),\n            "component_label": int(r["component_label"]),\n            "PC1": float(pc[0]),\n            "PC2": float(pc[1]) if len(pc) > 1 else 0.0,\n            "PC1_explained_fraction": explained[0],\n            "PC2_explained_fraction": explained[1],\n            "volume": r.get("volume", 0),\n            "mean_T": r.get("mean_T", 0.0),\n            "mean_abs_M": r.get("mean_abs_M", 0.0),\n            "lumen_count": r.get("lumen_count", 0),\n        })\n    return rows\n\n\ndef make_figures(outdir: Path, diversity_rows: List[Dict[str, Any]], pca_rows: List[Dict[str, Any]]) -> None:\n    if not MATPLOTLIB_AVAILABLE:\n        return\n    figdir = ensure_dir(outdir / "figures")\n\n    if diversity_rows:\n        steps = [r["step"] for r in diversity_rows]\n        counts = [r["component_count"] for r in diversity_rows]\n        div = [r["mean_pairwise_trait_distance"] for r in diversity_rows]\n        largest = [r["largest_component_volume"] for r in diversity_rows]\n\n        plt.figure(figsize=(8, 5))\n        plt.plot(steps, counts, marker="o")\n        plt.xlabel("Open-sea step")\n        plt.ylabel("Detected component count")\n        plt.title("Component count after open-sea release")\n        plt.tight_layout()\n        plt.savefig(figdir / "component_count_timeseries.png", dpi=200)\n        plt.close()\n\n        plt.figure(figsize=(8, 5))\n        plt.plot(steps, div, marker="o")\n        plt.xlabel("Open-sea step")\n        plt.ylabel("Mean pairwise trait distance")\n        plt.title("Population trait diversity after open-sea release")\n        plt.tight_layout()\n        plt.savefig(figdir / "diversity_timeseries.png", dpi=200)\n        plt.close()\n\n        plt.figure(figsize=(8, 5))\n        plt.plot(steps, largest, marker="o")\n        plt.xlabel("Open-sea step")\n        plt.ylabel("Largest component volume")\n        plt.title("Largest component volume after open-sea release")\n        plt.tight_layout()\n        plt.savefig(figdir / "largest_component_volume_timeseries.png", dpi=200)\n        plt.close()\n\n    if pca_rows:\n        pc1 = [r["PC1"] for r in pca_rows]\n        pc2 = [r["PC2"] for r in pca_rows]\n        steps = [r["step"] for r in pca_rows]\n        plt.figure(figsize=(7, 6))\n        sc = plt.scatter(pc1, pc2, c=steps, s=16)\n        plt.xlabel("PC1")\n        plt.ylabel("PC2")\n        plt.title("Component trait space after open-sea release")\n        plt.colorbar(sc, label="Open-sea step")\n        plt.tight_layout()\n        plt.savefig(figdir / "pca_trait_space.png", dpi=200)\n        plt.close()\n\n\ndef write_report(\n    outdir: Path,\n    cfg: SimConfig,\n    component_rows: List[Dict[str, Any]],\n    diversity_rows: List[Dict[str, Any]],\n    change_rows: List[Dict[str, Any]],\n    event_rows: List[Dict[str, Any]],\n) -> None:\n    report = outdir / "change_and_diversity_report.md"\n\n    n_snap = len(set(r["step"] for r in component_rows)) if component_rows else 0\n    n_comp_obs = len(component_rows)\n    n_tracks = len(set(r["track_id"] for r in component_rows)) if component_rows else 0\n\n    if diversity_rows:\n        first_div = diversity_rows[0]["mean_pairwise_trait_distance"]\n        last_div = diversity_rows[-1]["mean_pairwise_trait_distance"]\n        max_div = max(r["mean_pairwise_trait_distance"] for r in diversity_rows)\n        first_count = diversity_rows[0]["component_count"]\n        last_count = diversity_rows[-1]["component_count"]\n        max_count = max(r["component_count"] for r in diversity_rows)\n    else:\n        first_div = last_div = max_div = 0.0\n        first_count = last_count = max_count = 0\n\n    long_tracks = [r for r in change_rows if int(r["n_observations"]) >= 3]\n    if long_tracks:\n        mean_path = float(np.mean([float(r["path_length"]) for r in long_tracks]))\n        mean_volume_delta = float(np.mean([float(r["volume_delta"]) for r in long_tracks]))\n        mean_T_delta = float(np.mean([float(r["mean_T_delta"]) for r in long_tracks]))\n        mean_M_delta = float(np.mean([float(r["mean_abs_M_delta"]) for r in long_tracks]))\n    else:\n        mean_path = mean_volume_delta = mean_T_delta = mean_M_delta = 0.0\n\n    event_counts: Dict[str, int] = {}\n    for e in event_rows:\n        et = str(e.get("event_type", "unknown"))\n        event_counts[et] = event_counts.get(et, 0) + 1\n\n    lines = []\n    lines.append("# Open-Sea Change and Diversity Assay\\n")\n    lines.append(f"Version: `{VERSION}`\\n")\n    lines.append("\\n## Scope\\n")\n    lines.append("This analysis tests change and diversity after open-sea release. It does not test evolution, selection, adaptation, species formation, or genetic inheritance.\\n")\n    lines.append("\\n## Fixed component definition\\n")\n    lines.append(f"- Membrane voxel: `B >= {cfg.b_threshold}` and `T >= {cfg.t_threshold}`\\n")\n    lines.append("- Connectivity: 26-connected 3D components\\n")\n    lines.append(f"- Minimum component size: `{cfg.min_component_voxels}` voxels\\n")\n    lines.append(f"- Minimum lumen size: `{cfg.min_lumen_voxels}` voxels\\n")\n    lines.append("- Tracking: voxel-level overlap between consecutive open-sea snapshots\\n")\n    lines.append("\\n## Simulation settings\\n")\n    for k, v in asdict(cfg).items():\n        lines.append(f"- `{k}`: `{v}`\\n")\n    lines.append("\\n## Main observations\\n")\n    lines.append(f"- Open-sea snapshots with detected components: `{n_snap}`\\n")\n    lines.append(f"- Component observations: `{n_comp_obs}`\\n")\n    lines.append(f"- Component tracks: `{n_tracks}`\\n")\n    lines.append(f"- Component count: first `{first_count}`, last `{last_count}`, maximum `{max_count}`\\n")\n    lines.append(f"- Mean pairwise trait distance: first `{first_div:.6f}`, last `{last_div:.6f}`, maximum `{max_div:.6f}`\\n")\n    lines.append(f"- Mean path length among tracks with >=3 observations: `{mean_path:.6f}`\\n")\n    lines.append(f"- Mean volume change among tracks with >=3 observations: `{mean_volume_delta:.6f}`\\n")\n    lines.append(f"- Mean membrane-thickness change among tracks with >=3 observations: `{mean_T_delta:.6f}`\\n")\n    lines.append(f"- Mean internal abs(M) change among tracks with >=3 observations: `{mean_M_delta:.6f}`\\n")\n    lines.append("\\n## Event counts\\n")\n    if event_counts:\n        for k, v in sorted(event_counts.items()):\n            lines.append(f"- `{k}`: `{v}`\\n")\n    else:\n        lines.append("- No component events detected.\\n")\n\n    lines.append("\\n## Output files\\n")\n    for fn in [\n        "component_traits_over_time.csv",\n        "component_overlap_audit.csv",\n        "component_events.csv",\n        "population_diversity_timeseries.csv",\n        "component_change_summary.csv",\n        "pca_component_trait_space.csv",\n    ]:\n        lines.append(f"- `{fn}`\\n")\n    lines.append("\\n## Interpretation boundary\\n")\n    lines.append("A positive diversity result means that open-sea components changed over time and occupied a broader trait space. It does not, by itself, establish evolution. Evolutionary claims require a separate analysis of persistence, parent-child similarity, and null-model comparison.\\n")\n\n    report.write_text("".join(lines), encoding="utf-8")\n\n\n# =============================================================================\n# Pipeline\n# =============================================================================\n\ndef run_generation_and_open_sea(cfg: SimConfig, outdir: Path, logger: ProgressLogger) -> Path:\n    rng = np.random.default_rng(cfg.seed)\n    snapdir = ensure_dir(outdir / "open_sea_snapshots")\n\n    logger.log("STEP 1/5: constructing confined environment")\n    env_conf = make_confined_environment(cfg.confined_n, rng, cfg)\n    f = init_fields(cfg.confined_n, rng, env_conf)\n\n    logger.log(f"STEP 2/5: confined preformation steps={cfg.pre_steps}")\n    for step in range(1, cfg.pre_steps + 1):\n        update_fields(f, env_conf, rng, cfg, phase="confined_pre")\n        if step % max(1, cfg.pre_steps // 10) == 0:\n            summary = summarize_components_for_release(f.B, f.T, cfg)\n            logger.log(\n                "  confined preformation progress "\n                f"{step}/{cfg.pre_steps}; components={summary[\'component_count\']}; "\n                f"largest_fraction={summary[\'largest_component_fraction\']:.3f}; "\n                f"membrane_voxels={summary[\'total_membrane_voxels\']}"\n            )\n\n    logger.log(\n        "STEP 3/5: confined generation until multi-component release trigger "\n        f"or fallback at {cfg.gen_steps} steps"\n    )\n    logger.log(\n        "  release trigger: "\n        f"components >= {cfg.release_min_components}, "\n        f"check_every={cfg.release_check_every}, "\n        f"min_gen_step={cfg.release_min_gen_step}, "\n        f"max_largest_fraction={cfg.release_max_largest_fraction} "\n        "(<=0 means disabled)"\n    )\n\n    release_step = None\n    release_summary = None\n    for step in range(1, cfg.gen_steps + 1):\n        update_fields(f, env_conf, rng, cfg, phase="confined_gen")\n\n        should_check = (step % max(1, cfg.release_check_every) == 0) or (step == cfg.gen_steps)\n        if should_check:\n            summary = summarize_components_for_release(f.B, f.T, cfg)\n            if step % max(1, cfg.gen_steps // 10) == 0 or release_trigger_met(summary, cfg) or step == cfg.gen_steps:\n                logger.log(\n                    "  confined generation "\n                    f"{step}/{cfg.gen_steps}; components={summary[\'component_count\']}; "\n                    f"largest_fraction={summary[\'largest_component_fraction\']:.3f}; "\n                    f"largest_voxels={summary[\'largest_component_voxels\']}; "\n                    f"total_membrane_voxels={summary[\'total_membrane_voxels\']}"\n                )\n            if step >= cfg.release_min_gen_step and release_trigger_met(summary, cfg):\n                release_step = step\n                release_summary = summary\n                logger.log(\n                    "  RELEASE TRIGGER MET: "\n                    f"step={step}; components={summary[\'component_count\']}; "\n                    f"largest_fraction={summary[\'largest_component_fraction\']:.3f}"\n                )\n                break\n\n    if release_step is None:\n        release_step = cfg.gen_steps\n        release_summary = summarize_components_for_release(f.B, f.T, cfg)\n        logger.log(\n            "  RELEASE TRIGGER NOT MET; using fallback release at end of generation: "\n            f"step={release_step}; components={release_summary[\'component_count\']}; "\n            f"largest_fraction={release_summary[\'largest_component_fraction\']:.3f}"\n        )\n\n    with open(outdir / "release_trigger_summary.json", "w", encoding="utf-8") as fp:\n        json.dump(json_safe({"release_step": release_step, "release_summary": release_summary, "config": asdict(cfg)}), fp, indent=2, ensure_ascii=False)\n\n    logger.log("STEP 4/5: embedding selected pre-saturation state into open sea")\n    f_open = embed_center(f, cfg.open_n)\n    env_open = make_open_environment(cfg.open_n, rng, cfg.source_regime)\n\n    logger.log(f"STEP 5/5: open-sea release simulation steps={cfg.open_steps}; snapshots every {cfg.sample_every}")\n    save_snapshot(snapdir, 0, f_open, cfg, recenter_shift=(0, 0, 0))\n    saved = 1\n    for step in range(1, cfg.open_steps + 1):\n        update_fields(f_open, env_open, rng, cfg, phase="open")\n        shift = recenter_fields_if_needed(f_open, cfg, logger, step)\n        if step % cfg.sample_every == 0 or step == cfg.open_steps:\n            save_snapshot(snapdir, step, f_open, cfg, recenter_shift=shift)\n            saved += 1\n        if step % max(1, cfg.open_steps // 10) == 0:\n            summary = summarize_components_for_release(f_open.B, f_open.T, cfg)\n            logger.log(\n                f"  open-sea progress {step}/{cfg.open_steps}; "\n                f"components={summary[\'component_count\']}; "\n                f"largest_fraction={summary[\'largest_component_fraction\']:.3f}; "\n                f"membrane_voxels={summary[\'total_membrane_voxels\']}; snapshots_saved={saved}"\n            )\n\n    logger.log(f"saved open-sea snapshots to: {snapdir}")\n    return snapdir\n\n\ndef analyze_snapshots(snapdir: Path, outdir: Path, cfg: SimConfig, logger: ProgressLogger) -> None:\n    logger.log("ANALYSIS 1/6: loading snapshot list")\n    snaps = sorted(snapdir.glob("open_sea_step_*.npz"))\n    if not snaps:\n        raise FileNotFoundError(f"no open_sea_step_*.npz snapshots found in {snapdir}")\n    logger.log(f"  found {len(snaps)} snapshots")\n\n    tracker = ComponentTracker(min_overlap_voxels=5)\n    component_rows: List[Dict[str, Any]] = []\n    event_rows: List[Dict[str, Any]] = []\n    overlap_rows: List[Dict[str, Any]] = []\n\n    logger.log("ANALYSIS 2/6: detecting and tracking components")\n    for i, sp in enumerate(snaps, start=1):\n        rows, events, overlaps = extract_component_traits_from_snapshot(sp, cfg, tracker, logger)\n        component_rows.extend(rows)\n        event_rows.extend(events)\n        overlap_rows.extend(overlaps)\n        if i % max(1, len(snaps) // 10) == 0 or i == len(snaps):\n            logger.log(f"  processed snapshots {i}/{len(snaps)}; component_observations={len(component_rows)}")\n\n    logger.log("ANALYSIS 3/6: computing population diversity")\n    diversity_rows = compute_population_diversity(component_rows)\n\n    logger.log("ANALYSIS 4/6: computing component change summaries")\n    change_rows = compute_change_summary(component_rows)\n\n    logger.log("ANALYSIS 5/6: computing PCA trait space")\n    pca_rows = compute_pca_rows(component_rows)\n\n    logger.log("ANALYSIS 6/6: writing CSVs, figures, and report")\n    # Remove private z-vectors before CSV.\n    for r in component_rows:\n        if "_zvec" in r:\n            del r["_zvec"]\n\n    write_csv(outdir / "component_traits_over_time.csv", component_rows)\n    write_csv(outdir / "component_overlap_audit.csv", overlap_rows)\n    write_csv(outdir / "component_events.csv", event_rows)\n    write_csv(outdir / "population_diversity_timeseries.csv", diversity_rows)\n    write_csv(outdir / "component_change_summary.csv", change_rows)\n    write_csv(outdir / "pca_component_trait_space.csv", pca_rows)\n\n    make_figures(outdir, diversity_rows, pca_rows)\n    write_report(outdir, cfg, component_rows, diversity_rows, change_rows, event_rows)\n\n    logger.log("analysis outputs written")\n    logger.log(f"  component observations: {len(component_rows)}")\n    logger.log(f"  tracks: {len(set(r[\'track_id\'] for r in component_rows)) if component_rows else 0}")\n    logger.log(f"  report: {outdir / \'change_and_diversity_report.md\'}")\n\n\ndef mode_defaults(mode: str) -> Dict[str, Any]:\n    if mode == "smoke":\n        return dict(confined_n=28, open_n=44, pre_steps=80, gen_steps=160, open_steps=180, sample_every=20)\n    if mode == "quick":\n        return dict(confined_n=36, open_n=60, pre_steps=240, gen_steps=480, open_steps=600, sample_every=20)\n    if mode == "full":\n        return dict(confined_n=44, open_n=72, pre_steps=1200, gen_steps=2400, open_steps=1800, sample_every=20)\n    raise ValueError(f"unknown mode: {mode}")\n\n\n\n# =============================================================================\n# Fixed 10-hole formation + open-sea environmental heterogeneity sweep\n# =============================================================================\n\nVERSION = "2026-06-05-fixed10holes-openenv-sweep"\n\nOPEN_ENV_TYPES = [\n    "homogeneous",\n    "patchy_resource",\n    "flow_diverse",\n    "shear_diverse",\n    "residence_diverse",\n    "mixed_niche",\n]\n\n\ndef rescale_to_mean(a: np.ndarray, target_mean: float, max_iter: int = 8) -> np.ndarray:\n    """Rescale a nonnegative field to an approximate target mean after clipping to [0,1]."""\n    a = np.maximum(a.astype(np.float32), 0.0)\n    if float(np.max(a)) <= 1e-12:\n        return np.full_like(a, float(target_mean), dtype=np.float32)\n    a = normalize(a)\n    scale = float(target_mean) / (float(np.mean(a)) + 1e-12)\n    out = np.clip(a * scale, 0.0, 1.0).astype(np.float32)\n    for _ in range(max_iter):\n        m = float(np.mean(out))\n        if abs(m - target_mean) < 0.002:\n            break\n        out = np.clip(out * (float(target_mean) / (m + 1e-12)), 0.0, 1.0).astype(np.float32)\n    return out.astype(np.float32)\n\n\ndef deterministic_open_centers(n: int, count: int, rng: np.random.Generator, margin: float = 0.18) -> np.ndarray:\n    """Separated centers for open-sea niches."""\n    centers = []\n    attempts = 0\n    min_dist = 0.23 * n\n    while len(centers) < count and attempts < 10000:\n        attempts += 1\n        c = rng.uniform(margin * n, (1.0 - margin) * n, size=3)\n        if not centers or min(float(np.linalg.norm(c - q)) for q in centers) >= min_dist:\n            centers.append(c)\n    while len(centers) < count:\n        centers.append(rng.uniform(margin * n, (1.0 - margin) * n, size=3))\n    return np.array(centers, dtype=np.float64)\n\n\ndef gaussian_field_from_centers(n: int, centers: np.ndarray, radius_frac: float, amplitudes: Optional[np.ndarray] = None) -> np.ndarray:\n    x, y, z = np.indices((n, n, n), dtype=np.float32)\n    field = np.zeros((n, n, n), dtype=np.float32)\n    if amplitudes is None:\n        amplitudes = np.ones(len(centers), dtype=np.float64)\n    sig = float(radius_frac) * n\n    for amp, (cx, cy, cz) in zip(amplitudes, centers):\n        d = ((x - cx) / sig) ** 2 + ((y - cy) / sig) ** 2 + ((z - cz) / sig) ** 2\n        field += float(amp) * np.exp(-0.5 * d).astype(np.float32)\n    return normalize(field).astype(np.float32)\n\n\ndef make_vortex_flow(n: int, rng: np.random.Generator, centers: np.ndarray, strength: float = 0.035) -> Tuple[np.ndarray, np.ndarray, np.ndarray]:\n    x, y, z = np.indices((n, n, n), dtype=np.float32)\n    vx = np.zeros((n, n, n), dtype=np.float32)\n    vy = np.zeros_like(vx)\n    vz = np.zeros_like(vx)\n    for c in centers:\n        cx, cy, cz = c\n        axis = rng.normal(0, 1, size=3)\n        axis = axis / (np.linalg.norm(axis) + 1e-12)\n        rx = x - cx\n        ry = y - cy\n        rz = z - cz\n        # cross(axis, r)\n        wx = axis[1] * rz - axis[2] * ry\n        wy = axis[2] * rx - axis[0] * rz\n        wz = axis[0] * ry - axis[1] * rx\n        r2 = rx * rx + ry * ry + rz * rz\n        envelope = np.exp(-0.5 * r2 / ((0.18 * n) ** 2)).astype(np.float32)\n        norm = np.sqrt(wx * wx + wy * wy + wz * wz) + 1e-6\n        vx += (wx / norm * envelope).astype(np.float32)\n        vy += (wy / norm * envelope).astype(np.float32)\n        vz += (wz / norm * envelope).astype(np.float32)\n    mag = np.sqrt(vx * vx + vy * vy + vz * vz)\n    mean_mag = float(np.mean(mag)) + 1e-12\n    vx = (vx / mean_mag * strength).astype(np.float32)\n    vy = (vy / mean_mag * strength).astype(np.float32)\n    vz = (vz / mean_mag * strength).astype(np.float32)\n    return vx, vy, vz\n\n\ndef normalize_mean_flow(vx: np.ndarray, vy: np.ndarray, vz: np.ndarray, target_mean: float) -> Tuple[np.ndarray, np.ndarray, np.ndarray]:\n    mag = np.sqrt(vx * vx + vy * vy + vz * vz)\n    m = float(np.mean(mag)) + 1e-12\n    scale = float(target_mean) / m\n    return (vx * scale).astype(np.float32), (vy * scale).astype(np.float32), (vz * scale).astype(np.float32)\n\n\ndef make_open_environment_by_type(n: int, rng: np.random.Generator, env_type: str, source_regime: str = "continuous") -> Environment3D:\n    """Open-sea environment sweep.\n\n    Formation state is fixed across conditions. Only the release/open-sea field is\n    changed here. Resource total, mean flow magnitude, domain size, and integration\n    settings are kept approximately comparable.\n    """\n    if env_type not in OPEN_ENV_TYPES:\n        raise ValueError(f"unknown open_env_type: {env_type}. Allowed: {OPEN_ENV_TYPES}")\n\n    target_resource_mean = 0.18 if source_regime == "continuous" else (0.027 if source_regime == "low" else 0.0)\n    target_flow_mean = 0.030\n\n    zeros = np.zeros((n, n, n), dtype=np.float32)\n    pore = zeros.copy()\n    mineral = zeros.copy()\n    vent = zeros.copy()\n\n    # Base flow direction is shared in type but seeded per condition.\n    base = rng.normal(0, 1, size=3)\n    base = base / (np.linalg.norm(base) + 1e-12)\n    vx_base = np.full((n, n, n), target_flow_mean * base[0], dtype=np.float32)\n    vy_base = np.full((n, n, n), target_flow_mean * base[1], dtype=np.float32)\n    vz_base = np.full((n, n, n), target_flow_mean * base[2], dtype=np.float32)\n\n    pressure = np.full((n, n, n), 0.12, dtype=np.float32)\n    residence = np.full((n, n, n), 0.04, dtype=np.float32)\n    source_shape = np.full((n, n, n), target_resource_mean, dtype=np.float32)\n    vx, vy, vz = vx_base.copy(), vy_base.copy(), vz_base.copy()\n    shear = normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz))\n\n    centers_resource = deterministic_open_centers(n, 8, rng, margin=0.16)\n    centers_flow = deterministic_open_centers(n, 5, rng, margin=0.18)\n    centers_residence = deterministic_open_centers(n, 8, rng, margin=0.18)\n    centers_shear = deterministic_open_centers(n, 5, rng, margin=0.14)\n\n    if env_type == "homogeneous":\n        # Minimal spatial structure. This is the baseline collapse condition.\n        source_shape = np.full((n, n, n), target_resource_mean, dtype=np.float32)\n        residence = np.full((n, n, n), 0.04, dtype=np.float32)\n        pressure = np.full((n, n, n), 0.12, dtype=np.float32)\n        vx, vy, vz = normalize_mean_flow(vx_base, vy_base, vz_base, target_flow_mean)\n        shear = np.full((n, n, n), 0.08, dtype=np.float32)\n\n    elif env_type == "patchy_resource":\n        field = gaussian_field_from_centers(n, centers_resource, radius_frac=0.105, amplitudes=rng.uniform(0.8, 1.2, size=8))\n        source_shape = rescale_to_mean(field, target_resource_mean)\n        residence = np.full((n, n, n), 0.04, dtype=np.float32)\n        pressure = np.full((n, n, n), 0.12, dtype=np.float32)\n        vx, vy, vz = normalize_mean_flow(vx_base, vy_base, vz_base, target_flow_mean)\n        shear = np.full((n, n, n), 0.08, dtype=np.float32)\n\n    elif env_type == "flow_diverse":\n        evx, evy, evz = make_vortex_flow(n, rng, centers_flow, strength=0.030)\n        vx = vx_base + evx\n        vy = vy_base + evy\n        vz = vz_base + evz\n        vx, vy, vz = normalize_mean_flow(vx, vy, vz, target_flow_mean)\n        source_shape = np.full((n, n, n), target_resource_mean, dtype=np.float32)\n        residence = np.full((n, n, n), 0.04, dtype=np.float32)\n        pressure = normalize(0.20 + 0.20 * gaussian_field_from_centers(n, centers_flow, radius_frac=0.16))\n        shear = normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz))\n\n    elif env_type == "shear_diverse":\n        band = gaussian_field_from_centers(n, centers_shear, radius_frac=0.080, amplitudes=rng.uniform(0.9, 1.3, size=5))\n        source_shape = np.full((n, n, n), target_resource_mean, dtype=np.float32)\n        residence = np.full((n, n, n), 0.035, dtype=np.float32)\n        vx = vx_base + (0.016 * rng.normal(size=(n, n, n)).astype(np.float32) * band)\n        vy = vy_base + (0.016 * rng.normal(size=(n, n, n)).astype(np.float32) * band)\n        vz = vz_base + (0.016 * rng.normal(size=(n, n, n)).astype(np.float32) * band)\n        vx, vy, vz = normalize_mean_flow(vx, vy, vz, target_flow_mean)\n        shear = rescale_to_mean(0.25 * normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz)) + 0.75 * band, 0.18)\n        pressure = clip01(0.10 + 0.35 * band)\n\n    elif env_type == "residence_diverse":\n        pockets = gaussian_field_from_centers(n, centers_residence, radius_frac=0.105, amplitudes=rng.uniform(0.8, 1.2, size=8))\n        residence = clip01(0.025 + 0.68 * pockets)\n        source_shape = np.full((n, n, n), target_resource_mean, dtype=np.float32)\n        # Flow slows inside residence pockets, helping spatial separation persist.\n        attenuation = np.clip(1.0 - 0.78 * residence, 0.18, 1.0).astype(np.float32)\n        vx, vy, vz = normalize_mean_flow(vx_base * attenuation, vy_base * attenuation, vz_base * attenuation, target_flow_mean)\n        shear = normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz))\n        pressure = clip01(0.10 + 0.18 * (1.0 - residence))\n\n    elif env_type == "mixed_niche":\n        res_patch = gaussian_field_from_centers(n, centers_resource, radius_frac=0.095, amplitudes=rng.uniform(0.8, 1.25, size=8))\n        pockets = gaussian_field_from_centers(n, centers_residence, radius_frac=0.105, amplitudes=rng.uniform(0.8, 1.2, size=8))\n        shear_patch = gaussian_field_from_centers(n, centers_shear, radius_frac=0.075, amplitudes=rng.uniform(0.8, 1.3, size=5))\n        evx, evy, evz = make_vortex_flow(n, rng, centers_flow, strength=0.030)\n        source_shape = rescale_to_mean(0.85 * res_patch + 0.15 * pockets, target_resource_mean)\n        residence = clip01(0.020 + 0.55 * pockets + 0.10 * res_patch)\n        attenuation = np.clip(1.0 - 0.65 * residence + 0.10 * shear_patch, 0.18, 1.10).astype(np.float32)\n        vx = vx_base * attenuation + evx + 0.006 * shear_patch * rng.normal(size=(n, n, n)).astype(np.float32)\n        vy = vy_base * attenuation + evy + 0.006 * shear_patch * rng.normal(size=(n, n, n)).astype(np.float32)\n        vz = vz_base * attenuation + evz + 0.006 * shear_patch * rng.normal(size=(n, n, n)).astype(np.float32)\n        vx, vy, vz = normalize_mean_flow(vx, vy, vz, target_flow_mean)\n        shear = rescale_to_mean(0.40 * normalize(gradmag3(vx) + gradmag3(vy) + gradmag3(vz)) + 0.60 * shear_patch, 0.18)\n        pressure = clip01(0.08 + 0.20 * shear_patch + 0.12 * (1.0 - residence))\n\n    if source_regime == "none":\n        source_shape = np.zeros((n, n, n), dtype=np.float32)\n    elif source_regime == "low":\n        source_shape = rescale_to_mean(source_shape, 0.027)\n\n    return Environment3D(\n        pore=pore.astype(np.float32),\n        mineral=mineral.astype(np.float32),\n        residence=clip01(residence).astype(np.float32),\n        vent=vent.astype(np.float32),\n        pressure=clip01(pressure).astype(np.float32),\n        vx=vx.astype(np.float32),\n        vy=vy.astype(np.float32),\n        vz=vz.astype(np.float32),\n        shear=clip01(shear).astype(np.float32),\n        source_shape=clip01(source_shape).astype(np.float32),\n    )\n\n\ndef copy_fields(f: Fields) -> Fields:\n    return Fields(R=f.R.copy(), L=f.L.copy(), H=f.H.copy(), X=f.X.copy(), M=f.M.copy(), B=f.B.copy(), T=f.T.copy())\n\n\ndef save_release_state(path: Path, f: Fields, release_step: int, release_summary: Dict[str, Any]) -> None:\n    np.savez_compressed(\n        path,\n        release_step=np.array(release_step, dtype=np.int32),\n        B=f.B.astype(np.float32),\n        T=f.T.astype(np.float32),\n        M=f.M.astype(np.float32),\n        R=f.R.astype(np.float32),\n        L=f.L.astype(np.float32),\n        H=f.H.astype(np.float32),\n        X=f.X.astype(np.float32),\n        release_summary_json=np.array(json.dumps(json_safe(release_summary), ensure_ascii=False)),\n    )\n\n\ndef generate_fixed_release_state(cfg: SimConfig, outdir: Path, logger: ProgressLogger) -> Tuple[Fields, int, Dict[str, Any]]:\n    rng = np.random.default_rng(cfg.seed)\n    logger.log("FORMATION 1/3: constructing fixed 10-hole confined environment")\n    env_conf = make_confined_environment(cfg.confined_n, rng, cfg)\n    f = init_fields(cfg.confined_n, rng, env_conf)\n\n    logger.log(f"FORMATION 2/3: confined preformation steps={cfg.pre_steps}")\n    for step in range(1, cfg.pre_steps + 1):\n        update_fields(f, env_conf, rng, cfg, phase="confined_pre")\n        if step % max(1, cfg.pre_steps // 10) == 0:\n            summary = summarize_components_for_release(f.B, f.T, cfg)\n            logger.log(\n                f"  preformation {step}/{cfg.pre_steps}; components={summary[\'component_count\']}; "\n                f"largest_fraction={summary[\'largest_component_fraction\']:.3f}; membrane_voxels={summary[\'total_membrane_voxels\']}"\n            )\n\n    logger.log(\n        "FORMATION 3/3: confined generation until fixed release trigger; "\n        f"target components >= {cfg.release_min_components}"\n    )\n    release_step = None\n    release_summary = None\n    for step in range(1, cfg.gen_steps + 1):\n        update_fields(f, env_conf, rng, cfg, phase="confined_gen")\n        should_check = (step % max(1, cfg.release_check_every) == 0) or (step == cfg.gen_steps)\n        if should_check:\n            summary = summarize_components_for_release(f.B, f.T, cfg)\n            if step % max(1, cfg.gen_steps // 10) == 0 or release_trigger_met(summary, cfg) or step == cfg.gen_steps:\n                logger.log(\n                    f"  generation {step}/{cfg.gen_steps}; components={summary[\'component_count\']}; "\n                    f"largest_fraction={summary[\'largest_component_fraction\']:.3f}; membrane_voxels={summary[\'total_membrane_voxels\']}"\n                )\n            if step >= cfg.release_min_gen_step and release_trigger_met(summary, cfg):\n                release_step = step\n                release_summary = summary\n                logger.log(\n                    f"  FIXED RELEASE STATE SELECTED: step={step}; components={summary[\'component_count\']}; "\n                    f"largest_fraction={summary[\'largest_component_fraction\']:.3f}"\n                )\n                break\n\n    if release_step is None:\n        release_step = cfg.gen_steps\n        release_summary = summarize_components_for_release(f.B, f.T, cfg)\n        logger.log(\n            "  RELEASE TRIGGER NOT MET; fallback=end; "\n            f"step={release_step}; components={release_summary[\'component_count\']}; "\n            f"largest_fraction={release_summary[\'largest_component_fraction\']:.3f}"\n        )\n\n    save_release_state(outdir / "fixed_release_state.npz", f, release_step, release_summary)\n    with open(outdir / "fixed_release_summary.json", "w", encoding="utf-8") as fp:\n        json.dump(json_safe({"release_step": release_step, "release_summary": release_summary, "config": asdict(cfg)}), fp, indent=2, ensure_ascii=False)\n    return f, int(release_step), release_summary\n\n\ndef run_open_sea_condition_from_release(\n    release_fields: Fields,\n    cfg: SimConfig,\n    env_type: str,\n    cond_dir: Path,\n    release_step: int,\n    release_summary: Dict[str, Any],\n    condition_index: int,\n    logger: ProgressLogger,\n) -> Path:\n    snapdir = ensure_dir(cond_dir / "open_sea_snapshots")\n    rng = np.random.default_rng(cfg.seed + 10000 + 1009 * condition_index)\n    f_open = embed_center(copy_fields(release_fields), cfg.open_n)\n    env_open = make_open_environment_by_type(cfg.open_n, rng, env_type, cfg.source_regime)\n\n    with open(cond_dir / "release_trigger_summary.json", "w", encoding="utf-8") as fp:\n        json.dump(json_safe({\n            "release_step": release_step,\n            "release_summary": release_summary,\n            "open_env_type": env_type,\n            "config": asdict(cfg),\n        }), fp, indent=2, ensure_ascii=False)\n\n    logger.log(f"OPEN-SEA CONDITION: {env_type}; steps={cfg.open_steps}; snapshots every {cfg.sample_every}")\n    save_snapshot(snapdir, 0, f_open, cfg, recenter_shift=(0, 0, 0))\n    saved = 1\n    for step in range(1, cfg.open_steps + 1):\n        update_fields(f_open, env_open, rng, cfg, phase="open")\n        shift = recenter_fields_if_needed(f_open, cfg, logger, step)\n        if step % cfg.sample_every == 0 or step == cfg.open_steps:\n            save_snapshot(snapdir, step, f_open, cfg, recenter_shift=shift)\n            saved += 1\n        if step % max(1, cfg.open_steps // 10) == 0:\n            summary = summarize_components_for_release(f_open.B, f_open.T, cfg)\n            logger.log(\n                f"  open-sea {env_type} {step}/{cfg.open_steps}; components={summary[\'component_count\']}; "\n                f"largest_fraction={summary[\'largest_component_fraction\']:.3f}; membrane_voxels={summary[\'total_membrane_voxels\']}; snapshots_saved={saved}"\n            )\n    return snapdir\n\n\ndef parse_env_types(text: str) -> List[str]:\n    if text is None or str(text).strip() == "" or str(text).strip().lower() == "all":\n        return list(OPEN_ENV_TYPES)\n    vals = []\n    for part in str(text).split(\',\'):\n        p = part.strip()\n        if p:\n            if p not in OPEN_ENV_TYPES:\n                raise ValueError(f"unknown env type: {p}. allowed={OPEN_ENV_TYPES}")\n            vals.append(p)\n    return vals or list(OPEN_ENV_TYPES)\n\n\ndef parse_args() -> argparse.Namespace:\n    p = argparse.ArgumentParser(description="Fixed 10-hole formation + open-sea environmental heterogeneity sweep.")\n    p.add_argument("--mode", choices=["smoke", "quick", "full"], default="quick")\n    p.add_argument("--outdir", type=Path, required=True)\n    p.add_argument("--seed", type=int, default=12345)\n    p.add_argument("--env-types", type=str, default="all", help="Comma-separated open-sea env types or \'all\'.")\n    p.add_argument("--hole-count", type=int, default=10, help="Formation holes. Default fixed at 10.")\n    p.add_argument("--confined-n", type=int, default=None)\n    p.add_argument("--open-n", type=int, default=None)\n    p.add_argument("--pre-steps", type=int, default=None)\n    p.add_argument("--gen-steps", type=int, default=None)\n    p.add_argument("--open-steps", type=int, default=None)\n    p.add_argument("--sample-every", type=int, default=None)\n    p.add_argument("--dt", type=float, default=0.035)\n    p.add_argument("--b-threshold", type=float, default=0.16)\n    p.add_argument("--t-threshold", type=float, default=0.018)\n    p.add_argument("--min-component-voxels", type=int, default=12)\n    p.add_argument("--min-lumen-voxels", type=int, default=20)\n    p.add_argument("--source-regime", choices=["continuous", "low", "none"], default="continuous")\n    p.add_argument("--release-min-components", type=int, default=8, help="Release fixed formation state as soon as at least this many components are detected.")\n    p.add_argument("--release-check-every", type=int, default=20)\n    p.add_argument("--release-min-gen-step", type=int, default=0)\n    p.add_argument("--release-max-largest-fraction", type=float, default=0.0)\n    p.add_argument("--release-fallback", choices=["end"], default="end")\n    p.add_argument("--no-recenter", action="store_true")\n    p.add_argument("--save-float16", action="store_true")\n    return p.parse_args()\n\n\ndef build_config(args: argparse.Namespace) -> SimConfig:\n    d = mode_defaults(args.mode)\n    confined_n = args.confined_n if args.confined_n is not None else d["confined_n"]\n    open_n = args.open_n if args.open_n is not None else d["open_n"]\n    pre_steps = args.pre_steps if args.pre_steps is not None else d["pre_steps"]\n    gen_steps = args.gen_steps if args.gen_steps is not None else d["gen_steps"]\n    open_steps = args.open_steps if args.open_steps is not None else d["open_steps"]\n    sample_every = args.sample_every if args.sample_every is not None else d["sample_every"]\n    return SimConfig(\n        seed=int(args.seed),\n        hole_count=int(args.hole_count),\n        fixed_total_pore=False,  # hole size is fixed; no scaling by hole count\n        reference_hole_count=int(args.hole_count),\n        confined_n=int(confined_n),\n        open_n=int(open_n),\n        pre_steps=int(pre_steps),\n        gen_steps=int(gen_steps),\n        open_steps=int(open_steps),\n        sample_every=int(sample_every),\n        dt=float(args.dt),\n        b_threshold=float(args.b_threshold),\n        t_threshold=float(args.t_threshold),\n        min_component_voxels=int(args.min_component_voxels),\n        min_lumen_voxels=int(args.min_lumen_voxels),\n        source_regime=str(args.source_regime),\n        recenter=not bool(args.no_recenter),\n        save_float16=bool(args.save_float16),\n        release_min_components=int(args.release_min_components),\n        release_check_every=int(args.release_check_every),\n        release_min_gen_step=int(args.release_min_gen_step),\n        release_max_largest_fraction=float(args.release_max_largest_fraction),\n        release_fallback=str(args.release_fallback),\n    )\n\n\n\ndef load_summary_metric_csv(path: Path) -> List[Dict[str, Any]]:\n    if not path.exists():\n        return []\n    with open(path, newline=\'\', encoding=\'utf-8\') as f:\n        return list(csv.DictReader(f))\n\n\ndef summarize_env_condition_outputs(cond_dir: Path, env_type: str) -> Dict[str, Any]:\n    row: Dict[str, Any] = {"open_env_type": env_type, "condition_dir": str(cond_dir)}\n    rel_path = cond_dir / "release_trigger_summary.json"\n    if rel_path.exists():\n        try:\n            rel = json.loads(rel_path.read_text(encoding="utf-8"))\n            rs = rel.get("release_summary", {})\n            row.update({\n                "release_step": rel.get("release_step", ""),\n                "release_component_count": rs.get("component_count", ""),\n                "release_largest_component_fraction": rs.get("largest_component_fraction", ""),\n                "release_total_membrane_voxels": rs.get("total_membrane_voxels", ""),\n            })\n        except Exception as e:\n            row["release_summary_error"] = str(e)\n    div_rows = load_summary_metric_csv(cond_dir / "population_diversity_timeseries.csv")\n    if div_rows:\n        steps = [float(r.get("step", 0) or 0) for r in div_rows]\n        counts = [float(r.get("component_count", 0) or 0) for r in div_rows]\n        dists = [float(r.get("mean_pairwise_trait_distance", 0) or 0) for r in div_rows]\n        if len(steps) >= 2:\n            row["component_count_auc"] = float(np.trapezoid(counts, steps))\n            row["trait_distance_auc"] = float(np.trapezoid(dists, steps))\n        else:\n            row["component_count_auc"] = 0.0\n            row["trait_distance_auc"] = 0.0\n        row["first_component_count"] = counts[0]\n        row["final_component_count"] = counts[-1]\n        row["max_component_count"] = max(counts)\n        row["first_trait_distance"] = dists[0]\n        row["final_trait_distance"] = dists[-1]\n        row["max_trait_distance"] = max(dists)\n        t_single = ""\n        for st, c in zip(steps, counts):\n            if st > steps[0] and c <= 1:\n                t_single = st\n                break\n        row["time_to_single_component"] = t_single\n    ch_rows = load_summary_metric_csv(cond_dir / "component_change_summary.csv")\n    if ch_rows:\n        persistent = [r for r in ch_rows if int(float(r.get("n_observations", 0) or 0)) >= 3]\n        row["persistent_track_count"] = len(persistent)\n        if persistent:\n            row["mean_path_length_persistent"] = float(np.mean([float(r.get("path_length", 0) or 0) for r in persistent]))\n            row["mean_volume_delta_persistent"] = float(np.mean([float(r.get("volume_delta", 0) or 0) for r in persistent]))\n    ev_rows = load_summary_metric_csv(cond_dir / "component_events.csv")\n    if ev_rows:\n        row["fusion_event_count"] = sum(1 for r in ev_rows if str(r.get("event_type", "")) == "fusion_into_component")\n        row["emergence_event_count"] = sum(1 for r in ev_rows if str(r.get("event_type", "")) == "emergence")\n    return row\n\n\ndef write_openenv_sweep_report(outdir: Path, rows: List[Dict[str, Any]], cfg: SimConfig) -> None:\n    lines = []\n    lines.append("# Fixed 10-Hole Formation / Open-Sea Environment Sweep\\n\\n")\n    lines.append(f"Version: `{VERSION}`\\n\\n")\n    lines.append("Scope: change and diversity after open-sea release. This does not test evolution.\\n\\n")\n    lines.append("Fixed formation condition: 10 holes, fixed hole size, fixed release state reused across all open-sea environments.\\n\\n")\n    lines.append("Comparison variable: open-sea 3D environmental structure only.\\n\\n")\n    lines.append("| open sea env | release comps | max comps | final comps | max trait distance | trait AUC | time to single | persistent tracks | fusion events |\\n")\n    lines.append("|---|---:|---:|---:|---:|---:|---:|---:|---:|\\n")\n    for r in rows:\n        lines.append(\n            f"| {r.get(\'open_env_type\',\'\')} | {r.get(\'release_component_count\',\'\')} | {r.get(\'max_component_count\',\'\')} | "\n            f"{r.get(\'final_component_count\',\'\')} | {float(r.get(\'max_trait_distance\',0) or 0):.6f} | "\n            f"{float(r.get(\'trait_distance_auc\',0) or 0):.6f} | {r.get(\'time_to_single_component\',\'\')} | "\n            f"{r.get(\'persistent_track_count\',\'\')} | {r.get(\'fusion_event_count\',\'\')} |\\n"\n        )\n    lines.append("\\nInterpretation boundary: increased trait AUC or delayed time-to-single indicates extended diversity after release. Final component count >1 indicates sustained component multiplicity under that open-sea environment.\\n")\n    (outdir / "openenv_sweep_report.md").write_text("".join(lines), encoding="utf-8")\n\n\ndef main() -> int:\n    args = parse_args()\n    outdir = args.outdir.expanduser().resolve()\n    ensure_dir(outdir)\n    logger = ProgressLogger(outdir)\n    try:\n        env_types = parse_env_types(args.env_types)\n        cfg = build_config(args)\n        if cfg.hole_count != 10:\n            logger.log(f"WARNING: hole_count={cfg.hole_count}; requested design is fixed 10 holes. Continuing with user value.")\n        logger.log(f"START fixed-formation/open-env sweep :: version={VERSION}")\n        logger.log(f"outdir: {outdir}")\n        logger.log(f"mode: {args.mode}; fixed holes={cfg.hole_count}; env_types={env_types}")\n        logger.log(f"scipy_available: {SCIPY_AVAILABLE}; matplotlib_available: {MATPLOTLIB_AVAILABLE}")\n        with open(outdir / "analysis_parameters.json", "w", encoding="utf-8") as f:\n            json.dump(json_safe({"version": VERSION, "args": vars(args), "config": asdict(cfg), "env_types": env_types}), f, indent=2, ensure_ascii=False)\n\n        release_fields, release_step, release_summary = generate_fixed_release_state(cfg, outdir, logger)\n        summary_rows: List[Dict[str, Any]] = []\n        for i, env_type in enumerate(env_types):\n            cond_dir = ensure_dir(outdir / env_type)\n            cond_logger = ProgressLogger(cond_dir)\n            try:\n                cond_logger.log(f"START open-sea env condition: {env_type}")\n                snapdir = run_open_sea_condition_from_release(\n                    release_fields=release_fields,\n                    cfg=cfg,\n                    env_type=env_type,\n                    cond_dir=cond_dir,\n                    release_step=release_step,\n                    release_summary=release_summary,\n                    condition_index=i,\n                    logger=cond_logger,\n                )\n                analyze_snapshots(snapdir, cond_dir, cfg, cond_logger)\n                cond_logger.log(f"DONE condition: {env_type}")\n            except Exception as e:\n                cond_logger.log(f"ERROR condition {env_type}: {type(e).__name__}: {e}")\n                (cond_dir / "ERROR.txt").write_text(traceback.format_exc(), encoding="utf-8")\n            finally:\n                cond_logger.close()\n            row = summarize_env_condition_outputs(cond_dir, env_type)\n            summary_rows.append(row)\n            logger.log(\n                f"CONDITION END {env_type}: max_components={row.get(\'max_component_count\',\'NA\')}; "\n                f"final_components={row.get(\'final_component_count\',\'NA\')}; trait_auc={row.get(\'trait_distance_auc\',\'NA\')}"\n            )\n\n        write_csv(outdir / "openenv_sweep_summary.csv", summary_rows)\n        write_openenv_sweep_report(outdir, summary_rows, cfg)\n        logger.log(f"DONE; summary={outdir / \'openenv_sweep_summary.csv\'}; report={outdir / \'openenv_sweep_report.md\'}")\n        return 0\n    except Exception as e:\n        logger.log(f"ERROR: {type(e).__name__}: {e}")\n        (outdir / "ERROR.txt").write_text(traceback.format_exc(), encoding="utf-8")\n        return 1\n    finally:\n        logger.close()\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'POSTHOC_FIXED10_ENV_HISTORY_1TO4.py': '#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n"""\nPOSTHOC_FIXED10_ENV_HISTORY_1TO4.py\n\nCompletely post-hoc analysis for the fixed 10-hole / open-sea environmental-history result.\n\nNo simulation is run.\n\nIt reads existing outputs:\n    ~/Desktop/fixed10holes_openenv_full/<environment>/open_sea_snapshots/open_sea_step_*.npz\n\nand recomputes, from snapshots only:\n1. Environmental Imprint Index (EII)\n2. Initial -> re-fusion -> final three-phase comparison\n3. Voxel-level slice visualization for B, T, abs(M), R, X\n4. Threshold sensitivity:\n      loose  : B>=0.14, T>=0.016\n      main   : B>=0.16, T>=0.018\n      strict : B>=0.18, T>=0.020\n\nIt deliberately does NOT perform seed replication or rerun the field simulation.\n\nRun:\n    SCRIPT=$(ls -t ~/Downloads/POSTHOC_FIXED10_ENV_HISTORY_1TO4*.py | head -1)\n\n    python3 -u "$SCRIPT" \\\n      --root ~/Desktop/fixed10holes_openenv_full \\\n      --outdir ~/Desktop/fixed10holes_posthoc_1to4 \\\n      2>&1 | tee ~/Desktop/fixed10holes_posthoc_1to4.log\n\nOutputs:\n    posthoc_1to4_master_report.md\n    threshold_main/environment_refusion_transform_summary.csv\n    threshold_main/environment_transform_rankings.csv\n    threshold_main/environment_phase_metrics_long.csv\n    threshold_loose/...\n    threshold_strict/...\n    threshold_sensitivity_summary.csv\n    figures/\n    voxel_slices/\n\nVersion:\n    2026-06-05-posthoc-fixed10-envhistory-1to4\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport csv\nimport json\nimport math\nimport time\nimport traceback\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional, Tuple\n\nimport numpy as np\n\ntry:\n    from scipy import ndimage as ndi\n    SCIPY_AVAILABLE = True\nexcept Exception:\n    ndi = None\n    SCIPY_AVAILABLE = False\n\ntry:\n    import matplotlib\n    matplotlib.use("Agg")\n    import matplotlib.pyplot as plt\n    MATPLOTLIB_AVAILABLE = True\nexcept Exception:\n    plt = None\n    MATPLOTLIB_AVAILABLE = False\n\n\nVERSION = "2026-06-05-posthoc-fixed10-envhistory-1to4"\n\nDEFAULT_ENVS = [\n    "homogeneous",\n    "patchy_resource",\n    "flow_diverse",\n    "shear_diverse",\n    "residence_diverse",\n    "mixed_niche",\n]\n\nDEFAULT_THRESHOLDS = {\n    "loose": (0.14, 0.016),\n    "main": (0.16, 0.018),\n    "strict": (0.18, 0.020),\n}\n\nTRAIT_COLUMNS = [\n    "volume",\n    "surface_area",\n    "compactness",\n    "elongation",\n    "planarity",\n    "mean_B",\n    "mean_T",\n    "var_T",\n    "mean_abs_M",\n    "std_abs_M",\n    "mean_R",\n    "mean_X",\n    "lumen_count",\n    "lumen_volume_fraction",\n    "cumulative_path",\n    "net_displacement",\n    "persistence_ratio",\n]\n\n\n# =============================================================================\n# Utilities\n# =============================================================================\n\nclass Logger:\n    def __init__(self, outdir: Path):\n        self.t0 = time.time()\n        outdir.mkdir(parents=True, exist_ok=True)\n        self.fp = open(outdir / "posthoc_1to4_progress.log", "w", encoding="utf-8")\n\n    def log(self, msg: str) -> None:\n        line = f"[{time.time() - self.t0:9.1f}s] {msg}"\n        print(line, flush=True)\n        self.fp.write(line + "\\n")\n        self.fp.flush()\n\n    def close(self) -> None:\n        try:\n            self.fp.close()\n        except Exception:\n            pass\n\n\ndef to_float(x: Any, default: float = 0.0) -> float:\n    try:\n        if x is None or x == "":\n            return default\n        return float(x)\n    except Exception:\n        return default\n\n\ndef to_int(x: Any, default: int = 0) -> int:\n    try:\n        if x is None or x == "":\n            return default\n        return int(float(x))\n    except Exception:\n        return default\n\n\ndef json_safe(x: Any) -> Any:\n    if isinstance(x, Path):\n        return str(x)\n    if isinstance(x, np.ndarray):\n        return x.tolist()\n    if isinstance(x, np.integer):\n        return int(x)\n    if isinstance(x, np.floating):\n        return float(x)\n    if isinstance(x, np.bool_):\n        return bool(x)\n    if isinstance(x, dict):\n        return {str(k): json_safe(v) for k, v in x.items()}\n    if isinstance(x, (list, tuple)):\n        return [json_safe(v) for v in x]\n    return x\n\n\ndef write_csv(path: Path, rows: List[Dict[str, Any]], fieldnames: Optional[List[str]] = None) -> None:\n    path.parent.mkdir(parents=True, exist_ok=True)\n    if fieldnames is None:\n        keys: List[str] = []\n        seen = set()\n        for r in rows:\n            for k in r.keys():\n                if k not in seen:\n                    keys.append(k)\n                    seen.add(k)\n        fieldnames = keys\n    with open(path, "w", newline="", encoding="utf-8") as f:\n        w = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")\n        w.writeheader()\n        for r in rows:\n            w.writerow({k: json_safe(r.get(k, "")) for k in fieldnames})\n\n\ndef safe_trapezoid(y: List[float], x: List[float]) -> float:\n    if len(y) < 2:\n        return 0.0\n    return float(np.trapezoid(np.asarray(y, dtype=float), np.asarray(x, dtype=float)))\n\n\ndef parse_thresholds(s: str) -> Dict[str, Tuple[float, float]]:\n    if not s:\n        return dict(DEFAULT_THRESHOLDS)\n    out: Dict[str, Tuple[float, float]] = {}\n    for item in s.split(","):\n        item = item.strip()\n        if not item:\n            continue\n        parts = item.split(":")\n        if len(parts) != 3:\n            raise ValueError("threshold format must be name:B:T,name:B:T")\n        out[parts[0]] = (float(parts[1]), float(parts[2]))\n    return out\n\n\ndef component_surface_area(mask: np.ndarray) -> int:\n    if not np.any(mask):\n        return 0\n    # Non-periodic exposed faces via padding.\n    p = np.pad(mask, 1, mode="constant", constant_values=False)\n    area = 0\n    c = p[1:-1, 1:-1, 1:-1]\n    area += int(np.sum(c & ~p[:-2, 1:-1, 1:-1]))\n    area += int(np.sum(c & ~p[2:, 1:-1, 1:-1]))\n    area += int(np.sum(c & ~p[1:-1, :-2, 1:-1]))\n    area += int(np.sum(c & ~p[1:-1, 2:, 1:-1]))\n    area += int(np.sum(c & ~p[1:-1, 1:-1, :-2]))\n    area += int(np.sum(c & ~p[1:-1, 1:-1, 2:]))\n    return area\n\n\ndef shape_traits(points: np.ndarray, max_points: int = 8000) -> Tuple[float, float, Tuple[int, int, int]]:\n    if points.shape[0] < 3:\n        return 0.0, 0.0, (0, 0, 0)\n    mins = points.min(axis=0)\n    maxs = points.max(axis=0)\n    bbox = tuple(int(x) for x in (maxs - mins + 1))\n    pts = points\n    if pts.shape[0] > max_points:\n        idx = np.linspace(0, pts.shape[0] - 1, max_points).astype(int)\n        pts = pts[idx]\n    centered = pts.astype(float) - pts.mean(axis=0, keepdims=True)\n    cov = centered.T @ centered / max(len(pts) - 1, 1)\n    vals = np.linalg.eigvalsh(cov)\n    vals = np.sort(np.maximum(vals, 0.0))[::-1] + 1e-12\n    l1, l2, l3 = vals\n    elongation = float((l1 - l2) / l1)\n    planarity = float((l2 - l3) / l1)\n    return elongation, planarity, bbox\n\n\ndef detect_labels(mask: np.ndarray) -> Tuple[np.ndarray, int]:\n    if SCIPY_AVAILABLE:\n        structure = np.ones((3, 3, 3), dtype=np.int8)\n        labels, nlab = ndi.label(mask, structure=structure)\n        return labels.astype(np.int32, copy=False), int(nlab)\n    raise RuntimeError("scipy is required for this posthoc script because connected-component labeling is needed.")\n\n\ndef filter_small_labels(labels: np.ndarray, min_size: int) -> Tuple[np.ndarray, Dict[int, int]]:\n    if int(labels.max()) == 0:\n        return labels.astype(np.int32), {}\n    counts = np.bincount(labels.ravel())\n    keep = np.where(counts >= min_size)[0]\n    keep = keep[keep != 0]\n    out = np.zeros_like(labels, dtype=np.int32)\n    size_map: Dict[int, int] = {}\n    new = 0\n    for old in keep:\n        new += 1\n        out[labels == int(old)] = new\n        size_map[new] = int(counts[int(old)])\n    return out, size_map\n\n\ndef lumen_traits(component_mask: np.ndarray, min_lumen_voxels: int = 20) -> Tuple[int, int]:\n    """Internal cavity count inside component bounding box."""\n    if not np.any(component_mask):\n        return 0, 0\n    pts = np.argwhere(component_mask)\n    mins = np.maximum(pts.min(axis=0) - 1, 0)\n    maxs = np.minimum(pts.max(axis=0) + 2, np.array(component_mask.shape))\n    sub = component_mask[mins[0]:maxs[0], mins[1]:maxs[1], mins[2]:maxs[2]]\n    non = ~sub\n    labels, nlab = detect_labels(non)\n    if nlab == 0:\n        return 0, 0\n    border = set()\n    for face in [labels[0,:,:], labels[-1,:,:], labels[:,0,:], labels[:,-1,:], labels[:,:,0], labels[:,:,-1]]:\n        border.update(int(x) for x in np.unique(face) if int(x) != 0)\n    counts = np.bincount(labels.ravel())\n    n = 0\n    v = 0\n    for lab in range(1, len(counts)):\n        if lab in border:\n            continue\n        c = int(counts[lab])\n        if c >= min_lumen_voxels:\n            n += 1\n            v += c\n    return n, v\n\n\n# =============================================================================\n# Tracking and snapshot analysis\n# =============================================================================\n\nclass TrackState:\n    def __init__(self, tid: int, step: int, centroid: Tuple[float, float, float]):\n        self.track_id = tid\n        self.first_step = step\n        self.last_step = step\n        self.first_centroid = np.array(centroid, dtype=float)\n        self.prev_centroid = np.array(centroid, dtype=float)\n        self.cumulative_path = 0.0\n        self.observations = 1\n\n    def update(self, step: int, centroid: Tuple[float, float, float]):\n        c = np.array(centroid, dtype=float)\n        self.cumulative_path += float(np.linalg.norm(c - self.prev_centroid))\n        self.prev_centroid = c\n        self.last_step = step\n        self.observations += 1\n\n    def net(self, centroid: Tuple[float, float, float]) -> float:\n        c = np.array(centroid, dtype=float)\n        return float(np.linalg.norm(c - self.first_centroid))\n\n\nclass ComponentTracker:\n    def __init__(self, min_overlap: int = 5):\n        self.min_overlap = min_overlap\n        self.next_track_id = 1\n        self.prev_labels: Optional[np.ndarray] = None\n        self.prev_label_to_track: Dict[int, int] = {}\n        self.tracks: Dict[int, TrackState] = {}\n\n    def new_track(self, step: int, centroid: Tuple[float, float, float]) -> int:\n        tid = self.next_track_id\n        self.next_track_id += 1\n        self.tracks[tid] = TrackState(tid, step, centroid)\n        return tid\n\n    def assign(self, step: int, labels: np.ndarray, centroids: Dict[int, Tuple[float, float, float]]) -> Tuple[Dict[int, int], List[Dict[str, Any]], List[Dict[str, Any]]]:\n        events: List[Dict[str, Any]] = []\n        overlaps: List[Dict[str, Any]] = []\n        curr_labels = [int(x) for x in np.unique(labels) if int(x) != 0]\n        curr_to_track: Dict[int, int] = {}\n\n        if self.prev_labels is None:\n            for lab in curr_labels:\n                tid = self.new_track(step, centroids[lab])\n                curr_to_track[lab] = tid\n                events.append({"step": step, "event_type": "emergence", "track_id": tid, "component_label": lab})\n            self.prev_labels = labels.copy()\n            self.prev_label_to_track = curr_to_track\n            return curr_to_track, events, overlaps\n\n        prev = self.prev_labels\n        curr = labels\n        n_curr = int(curr.max()) + 1\n        both = (prev > 0) & (curr > 0)\n        pairs: List[Tuple[int, int, int]] = []\n        if np.any(both):\n            code = prev[both].astype(np.int64) * n_curr + curr[both].astype(np.int64)\n            uniq, counts = np.unique(code, return_counts=True)\n            for u, c in zip(uniq, counts):\n                pl = int(u // n_curr)\n                cl = int(u % n_curr)\n                c = int(c)\n                if c >= self.min_overlap:\n                    pairs.append((pl, cl, c))\n                    overlaps.append({\n                        "step": step,\n                        "prev_label": pl,\n                        "curr_label": cl,\n                        "prev_track_id": self.prev_label_to_track.get(pl, -1),\n                        "overlap_voxels": c,\n                    })\n\n        by_curr: Dict[int, List[Tuple[int, int]]] = {}\n        by_prev: Dict[int, List[Tuple[int, int]]] = {}\n        for pl, cl, c in pairs:\n            by_curr.setdefault(cl, []).append((pl, c))\n            by_prev.setdefault(pl, []).append((cl, c))\n\n        for cl in curr_labels:\n            cands = sorted(by_curr.get(cl, []), key=lambda x: x[1], reverse=True)\n            if cands:\n                best_prev, overlap = cands[0]\n                tid = self.prev_label_to_track.get(best_prev)\n                if tid is None:\n                    tid = self.new_track(step, centroids[cl])\n                    events.append({"step": step, "event_type": "emergence", "track_id": tid, "component_label": cl})\n                else:\n                    self.tracks[tid].update(step, centroids[cl])\n                    events.append({\n                        "step": step,\n                        "event_type": "continuation",\n                        "track_id": tid,\n                        "component_label": cl,\n                        "parent_prev_label": best_prev,\n                        "overlap_voxels": overlap,\n                    })\n                    if len(cands) > 1:\n                        events.append({\n                            "step": step,\n                            "event_type": "fusion_into_component",\n                            "track_id": tid,\n                            "component_label": cl,\n                            "n_previous_components": len(cands),\n                        })\n                curr_to_track[cl] = tid\n            else:\n                tid = self.new_track(step, centroids[cl])\n                curr_to_track[cl] = tid\n                events.append({"step": step, "event_type": "emergence", "track_id": tid, "component_label": cl})\n\n        for pl, currs in by_prev.items():\n            if len(currs) >= 2:\n                events.append({\n                    "step": step,\n                    "event_type": "fission_from_previous",\n                    "parent_track_id": self.prev_label_to_track.get(pl, -1),\n                    "prev_label": pl,\n                    "n_current_components": len(currs),\n                    "child_track_ids": ";".join(str(curr_to_track.get(cl, -1)) for cl, _ in currs),\n                })\n\n        prev_labels = [int(x) for x in np.unique(prev) if int(x) != 0]\n        prev_with_child = set(by_prev.keys())\n        for pl in prev_labels:\n            if pl not in prev_with_child:\n                events.append({\n                    "step": step,\n                    "event_type": "extinction_or_absorption",\n                    "track_id": self.prev_label_to_track.get(pl, -1),\n                    "prev_label": pl,\n                })\n\n        self.prev_labels = labels.copy()\n        self.prev_label_to_track = curr_to_track\n        return curr_to_track, events, overlaps\n\n\ndef load_snapshot(path: Path) -> Tuple[int, np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray]:\n    with np.load(path, allow_pickle=False) as data:\n        step = int(np.array(data["step"]).item()) if "step" in data else int(path.stem.split("_")[-1])\n        B = data["B"].astype(np.float32)\n        T = data["T"].astype(np.float32)\n        M = data["M"].astype(np.float32)\n        R = data["R"].astype(np.float32) if "R" in data else np.zeros_like(B)\n        X = data["X"].astype(np.float32) if "X" in data else np.zeros_like(B)\n    return step, B, T, M, R, X\n\n\ndef analyze_environment_snapshots(\n    env: str,\n    env_dir: Path,\n    threshold_name: str,\n    b_thr: float,\n    t_thr: float,\n    min_component_voxels: int,\n    min_lumen_voxels: int,\n    detect_lumens: bool,\n    logger: Logger,\n) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], List[Dict[str, Any]], List[Dict[str, Any]]]:\n    snapdir = env_dir / "open_sea_snapshots"\n    snaps = sorted(snapdir.glob("open_sea_step_*.npz"))\n    if not snaps:\n        raise FileNotFoundError(f"no snapshots found in {snapdir}")\n\n    tracker = ComponentTracker(min_overlap=5)\n    comp_rows: List[Dict[str, Any]] = []\n    event_rows: List[Dict[str, Any]] = []\n    overlap_rows: List[Dict[str, Any]] = []\n    label_cache: Dict[int, np.ndarray] = {}\n\n    logger.log(f"    {env}/{threshold_name}: analyzing {len(snaps)} snapshots")\n\n    for idx, sp in enumerate(snaps, 1):\n        step, B, T, M, R, X = load_snapshot(sp)\n        mask = (B >= b_thr) & (T >= t_thr)\n        labels, _ = detect_labels(mask)\n        labels, sizes = filter_small_labels(labels, min_component_voxels)\n        label_cache[step] = labels\n\n        labs = [int(x) for x in np.unique(labels) if int(x) != 0]\n        prelim: Dict[int, Dict[str, Any]] = {}\n        centroids: Dict[int, Tuple[float, float, float]] = {}\n        absM = np.abs(M)\n\n        for lab in labs:\n            cmask = labels == lab\n            pts = np.argwhere(cmask)\n            vol = int(pts.shape[0])\n            if vol == 0:\n                continue\n            weights = (B[cmask] + T[cmask] + 1e-6).astype(float)\n            centroid = np.average(pts.astype(float), axis=0, weights=weights)\n            cx, cy, cz = float(centroid[0]), float(centroid[1]), float(centroid[2])\n            centroids[lab] = (cx, cy, cz)\n            surface = component_surface_area(cmask)\n            compactness = float((vol ** (2.0 / 3.0)) / (surface + 1e-12))\n            elongation, planarity, bbox = shape_traits(pts)\n\n            if detect_lumens:\n                lcount, lvol = lumen_traits(cmask, min_lumen_voxels)\n            else:\n                lcount, lvol = 0, 0\n\n            prelim[lab] = {\n                "environment": env,\n                "threshold_name": threshold_name,\n                "step": step,\n                "component_label": lab,\n                "volume": vol,\n                "surface_area": surface,\n                "compactness": compactness,\n                "elongation": elongation,\n                "planarity": planarity,\n                "bbox_x": bbox[0],\n                "bbox_y": bbox[1],\n                "bbox_z": bbox[2],\n                "centroid_x": cx,\n                "centroid_y": cy,\n                "centroid_z": cz,\n                "mean_B": float(np.mean(B[cmask])),\n                "mean_T": float(np.mean(T[cmask])),\n                "var_T": float(np.var(T[cmask])),\n                "mean_abs_M": float(np.mean(absM[cmask])),\n                "std_abs_M": float(np.std(absM[cmask])),\n                "mean_R": float(np.mean(R[cmask])),\n                "mean_X": float(np.mean(X[cmask])),\n                "lumen_count": int(lcount),\n                "lumen_volume": int(lvol),\n                "lumen_volume_fraction": float(lvol / max(vol, 1)),\n            }\n\n        curr_to_track, events, overlaps = tracker.assign(step, labels, centroids)\n        for e in events:\n            e["environment"] = env\n            e["threshold_name"] = threshold_name\n        for o in overlaps:\n            o["environment"] = env\n            o["threshold_name"] = threshold_name\n        event_rows.extend(events)\n        overlap_rows.extend(overlaps)\n\n        for lab, row in prelim.items():\n            tid = curr_to_track[lab]\n            st = tracker.tracks[tid]\n            net = st.net(centroids[lab])\n            row["track_id"] = tid\n            row["track_first_step"] = st.first_step\n            row["track_observations"] = st.observations\n            row["cumulative_path"] = float(st.cumulative_path)\n            row["net_displacement"] = float(net)\n            row["persistence_ratio"] = float(net / st.cumulative_path) if st.cumulative_path > 1e-12 else 0.0\n            comp_rows.append(row)\n\n        if idx % max(1, len(snaps)//5) == 0 or idx == len(snaps):\n            logger.log(f"      processed {idx}/{len(snaps)} snapshots; component observations={len(comp_rows)}")\n\n    pop_rows = compute_population_diversity(env, threshold_name, comp_rows, snaps)\n    return comp_rows, pop_rows, event_rows, overlap_rows\n\n\ndef compute_population_diversity(env: str, threshold_name: str, comp_rows: List[Dict[str, Any]], snaps: List[Path]) -> List[Dict[str, Any]]:\n    if comp_rows:\n        X = np.array([[to_float(r.get(c)) for c in TRAIT_COLUMNS] for r in comp_rows], dtype=float)\n        X = np.nan_to_num(X, nan=0.0, posinf=0.0, neginf=0.0)\n        mu = X.mean(axis=0)\n        sd = X.std(axis=0)\n        sd[sd < 1e-12] = 1.0\n        Z = (X - mu) / sd\n    else:\n        Z = np.zeros((0, len(TRAIT_COLUMNS)), dtype=float)\n\n    # map row index by step\n    by_step_idx: Dict[int, List[int]] = {}\n    for i, r in enumerate(comp_rows):\n        by_step_idx.setdefault(to_int(r.get("step")), []).append(i)\n\n    all_steps = []\n    for sp in snaps:\n        try:\n            all_steps.append(int(sp.stem.split("_")[-1]))\n        except Exception:\n            pass\n    all_steps = sorted(set(all_steps))\n\n    rows: List[Dict[str, Any]] = []\n    for st in all_steps:\n        idx = by_step_idx.get(st, [])\n        n = len(idx)\n        if n <= 1:\n            mean_pairwise = 0.0\n            median_pairwise = 0.0\n            dispersion = 0.0\n        else:\n            sub = Z[idx, :]\n            diffs = sub[:, None, :] - sub[None, :, :]\n            dmat = np.sqrt(np.sum(diffs * diffs, axis=2))\n            tri = dmat[np.triu_indices(n, k=1)]\n            mean_pairwise = float(np.mean(tri)) if tri.size else 0.0\n            median_pairwise = float(np.median(tri)) if tri.size else 0.0\n            dispersion = float(np.mean(np.sum((sub - sub.mean(axis=0))**2, axis=1)))\n        vols = [to_float(comp_rows[i].get("volume")) for i in idx]\n        rows.append({\n            "environment": env,\n            "threshold_name": threshold_name,\n            "step": st,\n            "component_count": n,\n            "total_component_volume": float(np.sum(vols)) if vols else 0.0,\n            "largest_component_volume": float(np.max(vols)) if vols else 0.0,\n            "mean_pairwise_trait_distance": mean_pairwise,\n            "median_pairwise_trait_distance": median_pairwise,\n            "trait_dispersion": dispersion,\n        })\n    return rows\n\n\n# =============================================================================\n# Phase metrics, EII, reports\n# =============================================================================\n\ndef get_phase_steps(pop_rows: List[Dict[str, Any]]) -> Tuple[int, int, int]:\n    if not pop_rows:\n        return 0, 0, 0\n    steps = [to_int(r["step"]) for r in pop_rows]\n    counts = [to_int(r["component_count"]) for r in pop_rows]\n    initial = min(steps)\n    final = max(steps)\n    refusion = final\n    for st, c in zip(steps, counts):\n        if st > initial and c <= 1:\n            refusion = st\n            break\n    return initial, refusion, final\n\n\ndef weighted_mean(rows: List[Dict[str, Any]], key: str, weight_key: str = "volume") -> float:\n    if not rows:\n        return 0.0\n    vals = np.array([to_float(r.get(key)) for r in rows], dtype=float)\n    weights = np.array([max(to_float(r.get(weight_key)), 0.0) for r in rows], dtype=float)\n    if np.sum(weights) <= 0:\n        return float(np.mean(vals)) if vals.size else 0.0\n    return float(np.average(vals, weights=weights))\n\n\ndef snapshot_inner_outer_metrics(env: str, threshold_name: str, phase: str, step: int, env_dir: Path, b_thr: float, t_thr: float) -> Dict[str, Any]:\n    out: Dict[str, Any] = {\n        "environment": env,\n        "threshold_name": threshold_name,\n        "phase": phase,\n        "step": step,\n        "snapshot_available": 0,\n    }\n    sp = env_dir / "open_sea_snapshots" / f"open_sea_step_{step:06d}.npz"\n    if not sp.exists():\n        return out\n    step2, B, T, M, R, X = load_snapshot(sp)\n    mask = (B >= b_thr) & (T >= t_thr)\n    outside = ~mask\n    absM = np.abs(M)\n\n    def mean_on(arr, m):\n        return float(np.mean(arr[m])) if np.any(m) else 0.0\n    def std_on(arr, m):\n        return float(np.std(arr[m])) if np.any(m) else 0.0\n\n    out.update({\n        "snapshot_available": 1,\n        "inside_voxels": int(np.sum(mask)),\n        "outside_voxels": int(np.sum(outside)),\n        "inside_mean_B": mean_on(B, mask),\n        "inside_mean_T": mean_on(T, mask),\n        "inside_var_T": float(np.var(T[mask])) if np.any(mask) else 0.0,\n        "inside_mean_abs_M": mean_on(absM, mask),\n        "inside_std_abs_M": std_on(absM, mask),\n        "inside_mean_R": mean_on(R, mask),\n        "inside_mean_X": mean_on(X, mask),\n        "outside_mean_B": mean_on(B, outside),\n        "outside_mean_T": mean_on(T, outside),\n        "outside_mean_abs_M": mean_on(absM, outside),\n        "outside_std_abs_M": std_on(absM, outside),\n        "outside_mean_R": mean_on(R, outside),\n        "outside_std_R": std_on(R, outside),\n        "outside_mean_X": mean_on(X, outside),\n        "outside_std_X": std_on(X, outside),\n    })\n    out["contrast_abs_M_inside_minus_outside"] = out["inside_mean_abs_M"] - out["outside_mean_abs_M"]\n    out["contrast_R_inside_minus_outside"] = out["inside_mean_R"] - out["outside_mean_R"]\n    out["contrast_X_inside_minus_outside"] = out["inside_mean_X"] - out["outside_mean_X"]\n    out["contrast_T_inside_minus_outside"] = out["inside_mean_T"] - out["outside_mean_T"]\n    return out\n\n\ndef phase_metrics(env: str, threshold_name: str, phase: str, step: int, comp_rows: List[Dict[str, Any]], pop_by_step: Dict[int, Dict[str, Any]], env_dir: Path, b_thr: float, t_thr: float) -> Dict[str, Any]:\n    rows = [r for r in comp_rows if to_int(r["step"]) == step]\n    pop = pop_by_step.get(step, {})\n    vols = [to_float(r.get("volume")) for r in rows]\n    out: Dict[str, Any] = {\n        "environment": env,\n        "threshold_name": threshold_name,\n        "phase": phase,\n        "step": step,\n        "component_count": len(rows),\n        "total_volume": float(np.sum(vols)) if vols else 0.0,\n        "largest_volume": float(np.max(vols)) if vols else 0.0,\n        "total_surface_area": float(np.sum([to_float(r.get("surface_area")) for r in rows])) if rows else 0.0,\n        "total_lumen_count": int(np.sum([to_float(r.get("lumen_count")) for r in rows])) if rows else 0,\n        "total_lumen_volume": float(np.sum([to_float(r.get("lumen_volume")) for r in rows])) if rows else 0.0,\n        "max_cumulative_path": float(np.max([to_float(r.get("cumulative_path")) for r in rows])) if rows else 0.0,\n        "max_net_displacement": float(np.max([to_float(r.get("net_displacement")) for r in rows])) if rows else 0.0,\n        "mean_pairwise_trait_distance": to_float(pop.get("mean_pairwise_trait_distance")),\n        "trait_dispersion": to_float(pop.get("trait_dispersion")),\n    }\n    for key in [\n        "mean_B", "mean_T", "var_T", "mean_abs_M", "std_abs_M",\n        "mean_R", "mean_X", "compactness", "elongation", "planarity", "lumen_volume_fraction",\n    ]:\n        out[f"vw_{key}"] = weighted_mean(rows, key)\n    smet = snapshot_inner_outer_metrics(env, threshold_name, phase, step, env_dir, b_thr, t_thr)\n    for k, v in smet.items():\n        if k not in ("environment", "threshold_name", "phase", "step"):\n            out[k] = v\n    return out\n\n\ndef summarize_events(env: str, threshold_name: str, events: List[Dict[str, Any]]) -> Dict[str, Any]:\n    rows = [e for e in events if e["environment"] == env and e["threshold_name"] == threshold_name]\n    counts: Dict[str, int] = {}\n    fusion_steps: List[int] = []\n    for r in rows:\n        et = str(r.get("event_type", "unknown"))\n        counts[et] = counts.get(et, 0) + 1\n        if et == "fusion_into_component":\n            fusion_steps.append(to_int(r.get("step")))\n    out: Dict[str, Any] = {\n        "environment": env,\n        "threshold_name": threshold_name,\n        "fusion_event_count": counts.get("fusion_into_component", 0),\n        "emergence_count": counts.get("emergence", 0),\n        "continuation_count": counts.get("continuation", 0),\n        "absorption_count": counts.get("extinction_or_absorption", 0),\n        "fission_event_count": counts.get("fission_from_previous", 0),\n        "first_fusion_step": min(fusion_steps) if fusion_steps else "",\n        "last_fusion_step": max(fusion_steps) if fusion_steps else "",\n    }\n    for k, v in counts.items():\n        out[f"event_{k}"] = v\n    return out\n\n\ndef diff(prefix: str, refu: Dict[str, Any], init: Dict[str, Any], key: str) -> Dict[str, float]:\n    a = to_float(refu.get(key))\n    b = to_float(init.get(key))\n    return {\n        f"{prefix}_{key}_initial": b,\n        f"{prefix}_{key}_refusion": a,\n        f"{prefix}_{key}_delta": a - b,\n        f"{prefix}_{key}_ratio": (a / b) if abs(b) > 1e-12 else 0.0,\n    }\n\n\ndef summarize_environment_transform(env: str, threshold_name: str, phase_rows: List[Dict[str, Any]], pop_rows: List[Dict[str, Any]], event_row: Dict[str, Any]) -> Dict[str, Any]:\n    by_phase = {r["phase"]: r for r in phase_rows if r["environment"] == env and r["threshold_name"] == threshold_name}\n    init = by_phase["initial"]\n    refu = by_phase["refusion"]\n    final = by_phase["final"]\n    steps = [to_int(r["step"]) for r in pop_rows if r["environment"] == env and r["threshold_name"] == threshold_name]\n    counts = [to_float(r["component_count"]) for r in pop_rows if r["environment"] == env and r["threshold_name"] == threshold_name]\n    dists = [to_float(r["mean_pairwise_trait_distance"]) for r in pop_rows if r["environment"] == env and r["threshold_name"] == threshold_name]\n\n    out: Dict[str, Any] = {\n        "environment": env,\n        "threshold_name": threshold_name,\n        "initial_step": init["step"],\n        "refusion_step": refu["step"],\n        "final_step": final["step"],\n        "time_to_refusion": refu["step"] - init["step"],\n        "initial_component_count": init["component_count"],\n        "refusion_component_count": refu["component_count"],\n        "final_component_count": final["component_count"],\n        "max_component_count": float(np.max(counts)) if counts else 0.0,\n        "component_count_auc": safe_trapezoid(counts, steps),\n        "initial_trait_distance": init.get("mean_pairwise_trait_distance", 0.0),\n        "refusion_trait_distance": refu.get("mean_pairwise_trait_distance", 0.0),\n        "max_trait_distance": float(np.max(dists)) if dists else 0.0,\n        "trait_distance_auc": safe_trapezoid(dists, steps),\n    }\n    for key in [\n        "total_volume", "largest_volume", "total_surface_area",\n        "vw_mean_B", "vw_mean_T", "vw_var_T", "vw_mean_abs_M", "vw_std_abs_M",\n        "vw_mean_R", "vw_mean_X", "vw_compactness", "vw_elongation", "vw_planarity",\n        "total_lumen_count", "total_lumen_volume", "max_cumulative_path", "max_net_displacement",\n    ]:\n        out.update(diff("component", refu, init, key))\n    for key in [\n        "inside_voxels", "inside_mean_B", "inside_mean_T", "inside_var_T",\n        "inside_mean_abs_M", "inside_std_abs_M", "inside_mean_R", "inside_mean_X",\n        "outside_mean_abs_M", "outside_std_abs_M", "outside_mean_R", "outside_std_R",\n        "outside_mean_X", "outside_std_X",\n        "contrast_abs_M_inside_minus_outside",\n        "contrast_R_inside_minus_outside",\n        "contrast_X_inside_minus_outside",\n        "contrast_T_inside_minus_outside",\n    ]:\n        out.update(diff("snapshot", refu, init, key))\n    out.update(event_row)\n    return out\n\n\ndef add_eii(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:\n    if not rows:\n        return []\n    keys = [\n        "component_vw_mean_T_delta",\n        "component_vw_var_T_delta",\n        "component_vw_mean_abs_M_delta",\n        "component_vw_std_abs_M_delta",\n        "snapshot_contrast_abs_M_inside_minus_outside_delta",\n        "snapshot_contrast_R_inside_minus_outside_delta",\n        "component_max_net_displacement_delta",\n        "trait_distance_auc",\n        "time_to_refusion",\n    ]\n    stats: Dict[str, Tuple[np.ndarray, float, float]] = {}\n    for k in keys:\n        arr = np.array([abs(to_float(r.get(k))) for r in rows], dtype=float)\n        mu = float(np.mean(arr))\n        sd = float(np.std(arr))\n        if sd < 1e-12:\n            sd = 1.0\n        stats[k] = (arr, mu, sd)\n\n    out: List[Dict[str, Any]] = []\n    for i, r in enumerate(rows):\n        rr = dict(r)\n        eii = 0.0\n        for k in keys:\n            arr, mu, sd = stats[k]\n            z = (arr[i] - mu) / sd\n            rr[f"EII_abs_z_{k}"] = float(z)\n            eii += float(z)\n        rr["EII_environmental_imprint_index"] = float(eii)\n        out.append(rr)\n    out = sorted(out, key=lambda x: to_float(x.get("EII_environmental_imprint_index")), reverse=True)\n    for rank, r in enumerate(out, 1):\n        r["EII_rank"] = rank\n    return out\n\n\n# =============================================================================\n# Figures and reports\n# =============================================================================\n\ndef make_threshold_figures(outdir: Path, ranked: List[Dict[str, Any]], threshold_name: str) -> None:\n    if not MATPLOTLIB_AVAILABLE or not ranked:\n        return\n    figdir = outdir / "figures"\n    figdir.mkdir(parents=True, exist_ok=True)\n\n    def bar(key: str, fname: str, ylabel: str, title: str):\n        envs = [r["environment"] for r in ranked]\n        vals = [to_float(r.get(key)) for r in ranked]\n        plt.figure(figsize=(10, 5))\n        plt.bar(envs, vals)\n        plt.xticks(rotation=30, ha="right")\n        plt.ylabel(ylabel)\n        plt.title(title)\n        plt.tight_layout()\n        plt.savefig(figdir / fname, dpi=200)\n        plt.close()\n\n    bar("EII_environmental_imprint_index", f"{threshold_name}_EII_by_environment.png", "EII", f"EII by environment ({threshold_name})")\n    bar("time_to_refusion", f"{threshold_name}_refusion_time_by_environment.png", "steps", f"Time to re-fusion ({threshold_name})")\n    bar("trait_distance_auc", f"{threshold_name}_trait_auc_by_environment.png", "trait AUC", f"Trait diversity exposure ({threshold_name})")\n    bar("component_vw_mean_T_delta", f"{threshold_name}_delta_meanT_by_environment.png", "Δmean_T", f"Membrane thickness change ({threshold_name})")\n    bar("component_vw_mean_abs_M_delta", f"{threshold_name}_delta_absM_by_environment.png", "Δmean_abs_M", f"Internal M change ({threshold_name})")\n\n\ndef make_voxel_slice_figures(root: Path, outdir: Path, threshold_name: str, phase_rows: List[Dict[str, Any]], logger: Logger) -> None:\n    if not MATPLOTLIB_AVAILABLE:\n        logger.log("matplotlib not available; skipping voxel slices")\n        return\n    figdir = outdir / "voxel_slices"\n    figdir.mkdir(parents=True, exist_ok=True)\n    fields = ["B", "T", "absM", "R", "X"]\n\n    for env in DEFAULT_ENVS:\n        env_phase = [r for r in phase_rows if r["environment"] == env and r["threshold_name"] == threshold_name]\n        if not env_phase:\n            continue\n        phase_data: Dict[str, Dict[str, Any]] = {}\n        env_dir = root / env\n        for ph in ["initial", "refusion", "final"]:\n            rows = [r for r in env_phase if r["phase"] == ph]\n            if not rows:\n                continue\n            step = to_int(rows[0]["step"])\n            sp = env_dir / "open_sea_snapshots" / f"open_sea_step_{step:06d}.npz"\n            if not sp.exists():\n                continue\n            _, B, T, M, R, X = load_snapshot(sp)\n            z_scores = (B + T).sum(axis=(0, 1))\n            z = int(np.argmax(z_scores)) if z_scores.size else B.shape[2] // 2\n            phase_data[ph] = {\n                "step": step,\n                "z": z,\n                "B": B[:, :, z],\n                "T": T[:, :, z],\n                "absM": np.abs(M[:, :, z]),\n                "R": R[:, :, z],\n                "X": X[:, :, z],\n            }\n        if not phase_data:\n            continue\n\n        nrows = len([p for p in ["initial", "refusion", "final"] if p in phase_data])\n        plt.figure(figsize=(14, 3.2 * nrows))\n        row_idx = 0\n        for ph in ["initial", "refusion", "final"]:\n            if ph not in phase_data:\n                continue\n            for j, field in enumerate(fields):\n                ax = plt.subplot(nrows, len(fields), row_idx * len(fields) + j + 1)\n                ax.imshow(phase_data[ph][field])\n                ax.set_xticks([])\n                ax.set_yticks([])\n                ax.set_title(f"{ph} {field}\\nstep {phase_data[ph][\'step\']}, z={phase_data[ph][\'z\']}", fontsize=8)\n            row_idx += 1\n        plt.suptitle(f"{env} initial / re-fusion / final ({threshold_name})")\n        plt.tight_layout()\n        plt.savefig(figdir / f"{threshold_name}_{env}_initial_refusion_final_slices.png", dpi=200)\n        plt.close()\n\n\ndef write_threshold_report(path: Path, ranked: List[Dict[str, Any]], threshold_name: str) -> None:\n    lines: List[str] = []\n    lines.append("# Environmental Imprint / Refusion Transformation Report\\n\\n")\n    lines.append(f"Version: `{VERSION}`\\n\\n")\n    lines.append(f"Threshold set: `{threshold_name}`\\n\\n")\n    lines.append("| rank | environment | EII | refusion step | trait AUC | max trait distance | Δvolume | Δmean_T | Δvar_T | Δmean_abs_M | Δstd_abs_M | ΔM contrast | Δmax net displacement | fusion events |\\n")\n    lines.append("|---:|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|\\n")\n    for r in ranked:\n        lines.append(\n            f"| {to_int(r.get(\'EII_rank\'))} | {r.get(\'environment\')} | "\n            f"{to_float(r.get(\'EII_environmental_imprint_index\')):.3f} | "\n            f"{to_float(r.get(\'time_to_refusion\')):.0f} | "\n            f"{to_float(r.get(\'trait_distance_auc\')):.3f} | "\n            f"{to_float(r.get(\'max_trait_distance\')):.3f} | "\n            f"{to_float(r.get(\'component_total_volume_delta\')):.3f} | "\n            f"{to_float(r.get(\'component_vw_mean_T_delta\')):.6f} | "\n            f"{to_float(r.get(\'component_vw_var_T_delta\')):.6f} | "\n            f"{to_float(r.get(\'component_vw_mean_abs_M_delta\')):.6f} | "\n            f"{to_float(r.get(\'component_vw_std_abs_M_delta\')):.6f} | "\n            f"{to_float(r.get(\'snapshot_contrast_abs_M_inside_minus_outside_delta\')):.6f} | "\n            f"{to_float(r.get(\'component_max_net_displacement_delta\')):.3f} | "\n            f"{to_int(r.get(\'fusion_event_count\'))} |\\n"\n        )\n    if ranked:\n        lines.append("\\n")\n        lines.append(f"Top EII condition: `{ranked[0][\'environment\']}`.\\n")\n    path.write_text("".join(lines), encoding="utf-8")\n\n\ndef write_master_report(outdir: Path, all_ranked: List[Dict[str, Any]], threshold_summary: List[Dict[str, Any]]) -> None:\n    lines: List[str] = []\n    lines.append("# Fixed 10-Hole Environmental-History Posthoc Analysis 1-4\\n\\n")\n    lines.append(f"Version: `{VERSION}`\\n\\n")\n    lines.append("This is a completely post-hoc analysis. No simulation was rerun.\\n\\n")\n    lines.append("Analyses included: EII, initial→re-fusion→final comparison, voxel-slice visualization, and threshold sensitivity.\\n\\n")\n\n    lines.append("## Threshold sensitivity summary\\n\\n")\n    lines.append("| threshold | environment | rank | EII | refusion step | trait AUC | max trait distance | final comps | fusion events |\\n")\n    lines.append("|---|---|---:|---:|---:|---:|---:|---:|---:|\\n")\n    for r in threshold_summary:\n        lines.append(\n            f"| {r[\'threshold_name\']} | {r[\'environment\']} | {to_int(r.get(\'EII_rank\'))} | "\n            f"{to_float(r.get(\'EII_environmental_imprint_index\')):.3f} | "\n            f"{to_float(r.get(\'time_to_refusion\')):.0f} | "\n            f"{to_float(r.get(\'trait_distance_auc\')):.3f} | "\n            f"{to_float(r.get(\'max_trait_distance\')):.3f} | "\n            f"{to_float(r.get(\'final_component_count\')):.0f} | "\n            f"{to_int(r.get(\'fusion_event_count\'))} |\\n"\n        )\n\n    lines.append("\\n## Interpretation boundary\\n\\n")\n    lines.append("EII is a descriptive release-to-refusion transformation index. It is not a life index, not a fitness measure, and not evidence of evolution by itself. The central observation is whether identical initial release components acquire environment-dependent structural and motion histories before re-fusion.\\n")\n    (outdir / "posthoc_1to4_master_report.md").write_text("".join(lines), encoding="utf-8")\n\n\n# =============================================================================\n# Main posthoc pipeline\n# =============================================================================\n\ndef analyze_threshold(root: Path, outdir: Path, threshold_name: str, b_thr: float, t_thr: float, args: argparse.Namespace, logger: Logger) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], List[Dict[str, Any]]]:\n    logger.log(f"THRESHOLD {threshold_name}: B>={b_thr}, T>={t_thr}")\n    tdir = outdir / f"threshold_{threshold_name}"\n    tdir.mkdir(parents=True, exist_ok=True)\n\n    all_comp: List[Dict[str, Any]] = []\n    all_pop: List[Dict[str, Any]] = []\n    all_events: List[Dict[str, Any]] = []\n    all_overlaps: List[Dict[str, Any]] = []\n    all_phase: List[Dict[str, Any]] = []\n    transform_rows: List[Dict[str, Any]] = []\n    event_summary_rows: List[Dict[str, Any]] = []\n\n    for env in args.envs:\n        env_dir = root / env\n        if not env_dir.exists():\n            logger.log(f"  skip {env}: folder missing")\n            continue\n        comp, pop, events, overlaps = analyze_environment_snapshots(\n            env=env,\n            env_dir=env_dir,\n            threshold_name=threshold_name,\n            b_thr=b_thr,\n            t_thr=t_thr,\n            min_component_voxels=args.min_component_voxels,\n            min_lumen_voxels=args.min_lumen_voxels,\n            detect_lumens=args.detect_lumens,\n            logger=logger,\n        )\n        all_comp.extend(comp)\n        all_pop.extend(pop)\n        all_events.extend(events)\n        all_overlaps.extend(overlaps)\n\n        pop_by_step = {to_int(r["step"]): r for r in pop}\n        initial, refusion, final = get_phase_steps(pop)\n        phase_rows = []\n        for phase, step in [("initial", initial), ("refusion", refusion), ("final", final)]:\n            pr = phase_metrics(env, threshold_name, phase, step, comp, pop_by_step, env_dir, b_thr, t_thr)\n            phase_rows.append(pr)\n            all_phase.append(pr)\n        evsum = summarize_events(env, threshold_name, events)\n        event_summary_rows.append(evsum)\n        transform_rows.append(summarize_environment_transform(env, threshold_name, phase_rows, pop, evsum))\n\n    ranked = add_eii(transform_rows)\n\n    write_csv(tdir / "component_traits_over_time.csv", all_comp)\n    write_csv(tdir / "population_diversity_timeseries.csv", all_pop)\n    write_csv(tdir / "component_events.csv", all_events)\n    write_csv(tdir / "component_overlap_audit.csv", all_overlaps)\n    write_csv(tdir / "environment_phase_metrics_long.csv", all_phase)\n    write_csv(tdir / "environment_event_summary.csv", event_summary_rows)\n    write_csv(tdir / "environment_refusion_transform_summary.csv", transform_rows)\n    write_csv(tdir / "environment_transform_rankings.csv", ranked)\n\n    make_threshold_figures(tdir, ranked, threshold_name)\n    make_voxel_slice_figures(root, tdir, threshold_name, all_phase, logger)\n    write_threshold_report(tdir / "posthoc_refusion_transform_report.md", ranked, threshold_name)\n\n    return ranked, transform_rows, all_phase\n\n\ndef parse_args() -> argparse.Namespace:\n    p = argparse.ArgumentParser()\n    p.add_argument("--root", type=Path, required=True, help="Root folder from fixed10holes openenv sweep.")\n    p.add_argument("--outdir", type=Path, required=True)\n    p.add_argument("--envs", type=str, default=",".join(DEFAULT_ENVS), help="Comma-separated environment folder names.")\n    p.add_argument("--thresholds", type=str, default="loose:0.14:0.016,main:0.16:0.018,strict:0.18:0.020")\n    p.add_argument("--min-component-voxels", type=int, default=12)\n    p.add_argument("--min-lumen-voxels", type=int, default=20)\n    p.add_argument("--detect-lumens", action="store_true", help="Detect internal lumens; slower. Default off for speed.")\n    return p.parse_args()\n\n\ndef main() -> int:\n    args = parse_args()\n    args.root = args.root.expanduser().resolve()\n    args.outdir = args.outdir.expanduser().resolve()\n    args.envs = [e.strip() for e in args.envs.split(",") if e.strip()]\n    thresholds = parse_thresholds(args.thresholds)\n\n    args.outdir.mkdir(parents=True, exist_ok=True)\n    logger = Logger(args.outdir)\n\n    try:\n        logger.log(f"START posthoc fixed10 env history 1-4 :: version={VERSION}")\n        logger.log(f"root: {args.root}")\n        logger.log(f"outdir: {args.outdir}")\n        logger.log(f"envs: {args.envs}")\n        logger.log(f"thresholds: {thresholds}")\n        logger.log(f"scipy_available: {SCIPY_AVAILABLE}")\n        logger.log(f"matplotlib_available: {MATPLOTLIB_AVAILABLE}")\n        logger.log(f"detect_lumens: {args.detect_lumens}")\n\n        if not SCIPY_AVAILABLE:\n            raise RuntimeError("scipy is required for connected-component labeling")\n\n        with open(args.outdir / "posthoc_1to4_parameters.json", "w", encoding="utf-8") as f:\n            json.dump(json_safe({\n                "version": VERSION,\n                "root": args.root,\n                "outdir": args.outdir,\n                "envs": args.envs,\n                "thresholds": thresholds,\n                "min_component_voxels": args.min_component_voxels,\n                "min_lumen_voxels": args.min_lumen_voxels,\n                "detect_lumens": args.detect_lumens,\n            }), f, indent=2, ensure_ascii=False)\n\n        all_ranked: List[Dict[str, Any]] = []\n        all_transform: List[Dict[str, Any]] = []\n        all_phase: List[Dict[str, Any]] = []\n\n        # Run main first if present, then others.\n        ordered = []\n        if "main" in thresholds:\n            ordered.append(("main", thresholds["main"]))\n        for name, vals in thresholds.items():\n            if name != "main":\n                ordered.append((name, vals))\n\n        for name, (b, t) in ordered:\n            ranked, transform, phase = analyze_threshold(args.root, args.outdir, name, b, t, args, logger)\n            all_ranked.extend(ranked)\n            all_transform.extend(transform)\n            all_phase.extend(phase)\n\n        write_csv(args.outdir / "ALL_threshold_environment_transform_rankings.csv", all_ranked)\n        write_csv(args.outdir / "ALL_threshold_environment_refusion_transform_summary.csv", all_transform)\n        write_csv(args.outdir / "ALL_threshold_environment_phase_metrics_long.csv", all_phase)\n\n        # condensed summary for the master report\n        threshold_summary = sorted(all_ranked, key=lambda r: (0 if r["threshold_name"] == "main" else (1 if r["threshold_name"] == "loose" else 2), to_int(r.get("EII_rank"))))\n        write_csv(args.outdir / "threshold_sensitivity_summary.csv", threshold_summary)\n        write_master_report(args.outdir, all_ranked, threshold_summary)\n\n        logger.log("DONE")\n        logger.log(f"master report: {args.outdir / \'posthoc_1to4_master_report.md\'}")\n        return 0\n\n    except Exception as e:\n        logger.log(f"ERROR: {type(e).__name__}: {e}")\n        (args.outdir / "ERROR.txt").write_text(traceback.format_exc(), encoding="utf-8")\n        return 1\n    finally:\n        logger.close()\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'POSTHOC_IMPRINT_RETENTION_IRI.py': '#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n"""\nPOSTHOC_IMPRINT_RETENTION_IRI.py\n\nPurpose\n-------\nCompletely post-hoc analysis of whether release-to-refusion structural changes\nremain in the final re-fused aggregate.\n\nThis script does NOT rerun any simulation.\n\nIt reads outputs from:\n    POSTHOC_FIXED10_ENV_HISTORY_1TO4.py\n\nExpected input root:\n    ~/Desktop/fixed10holes_posthoc_1to4/\n\nRequired file:\n    ALL_threshold_environment_phase_metrics_long.csv\n\nOptional files:\n    ALL_threshold_environment_transform_rankings.csv\n    threshold_sensitivity_summary.csv\n\nCore idea\n---------\nFor each threshold/environment/metric:\n\n    initial -> re-fusion  : environment-induced transformation\n    initial -> final      : retained transformation\n\nImprint Retention Index (IRI):\n\n    IRI = |final - initial| / (|refusion - initial| + eps)\n\nInterpretation:\n    IRI ~ 0   : re-fusion change relaxed back toward initial\n    IRI ~ 1   : re-fusion change retained until final\n    IRI > 1   : transformation continued after re-fusion\n\nThis is descriptive post-hoc analysis.\nIt is not a life index, not a fitness measure, and not evidence of evolution by itself.\n\nRun\n---\nSCRIPT=$(ls -t ~/Downloads/POSTHOC_IMPRINT_RETENTION_IRI*.py | head -1)\n\npython3 -u "$SCRIPT" \\\n  --posthoc-root ~/Desktop/fixed10holes_posthoc_1to4 \\\n  --outdir ~/Desktop/fixed10holes_imprint_retention_IRI \\\n  2>&1 | tee ~/Desktop/fixed10holes_imprint_retention_IRI.log\n\nOutputs\n-------\noutdir/\n  IRI_metric_long.csv\n  IRI_environment_summary.csv\n  IRI_threshold_summary.csv\n  IRI_environment_rankings.csv\n  imprint_retention_report.md\n  figures/\n    IRI_by_environment_main.png\n    retained_EII_by_environment_main.png\n    IRI_by_threshold_environment.png\n    metric_retention_heatmap_main.png\n\nVersion\n-------\n2026-06-05-IRI-posthoc-v1\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport csv\nimport json\nimport math\nimport time\nimport traceback\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional, Tuple\n\nimport numpy as np\n\ntry:\n    import matplotlib\n    matplotlib.use("Agg")\n    import matplotlib.pyplot as plt\n    MATPLOTLIB_AVAILABLE = True\nexcept Exception:\n    plt = None\n    MATPLOTLIB_AVAILABLE = False\n\n\nVERSION = "2026-06-05-IRI-posthoc-v1"\n\nDEFAULT_METRICS = [\n    # membrane structure\n    "vw_mean_B",\n    "vw_mean_T",\n    "vw_var_T",\n    "inside_mean_B",\n    "inside_mean_T",\n    "inside_var_T",\n\n    # internal M structure\n    "vw_mean_abs_M",\n    "vw_std_abs_M",\n    "inside_mean_abs_M",\n    "inside_std_abs_M",\n    "contrast_abs_M_inside_minus_outside",\n\n    # external/inside-outside relation\n    "inside_mean_R",\n    "inside_mean_X",\n    "outside_mean_R",\n    "outside_std_R",\n    "outside_mean_X",\n    "outside_std_X",\n    "contrast_R_inside_minus_outside",\n    "contrast_X_inside_minus_outside",\n\n    # gross morphology/motion\n    "total_volume",\n    "largest_volume",\n    "total_surface_area",\n    "max_net_displacement",\n    "max_cumulative_path",\n]\n\n# Metrics used to compute a compact retained-imprint score.\n# These are the same conceptual families as EII: membrane, M, inner/outer contrast, and motion.\nEII_CORE_METRICS = [\n    "vw_mean_T",\n    "vw_var_T",\n    "vw_mean_abs_M",\n    "vw_std_abs_M",\n    "contrast_abs_M_inside_minus_outside",\n    "contrast_R_inside_minus_outside",\n    "max_net_displacement",\n]\n\n\nclass Logger:\n    def __init__(self, outdir: Path):\n        self.t0 = time.time()\n        outdir.mkdir(parents=True, exist_ok=True)\n        self.fp = open(outdir / "IRI_progress.log", "w", encoding="utf-8")\n\n    def log(self, msg: str) -> None:\n        line = f"[{time.time() - self.t0:9.1f}s] {msg}"\n        print(line, flush=True)\n        self.fp.write(line + "\\n")\n        self.fp.flush()\n\n    def close(self) -> None:\n        try:\n            self.fp.close()\n        except Exception:\n            pass\n\n\ndef to_float(x: Any, default: float = np.nan) -> float:\n    try:\n        if x is None or x == "":\n            return default\n        return float(x)\n    except Exception:\n        return default\n\n\ndef to_int(x: Any, default: int = 0) -> int:\n    try:\n        if x is None or x == "":\n            return default\n        return int(float(x))\n    except Exception:\n        return default\n\n\ndef json_safe(x: Any) -> Any:\n    if isinstance(x, Path):\n        return str(x)\n    if isinstance(x, np.ndarray):\n        return x.tolist()\n    if isinstance(x, np.integer):\n        return int(x)\n    if isinstance(x, np.floating):\n        return float(x)\n    if isinstance(x, np.bool_):\n        return bool(x)\n    if isinstance(x, dict):\n        return {str(k): json_safe(v) for k, v in x.items()}\n    if isinstance(x, (list, tuple)):\n        return [json_safe(v) for v in x]\n    return x\n\n\ndef read_csv_rows(path: Path) -> List[Dict[str, str]]:\n    with open(path, newline="", encoding="utf-8") as f:\n        return list(csv.DictReader(f))\n\n\ndef write_csv(path: Path, rows: List[Dict[str, Any]], fieldnames: Optional[List[str]] = None) -> None:\n    path.parent.mkdir(parents=True, exist_ok=True)\n    if fieldnames is None:\n        keys: List[str] = []\n        seen = set()\n        for r in rows:\n            for k in r.keys():\n                if k not in seen:\n                    keys.append(k)\n                    seen.add(k)\n        fieldnames = keys\n    with open(path, "w", newline="", encoding="utf-8") as f:\n        w = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")\n        w.writeheader()\n        for r in rows:\n            w.writerow({k: json_safe(r.get(k, "")) for k in fieldnames})\n\n\ndef parse_metric_list(s: Optional[str]) -> Optional[List[str]]:\n    if not s:\n        return None\n    return [x.strip() for x in s.split(",") if x.strip()]\n\n\ndef finite_mean(xs: List[float]) -> float:\n    arr = np.asarray(xs, dtype=float)\n    arr = arr[np.isfinite(arr)]\n    return float(np.mean(arr)) if arr.size else np.nan\n\n\ndef finite_median(xs: List[float]) -> float:\n    arr = np.asarray(xs, dtype=float)\n    arr = arr[np.isfinite(arr)]\n    return float(np.median(arr)) if arr.size else np.nan\n\n\ndef finite_sd(xs: List[float]) -> float:\n    arr = np.asarray(xs, dtype=float)\n    arr = arr[np.isfinite(arr)]\n    return float(np.std(arr, ddof=1)) if arr.size > 1 else 0.0\n\n\ndef classify_iri(iri: float) -> str:\n    if not np.isfinite(iri):\n        return "undefined"\n    if iri < 0.25:\n        return "relaxed"\n    if iri < 0.75:\n        return "partially_retained"\n    if iri <= 1.25:\n        return "retained"\n    return "amplified_after_refusion"\n\n\ndef available_metrics(phase_rows: List[Dict[str, str]], requested: Optional[List[str]]) -> List[str]:\n    keys = set()\n    for r in phase_rows:\n        keys.update(r.keys())\n\n    if requested:\n        candidates = requested\n    else:\n        candidates = DEFAULT_METRICS\n\n    usable = []\n    for k in candidates:\n        if k in keys:\n            # ensure at least some numeric values exist\n            vals = [to_float(r.get(k), np.nan) for r in phase_rows]\n            if np.any(np.isfinite(vals)):\n                usable.append(k)\n    return usable\n\n\ndef build_phase_index(rows: List[Dict[str, str]]) -> Dict[Tuple[str, str, str], Dict[str, str]]:\n    idx: Dict[Tuple[str, str, str], Dict[str, str]] = {}\n    for r in rows:\n        env = r.get("environment", "")\n        thr = r.get("threshold_name", "")\n        ph = r.get("phase", "")\n        idx[(thr, env, ph)] = r\n    return idx\n\n\ndef compute_iri_rows(\n    phase_rows: List[Dict[str, str]],\n    metrics: List[str],\n    eps: float,\n) -> List[Dict[str, Any]]:\n    idx = build_phase_index(phase_rows)\n    thresholds = sorted(set(r.get("threshold_name", "") for r in phase_rows))\n    envs = sorted(set(r.get("environment", "") for r in phase_rows))\n\n    rows: List[Dict[str, Any]] = []\n    for thr in thresholds:\n        for env in envs:\n            init = idx.get((thr, env, "initial"))\n            refu = idx.get((thr, env, "refusion"))\n            final = idx.get((thr, env, "final"))\n            if not init or not refu or not final:\n                continue\n\n            for m in metrics:\n                vi = to_float(init.get(m), np.nan)\n                vr = to_float(refu.get(m), np.nan)\n                vf = to_float(final.get(m), np.nan)\n                if not (np.isfinite(vi) and np.isfinite(vr) and np.isfinite(vf)):\n                    continue\n\n                d_ref = vr - vi\n                d_final = vf - vi\n                post_refusion_change = vf - vr\n                abs_ref = abs(d_ref)\n                abs_final = abs(d_final)\n                iri = abs_final / (abs_ref + eps)\n                signed_retention = d_final / d_ref if abs(d_ref) > eps else np.nan\n\n                rows.append({\n                    "threshold_name": thr,\n                    "environment": env,\n                    "metric": m,\n                    "initial": vi,\n                    "refusion": vr,\n                    "final": vf,\n                    "delta_refusion_minus_initial": d_ref,\n                    "delta_final_minus_initial": d_final,\n                    "delta_final_minus_refusion": post_refusion_change,\n                    "abs_delta_refusion": abs_ref,\n                    "abs_delta_final": abs_final,\n                    "IRI_abs_final_over_refusion": iri,\n                    "signed_retention_ratio": signed_retention,\n                    "retention_class": classify_iri(iri),\n                    "initial_step": to_int(init.get("step")),\n                    "refusion_step": to_int(refu.get("step")),\n                    "final_step": to_int(final.get("step")),\n                    "time_to_refusion": to_int(refu.get("step")) - to_int(init.get("step")),\n                    "time_refusion_to_final": to_int(final.get("step")) - to_int(refu.get("step")),\n                })\n    return rows\n\n\ndef zscore_by_threshold(rows: List[Dict[str, Any]], value_key: str, out_key: str) -> None:\n    thresholds = sorted(set(r["threshold_name"] for r in rows))\n    for thr in thresholds:\n        sub = [r for r in rows if r["threshold_name"] == thr]\n        vals = np.asarray([to_float(r.get(value_key), np.nan) for r in sub], dtype=float)\n        finite = vals[np.isfinite(vals)]\n        if finite.size == 0:\n            for r in sub:\n                r[out_key] = np.nan\n            continue\n        mu = float(np.mean(finite))\n        sd = float(np.std(finite))\n        if sd < 1e-12:\n            sd = 1.0\n        for r in sub:\n            v = to_float(r.get(value_key), np.nan)\n            r[out_key] = float((v - mu) / sd) if np.isfinite(v) else np.nan\n\n\ndef compute_environment_summary(metric_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:\n    # Add normalized retained structural magnitude.\n    # retained_abs_z = z(|final-initial|)\n    temp = [dict(r) for r in metric_rows]\n    zscore_by_threshold(temp, "abs_delta_final", "retained_abs_z_by_threshold")\n    zscore_by_threshold(temp, "abs_delta_refusion", "refusion_abs_z_by_threshold")\n\n    grouped: Dict[Tuple[str, str], List[Dict[str, Any]]] = {}\n    for r in temp:\n        grouped.setdefault((r["threshold_name"], r["environment"]), []).append(r)\n\n    rows: List[Dict[str, Any]] = []\n    for (thr, env), rs in sorted(grouped.items()):\n        iri_vals = [to_float(r["IRI_abs_final_over_refusion"]) for r in rs]\n        signed_vals = [to_float(r["signed_retention_ratio"]) for r in rs]\n        retained_z = [to_float(r["retained_abs_z_by_threshold"]) for r in rs]\n        refusion_z = [to_float(r["refusion_abs_z_by_threshold"]) for r in rs]\n\n        # Core metric subset.\n        core = [r for r in rs if r["metric"] in EII_CORE_METRICS]\n        core_iri = [to_float(r["IRI_abs_final_over_refusion"]) for r in core]\n        core_retained_z = [to_float(r["retained_abs_z_by_threshold"]) for r in core]\n\n        class_counts: Dict[str, int] = {}\n        for r in rs:\n            c = r.get("retention_class", "undefined")\n            class_counts[c] = class_counts.get(c, 0) + 1\n\n        row = {\n            "threshold_name": thr,\n            "environment": env,\n            "n_metrics": len(rs),\n            "IRI_mean": finite_mean(iri_vals),\n            "IRI_median": finite_median(iri_vals),\n            "IRI_sd": finite_sd(iri_vals),\n            "signed_retention_mean": finite_mean(signed_vals),\n            "retained_abs_z_mean": finite_mean(retained_z),\n            "refusion_abs_z_mean": finite_mean(refusion_z),\n            "core_IRI_mean": finite_mean(core_iri),\n            "core_IRI_median": finite_median(core_iri),\n            "core_retained_abs_z_mean": finite_mean(core_retained_z),\n            "retained_metric_count": class_counts.get("retained", 0),\n            "amplified_metric_count": class_counts.get("amplified_after_refusion", 0),\n            "partial_metric_count": class_counts.get("partially_retained", 0),\n            "relaxed_metric_count": class_counts.get("relaxed", 0),\n        }\n\n        # Pull key metrics for readable summaries.\n        by_metric = {r["metric"]: r for r in rs}\n        for m in [\n            "vw_mean_T",\n            "vw_var_T",\n            "vw_mean_abs_M",\n            "vw_std_abs_M",\n            "contrast_abs_M_inside_minus_outside",\n            "contrast_R_inside_minus_outside",\n            "max_net_displacement",\n            "total_volume",\n        ]:\n            if m in by_metric:\n                row[f"{m}_IRI"] = by_metric[m]["IRI_abs_final_over_refusion"]\n                row[f"{m}_delta_refusion"] = by_metric[m]["delta_refusion_minus_initial"]\n                row[f"{m}_delta_final"] = by_metric[m]["delta_final_minus_initial"]\n\n        rows.append(row)\n\n    # Environment-level IRI ranking per threshold.\n    out: List[Dict[str, Any]] = []\n    for thr in sorted(set(r["threshold_name"] for r in rows)):\n        sub = [r for r in rows if r["threshold_name"] == thr]\n        # Composite retained-imprint score:\n        # 1) core retained magnitude z\n        # 2) mean IRI z\n        # 3) retained/amplified metric count z\n        for key in ["core_retained_abs_z_mean", "core_IRI_mean"]:\n            vals = np.asarray([to_float(r.get(key), np.nan) for r in sub], dtype=float)\n            finite = vals[np.isfinite(vals)]\n            mu = float(np.mean(finite)) if finite.size else 0.0\n            sd = float(np.std(finite)) if finite.size else 1.0\n            if sd < 1e-12:\n                sd = 1.0\n            for r in sub:\n                r[f"z_{key}"] = (to_float(r.get(key), 0.0) - mu) / sd\n\n        counts = np.asarray([to_float(r.get("retained_metric_count"), 0.0) + to_float(r.get("amplified_metric_count"), 0.0) for r in sub], dtype=float)\n        mu = float(np.mean(counts))\n        sd = float(np.std(counts))\n        if sd < 1e-12:\n            sd = 1.0\n        for r, c in zip(sub, counts):\n            r["z_retained_or_amplified_count"] = float((c - mu) / sd)\n            r["IRI_retained_imprint_score"] = (\n                to_float(r.get("z_core_retained_abs_z_mean"), 0.0)\n                + to_float(r.get("z_core_IRI_mean"), 0.0)\n                + to_float(r.get("z_retained_or_amplified_count"), 0.0)\n            )\n\n        sub = sorted(sub, key=lambda x: to_float(x.get("IRI_retained_imprint_score"), -999), reverse=True)\n        for rank, r in enumerate(sub, 1):\n            r["IRI_retention_rank"] = rank\n            out.append(r)\n\n    return out\n\n\ndef compute_threshold_summary(env_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:\n    return sorted(env_rows, key=lambda r: (\n        0 if r["threshold_name"] == "main" else (1 if r["threshold_name"] == "loose" else 2),\n        to_int(r.get("IRI_retention_rank")),\n    ))\n\n\ndef make_figures(outdir: Path, metric_rows: List[Dict[str, Any]], env_rows: List[Dict[str, Any]]) -> None:\n    if not MATPLOTLIB_AVAILABLE:\n        return\n\n    figdir = outdir / "figures"\n    figdir.mkdir(parents=True, exist_ok=True)\n\n    # Main-threshold barplots.\n    main = [r for r in env_rows if r["threshold_name"] == "main"]\n    main = sorted(main, key=lambda r: to_int(r.get("IRI_retention_rank")))\n\n    def bar_main(key: str, fname: str, ylabel: str, title: str):\n        if not main:\n            return\n        envs = [r["environment"] for r in main]\n        vals = [to_float(r.get(key), 0.0) for r in main]\n        plt.figure(figsize=(10, 5))\n        plt.bar(envs, vals)\n        plt.xticks(rotation=30, ha="right")\n        plt.ylabel(ylabel)\n        plt.title(title)\n        plt.tight_layout()\n        plt.savefig(figdir / fname, dpi=200)\n        plt.close()\n\n    bar_main("IRI_retained_imprint_score", "IRI_retained_imprint_score_main.png", "Retained-imprint score", "Final retained imprint score, main threshold")\n    bar_main("core_IRI_mean", "IRI_core_mean_main.png", "Core IRI mean", "Core metric IRI, main threshold")\n    bar_main("core_retained_abs_z_mean", "retained_core_abs_z_main.png", "Core retained |Δfinal| z", "Retained structural magnitude, main threshold")\n    bar_main("retained_metric_count", "retained_metric_count_main.png", "Metric count", "Retained metric count, main threshold")\n    bar_main("amplified_metric_count", "amplified_metric_count_main.png", "Metric count", "Amplified-after-refusion metric count, main threshold")\n\n    # Threshold-environment grouped heatmap-like plot for retained score.\n    thresholds = ["loose", "main", "strict"]\n    envs = sorted(set(r["environment"] for r in env_rows))\n    mat = np.full((len(thresholds), len(envs)), np.nan)\n    for i, thr in enumerate(thresholds):\n        for j, env in enumerate(envs):\n            match = [r for r in env_rows if r["threshold_name"] == thr and r["environment"] == env]\n            if match:\n                mat[i, j] = to_float(match[0].get("IRI_retained_imprint_score"), np.nan)\n    plt.figure(figsize=(10, 4))\n    plt.imshow(mat, aspect="auto")\n    plt.colorbar(label="Retained-imprint score")\n    plt.xticks(range(len(envs)), envs, rotation=30, ha="right")\n    plt.yticks(range(len(thresholds)), thresholds)\n    plt.title("Retained imprint score across thresholds")\n    plt.tight_layout()\n    plt.savefig(figdir / "IRI_by_threshold_environment.png", dpi=200)\n    plt.close()\n\n    # Metric heatmap for main threshold IRI.\n    selected_metrics = [\n        "vw_mean_T",\n        "vw_var_T",\n        "vw_mean_abs_M",\n        "vw_std_abs_M",\n        "contrast_abs_M_inside_minus_outside",\n        "contrast_R_inside_minus_outside",\n        "max_net_displacement",\n        "total_volume",\n    ]\n    main_m = [r for r in metric_rows if r["threshold_name"] == "main" and r["metric"] in selected_metrics]\n    envs2 = sorted(set(r["environment"] for r in main_m))\n    mat2 = np.full((len(selected_metrics), len(envs2)), np.nan)\n    for i, m in enumerate(selected_metrics):\n        for j, env in enumerate(envs2):\n            match = [r for r in main_m if r["environment"] == env and r["metric"] == m]\n            if match:\n                mat2[i, j] = to_float(match[0].get("IRI_abs_final_over_refusion"), np.nan)\n    plt.figure(figsize=(10, 6))\n    plt.imshow(mat2, aspect="auto", vmin=0)\n    plt.colorbar(label="IRI")\n    plt.xticks(range(len(envs2)), envs2, rotation=30, ha="right")\n    plt.yticks(range(len(selected_metrics)), selected_metrics)\n    plt.title("Metric-level IRI, main threshold")\n    plt.tight_layout()\n    plt.savefig(figdir / "metric_retention_heatmap_main.png", dpi=200)\n    plt.close()\n\n\ndef write_report(outdir: Path, metric_rows: List[Dict[str, Any]], env_rows: List[Dict[str, Any]], threshold_summary: List[Dict[str, Any]]) -> None:\n    lines: List[str] = []\n    lines.append("# Imprint Retention Index Analysis\\n\\n")\n    lines.append(f"Version: `{VERSION}`\\n\\n")\n    lines.append("Scope: completely post-hoc analysis of whether release-to-refusion structural changes remain until the final state.\\n\\n")\n    lines.append("Definition:\\n\\n")\n    lines.append("```text\\n")\n    lines.append("IRI = |final - initial| / (|refusion - initial| + eps)\\n")\n    lines.append("```\\n\\n")\n    lines.append("Interpretation: IRI near 0 indicates relaxation toward the initial state; IRI near 1 indicates retention; IRI greater than 1 indicates continued transformation after re-fusion.\\n\\n")\n\n    lines.append("## Environment summary\\n\\n")\n    lines.append("| threshold | rank | environment | retained score | core IRI mean | retained | amplified | relaxed | ΔT IRI | ΔM IRI | ΔM contrast IRI | Δmotion IRI |\\n")\n    lines.append("|---|---:|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|\\n")\n    for r in threshold_summary:\n        lines.append(\n            f"| {r[\'threshold_name\']} | {to_int(r.get(\'IRI_retention_rank\'))} | {r[\'environment\']} | "\n            f"{to_float(r.get(\'IRI_retained_imprint_score\')):.3f} | "\n            f"{to_float(r.get(\'core_IRI_mean\')):.3f} | "\n            f"{to_int(r.get(\'retained_metric_count\'))} | "\n            f"{to_int(r.get(\'amplified_metric_count\'))} | "\n            f"{to_int(r.get(\'relaxed_metric_count\'))} | "\n            f"{to_float(r.get(\'vw_mean_T_IRI\')):.3f} | "\n            f"{to_float(r.get(\'vw_mean_abs_M_IRI\')):.3f} | "\n            f"{to_float(r.get(\'contrast_abs_M_inside_minus_outside_IRI\')):.3f} | "\n            f"{to_float(r.get(\'max_net_displacement_IRI\')):.3f} |\\n"\n        )\n\n    # Main threshold narrative.\n    main = [r for r in threshold_summary if r["threshold_name"] == "main"]\n    main = sorted(main, key=lambda r: to_int(r.get("IRI_retention_rank")))\n    if main:\n        top = main[0]\n        lines.append("\\n## Main-threshold conclusion\\n\\n")\n        lines.append(\n            f"Under the main threshold, the highest final retained-imprint score was observed in `{top[\'environment\']}`. "\n            "This indicates that the environment-induced release-to-refusion transformation did not simply vanish at final time, but remained or continued in the final aggregate for the selected structural/internal/motion metrics.\\n\\n"\n        )\n\n    lines.append("## Interpretation boundary\\n\\n")\n    lines.append("This analysis does not test evolution. It tests whether environment-dependent structural transformation at re-fusion is retained until the final state.\\n")\n\n    (outdir / "imprint_retention_report.md").write_text("".join(lines), encoding="utf-8")\n\n\ndef parse_args() -> argparse.Namespace:\n    p = argparse.ArgumentParser()\n    p.add_argument("--posthoc-root", type=Path, required=True, help="Output root from POSTHOC_FIXED10_ENV_HISTORY_1TO4.py")\n    p.add_argument("--outdir", type=Path, required=True)\n    p.add_argument("--metrics", type=str, default="", help="Optional comma-separated metric list.")\n    p.add_argument("--eps", type=float, default=1e-9)\n    return p.parse_args()\n\n\ndef main() -> int:\n    args = parse_args()\n    root = args.posthoc_root.expanduser().resolve()\n    outdir = args.outdir.expanduser().resolve()\n    outdir.mkdir(parents=True, exist_ok=True)\n    logger = Logger(outdir)\n\n    try:\n        logger.log(f"START IRI posthoc analysis :: version={VERSION}")\n        logger.log(f"posthoc root: {root}")\n        logger.log(f"outdir: {outdir}")\n\n        phase_path = root / "ALL_threshold_environment_phase_metrics_long.csv"\n        if not phase_path.exists():\n            raise FileNotFoundError(f"required file not found: {phase_path}")\n\n        phase_rows = read_csv_rows(phase_path)\n        requested_metrics = parse_metric_list(args.metrics)\n        metrics = available_metrics(phase_rows, requested_metrics)\n\n        logger.log(f"loaded phase rows: {len(phase_rows)}")\n        logger.log(f"usable metrics: {metrics}")\n\n        with open(outdir / "IRI_parameters.json", "w", encoding="utf-8") as f:\n            json.dump(json_safe({\n                "version": VERSION,\n                "posthoc_root": root,\n                "outdir": outdir,\n                "metrics": metrics,\n                "eps": args.eps,\n                "EII_CORE_METRICS": EII_CORE_METRICS,\n            }), f, indent=2, ensure_ascii=False)\n\n        logger.log("computing metric-level IRI")\n        metric_rows = compute_iri_rows(phase_rows, metrics, args.eps)\n        write_csv(outdir / "IRI_metric_long.csv", metric_rows)\n\n        logger.log("computing environment-level IRI summary")\n        env_rows = compute_environment_summary(metric_rows)\n        write_csv(outdir / "IRI_environment_summary.csv", env_rows)\n\n        threshold_summary = compute_threshold_summary(env_rows)\n        write_csv(outdir / "IRI_threshold_summary.csv", threshold_summary)\n        write_csv(outdir / "IRI_environment_rankings.csv", threshold_summary)\n\n        logger.log("making figures")\n        make_figures(outdir, metric_rows, env_rows)\n\n        logger.log("writing report")\n        write_report(outdir, metric_rows, env_rows, threshold_summary)\n\n        logger.log("DONE")\n        logger.log(f"report: {outdir / \'imprint_retention_report.md\'}")\n        return 0\n\n    except Exception as e:\n        logger.log(f"ERROR: {type(e).__name__}: {e}")\n        (outdir / "ERROR.txt").write_text(traceback.format_exc(), encoding="utf-8")\n        return 1\n    finally:\n        logger.close()\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'GENERATE_FIXED10_ENV_HISTORY_PAPER_FIGURES_FIXED_LAYOUT.py': '#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n"""\nGENERATE_FIXED10_ENV_HISTORY_PAPER_FIGURES_FIXED_LAYOUT.py\n\nRevised publication-figure generator with overlap-safe layout:\n- larger canvas sizes\n- explicit extra bottom margins\n- legends moved outside plotting areas\n- wrapped / shortened x-axis labels\n- panel text repositioned away from borders and shapes\n- per-panel spacing tightened manually where constrained_layout was insufficient\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport csv\nimport json\nimport time\nimport traceback\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Tuple\n\nimport numpy as np\nimport matplotlib\nmatplotlib.use("Agg")\nimport matplotlib.pyplot as plt\nfrom matplotlib.patches import Circle, Rectangle, FancyArrowPatch\nfrom matplotlib.gridspec import GridSpec\n\nVERSION = "2026-06-05-paper-figures-fixed-layout-v2"\n\nENV_ORDER = [\n    "homogeneous",\n    "patchy_resource",\n    "flow_diverse",\n    "shear_diverse",\n    "residence_diverse",\n    "mixed_niche",\n]\n\nENV_LABELS = {\n    "homogeneous": "Homogeneous",\n    "patchy_resource": "Patchy\\nresource",\n    "flow_diverse": "Flow-\\ndiverse",\n    "shear_diverse": "Shear-\\ndiverse",\n    "residence_diverse": "Residence-\\ndiverse",\n    "mixed_niche": "Mixed-\\nniche",\n}\n\nVOXEL_ENVS = ["homogeneous", "shear_diverse", "residence_diverse", "mixed_niche"]\n\nplt.rcParams.update({\n    "figure.dpi": 150,\n    "savefig.dpi": 300,\n    "font.size": 10,\n    "axes.titlesize": 11,\n    "axes.labelsize": 10,\n    "xtick.labelsize": 8,\n    "ytick.labelsize": 8,\n    "legend.fontsize": 8,\n    "pdf.fonttype": 42,\n    "ps.fonttype": 42,\n})\n\n\nclass Logger:\n    def __init__(self, outdir: Path):\n        self.t0 = time.time()\n        self.outdir = outdir\n        outdir.mkdir(parents=True, exist_ok=True)\n        self.fp = open(outdir / "figure_generation_log.txt", "w", encoding="utf-8")\n\n    def log(self, msg: str) -> None:\n        line = f"[{time.time() - self.t0:9.1f}s] {msg}"\n        print(line, flush=True)\n        self.fp.write(line + "\\n")\n        self.fp.flush()\n\n    def close(self):\n        try:\n            self.fp.close()\n        except Exception:\n            pass\n\n\ndef to_float(x: Any, default: float = np.nan) -> float:\n    try:\n        if x is None or x == "":\n            return default\n        return float(x)\n    except Exception:\n        return default\n\n\ndef to_int(x: Any, default: int = 0) -> int:\n    try:\n        if x is None or x == "":\n            return default\n        return int(float(x))\n    except Exception:\n        return default\n\n\ndef read_csv_rows(path: Path) -> List[Dict[str, str]]:\n    if not path.exists():\n        return []\n    with open(path, newline="", encoding="utf-8") as f:\n        return list(csv.DictReader(f))\n\n\ndef save_figure(fig, outdir: Path, stem: str):\n    outdir.mkdir(parents=True, exist_ok=True)\n    png = outdir / f"{stem}.png"\n    pdf = outdir / f"{stem}.pdf"\n    fig.savefig(png, bbox_inches="tight", pad_inches=0.08)\n    fig.savefig(pdf, bbox_inches="tight", pad_inches=0.08)\n    plt.close(fig)\n    return png, pdf\n\n\ndef add_panel_label(ax, label: str):\n    ax.text(\n        -0.12, 1.08, label,\n        transform=ax.transAxes,\n        fontsize=13,\n        fontweight="bold",\n        va="top",\n        ha="left",\n    )\n\n\ndef env_label(env: str) -> str:\n    return ENV_LABELS.get(env, env)\n\n\ndef get_phase_steps_from_pop(pop_rows: List[Dict[str, str]]) -> Tuple[int, int, int]:\n    if not pop_rows:\n        return 0, 0, 0\n    steps = [to_int(r.get("step")) for r in pop_rows]\n    counts = [to_int(r.get("component_count")) for r in pop_rows]\n    initial = min(steps)\n    final = max(steps)\n    refusion = final\n    for st, c in zip(steps, counts):\n        if st > initial and c <= 1:\n            refusion = st\n            break\n    return initial, refusion, final\n\n\ndef load_threshold_summary(posthoc_root: Path) -> List[Dict[str, str]]:\n    for p in [\n        posthoc_root / "threshold_sensitivity_summary.csv",\n        posthoc_root / "ALL_threshold_environment_transform_rankings.csv",\n    ]:\n        rows = read_csv_rows(p)\n        if rows:\n            return rows\n    return []\n\n\ndef load_iri_summary(iri_root: Path) -> List[Dict[str, str]]:\n    for p in [\n        iri_root / "IRI_threshold_summary.csv",\n        iri_root / "IRI_environment_rankings.csv",\n        iri_root / "IRI_environment_summary.csv",\n    ]:\n        rows = read_csv_rows(p)\n        if rows:\n            return rows\n    return []\n\n\ndef finalize_axes_labels(ax):\n    for label in ax.get_xticklabels():\n        label.set_rotation(35)\n        label.set_ha("right")\n    ax.margins(x=0.05)\n\n\ndef figure_1_assay_design(outdir: Path, logger: Logger):\n    logger.log("Creating Figure 1")\n    fig = plt.figure(figsize=(17, 10))\n    gs = GridSpec(2, 3, figure=fig, height_ratios=[1.0, 1.05], hspace=0.10, wspace=0.16)\n\n    ax1 = fig.add_subplot(gs[0, 0])\n    ax2 = fig.add_subplot(gs[0, 1])\n    ax3 = fig.add_subplot(gs[0, 2])\n    ax4 = fig.add_subplot(gs[1, 0])\n    ax5 = fig.add_subplot(gs[1, 1:])\n\n    for ax in [ax1, ax2, ax3, ax4, ax5]:\n        ax.set_xticks([])\n        ax.set_yticks([])\n        ax.set_xlim(0, 1)\n        ax.set_ylim(0, 1)\n\n    # A\n    add_panel_label(ax1, "A")\n    ax1.set_title("Fixed 10-hole formation environment", pad=10)\n    ax1.add_patch(Rectangle((0.05, 0.06), 0.90, 0.88, fill=False, linewidth=1.1))\n    centers = [\n        (0.22, 0.70), (0.48, 0.72), (0.74, 0.70),\n        (0.28, 0.46), (0.48, 0.49), (0.70, 0.46),\n        (0.20, 0.22), (0.36, 0.16), (0.55, 0.22), (0.72, 0.16)\n    ]\n    for c in centers:\n        ax1.add_patch(Circle(c, 0.055, fill=False, linewidth=1.8))\n    ax1.text(0.5, 0.02, "10 identical microtopographic holes", ha="center", va="bottom", fontsize=9)\n\n    # B\n    add_panel_label(ax2, "B")\n    ax2.set_title("Local amplification inside holes", pad=10)\n    for c in centers:\n        ax2.add_patch(Circle(c, 0.055, fill=False, linewidth=1.2))\n        ax2.add_patch(Circle(c, 0.030, alpha=0.35))\n    ax2.text(0.52, 0.74, "R, L, H retention", ha="center", va="center", fontsize=9)\n    ax2.text(0.52, 0.64, "B/T membrane amplification", ha="center", va="center", fontsize=10)\n    ax2.text(0.52, 0.54, "M-field recurrence", ha="center", va="center", fontsize=10)\n    ax2.add_patch(FancyArrowPatch((0.12, 0.12), (0.88, 0.12), arrowstyle="->", mutation_scale=16))\n    ax2.text(0.50, 0.05, "preformation \\u2192 generation", ha="center", va="bottom", fontsize=10)\n\n    # C\n    add_panel_label(ax3, "C")\n    ax3.set_title("Same release state", pad=10)\n    rel = [(0.22, 0.70, 0.055), (0.30, 0.46, 0.055), (0.50, 0.49, 0.055), (0.72, 0.46, 0.045),\n           (0.20, 0.22, 0.040), (0.36, 0.16, 0.048), (0.55, 0.22, 0.055), (0.74, 0.16, 0.040)]\n    for x, y, r in rel:\n        ax3.add_patch(Circle((x, y), r, fill=False, linewidth=1.8))\n    ax3.text(0.5, 0.12, "Detected membrane components", ha="center", va="bottom", fontsize=10)\n    ax3.text(0.5, 0.04, "same initial state for all environments", ha="center", va="bottom", fontsize=10)\n\n    # D\n    add_panel_label(ax4, "D")\n    ax4.set_title("Six open-sea environmental histories", pad=10)\n    yvals = np.linspace(0.82, 0.20, len(ENV_ORDER))\n    for y, env in zip(yvals, ENV_ORDER):\n        ax4.add_patch(Rectangle((0.05, y - 0.04), 0.10, 0.09, fill=False))\n        ax4.text(0.20, y, env_label(env).replace("\\n", " "), va="center", fontsize=10)\n    ax4.text(0.5, 0.03, "formation fixed; open-sea structure varied", ha="center", va="bottom", fontsize=10)\n\n    # E\n    add_panel_label(ax5, "E")\n    ax5.set_title("Analysis timeline and outcome measures", pad=10)\n    x0, x1, x2 = 0.15, 0.50, 0.85\n    y = 0.55\n    for x, txt in [(x0, "Initial release"), (x1, "Re-fusion"), (x2, "Final")]:\n        ax5.add_patch(Circle((x, y), 0.055, fill=False, linewidth=1.8))\n        ax5.text(x, 0.40, txt, ha="center", va="top", fontsize=10)\n    ax5.add_patch(FancyArrowPatch((x0 + 0.07, y), (x1 - 0.07, y), arrowstyle="->", mutation_scale=16))\n    ax5.add_patch(FancyArrowPatch((x1 + 0.07, y), (x2 - 0.07, y), arrowstyle="->", mutation_scale=16))\n    ax5.text(0.33, 0.70, "EII\\nrelease \\u2192 re-fusion", ha="center", fontsize=11)\n    ax5.text(0.67, 0.70, "IRI\\nre-fusion \\u2192 final", ha="center", fontsize=11)\n    ax5.text(0.5, 0.20, "component count, trait diversity, membrane T, internal |M|, motion",\n             ha="center", va="center", fontsize=10)\n\n    fig.subplots_adjust(left=0.05, right=0.985, top=0.95, bottom=0.06)\n    return save_figure(fig, outdir, "Figure_1_assay_design")\n\n\ndef figure_2_transient_diversity(root: Path, outdir: Path, logger: Logger):\n    logger.log("Creating Figure 2")\n    fig = plt.figure(figsize=(18, 11))\n    gs = GridSpec(2, 3, figure=fig, hspace=0.34, wspace=0.28)\n\n    axA = fig.add_subplot(gs[0, 0])\n    axB = fig.add_subplot(gs[0, 1])\n    axC = fig.add_subplot(gs[0, 2])\n    axD = fig.add_subplot(gs[1, 0])\n    axE = fig.add_subplot(gs[1, 1])\n    axF = fig.add_subplot(gs[1, 2])\n\n    summary_rows = []\n    for env in ENV_ORDER:\n        pop = read_csv_rows(root / env / "population_diversity_timeseries.csv")\n        events = read_csv_rows(root / env / "component_events.csv")\n        if not pop:\n            continue\n        steps = [to_int(r.get("step")) for r in pop]\n        counts = [to_float(r.get("component_count")) for r in pop]\n        dists = [to_float(r.get("mean_pairwise_trait_distance")) for r in pop]\n        initial, refusion, final = get_phase_steps_from_pop(pop)\n        fusion_count = sum(1 for e in events if e.get("event_type") == "fusion_into_component")\n        trait_auc = float(np.trapezoid(np.asarray(dists), np.asarray(steps))) if len(steps) > 1 else 0.0\n        summary_rows.append({\n            "env": env, "refusion": refusion, "fusion_count": fusion_count,\n            "trait_auc": trait_auc, "max_count": max(counts) if counts else 0, "max_dist": max(dists) if dists else 0\n        })\n        axA.plot(steps, counts, label=env_label(env).replace("\\n", " "), linewidth=1.8)\n        axB.plot(steps, dists, label=env_label(env).replace("\\n", " "), linewidth=1.8)\n\n    add_panel_label(axA, "A")\n    axA.set_title("Component count over time")\n    axA.set_xlabel("Open-sea step")\n    axA.set_ylabel("Component count")\n\n    add_panel_label(axB, "B")\n    axB.set_title("Trait diversity over time")\n    axB.set_xlabel("Open-sea step")\n    axB.set_ylabel("Mean pairwise trait distance")\n    axB.legend(loc="center left", bbox_to_anchor=(1.02, 0.5), frameon=False, borderaxespad=0.)\n\n    envs = [env_label(r["env"]) for r in summary_rows]\n    x = np.arange(len(envs))\n\n    add_panel_label(axC, "C")\n    axC.bar(x, [r["refusion"] for r in summary_rows])\n    axC.set_title("Time to re-fusion")\n    axC.set_ylabel("Step")\n    axC.set_xticks(x)\n    axC.set_xticklabels(envs)\n    finalize_axes_labels(axC)\n\n    add_panel_label(axD, "D")\n    axD.bar(x, [r["fusion_count"] for r in summary_rows])\n    axD.set_title("Fusion events")\n    axD.set_ylabel("Count")\n    axD.set_xticks(x)\n    axD.set_xticklabels(envs)\n    finalize_axes_labels(axD)\n\n    add_panel_label(axE, "E")\n    axE.bar(x, [r["trait_auc"] for r in summary_rows])\n    axE.set_title("Trait-distance AUC")\n    axE.set_ylabel("AUC")\n    axE.set_xticks(x)\n    axE.set_xticklabels(envs)\n    finalize_axes_labels(axE)\n\n    add_panel_label(axF, "F")\n    axF.bar(x, [r["max_dist"] for r in summary_rows])\n    axF.set_title("Maximum trait distance")\n    axF.set_ylabel("Distance")\n    axF.set_xticks(x)\n    axF.set_xticklabels(envs)\n    finalize_axes_labels(axF)\n\n    fig.subplots_adjust(left=0.06, right=0.93, top=0.95, bottom=0.14)\n    return save_figure(fig, outdir, "Figure_2_transient_diversity_refusion")\n\n\ndef figure_3_eii(posthoc_root: Path, outdir: Path, logger: Logger):\n    logger.log("Creating Figure 3")\n    rows = load_threshold_summary(posthoc_root)\n    if not rows:\n        raise FileNotFoundError("Could not find threshold summary for Figure 3")\n\n    fig = plt.figure(figsize=(18, 11))\n    gs = GridSpec(2, 3, figure=fig, hspace=0.36, wspace=0.28)\n    axA = fig.add_subplot(gs[0, 0])\n    axB = fig.add_subplot(gs[0, 1:])\n    axC = fig.add_subplot(gs[1, 0])\n    axD = fig.add_subplot(gs[1, 1])\n    axE = fig.add_subplot(gs[1, 2])\n\n    main = [r for r in rows if r.get("threshold_name") == "main" or r.get("threshold") == "main"]\n    main = sorted(main, key=lambda r: to_int(r.get("rank", r.get("EII_rank", 999))))\n    envs = [env_label(r["environment"]) for r in main]\n    x = np.arange(len(envs))\n\n    add_panel_label(axA, "A")\n    axA.bar(x, [to_float(r.get("EII", r.get("EII_environmental_imprint_index"))) for r in main])\n    axA.set_title("EII ranking, main threshold")\n    axA.set_ylabel("EII")\n    axA.set_xticks(x)\n    axA.set_xticklabels(envs)\n    finalize_axes_labels(axA)\n\n    add_panel_label(axB, "B")\n    thresholds = ["loose", "main", "strict"]\n    width = 0.24\n    for i, thr in enumerate(thresholds):\n        sub = [r for r in rows if r.get("threshold_name") == thr or r.get("threshold") == thr]\n        byenv = {r["environment"]: r for r in sub}\n        vals = [to_float(byenv.get(env, {}).get("EII", byenv.get(env, {}).get("EII_environmental_imprint_index"))) for env in ENV_ORDER]\n        axB.bar(np.arange(len(ENV_ORDER)) + (i - 1) * width, vals, width=width, label=thr)\n    axB.set_title("EII threshold sensitivity")\n    axB.set_ylabel("EII")\n    axB.set_xticks(np.arange(len(ENV_ORDER)))\n    axB.set_xticklabels([env_label(e) for e in ENV_ORDER])\n    finalize_axes_labels(axB)\n    axB.legend(loc="center left", bbox_to_anchor=(1.01, 0.5), frameon=False, borderaxespad=0.)\n\n    add_panel_label(axC, "C")\n    axC.bar(x, [to_float(r.get("trait AUC", r.get("trait_distance_auc"))) for r in main])\n    axC.set_title("Trait-distance AUC")\n    axC.set_ylabel("AUC")\n    axC.set_xticks(x)\n    axC.set_xticklabels(envs)\n    finalize_axes_labels(axC)\n\n    add_panel_label(axD, "D")\n    axD.bar(x, [to_float(r.get("refusion step", r.get("time_to_refusion"))) for r in main])\n    axD.set_title("Re-fusion step")\n    axD.set_ylabel("Step")\n    axD.set_xticks(x)\n    axD.set_xticklabels(envs)\n    finalize_axes_labels(axD)\n\n    add_panel_label(axE, "E")\n    axE.bar(x, [to_float(r.get("fusion events", r.get("fusion_event_count"))) for r in main])\n    axE.set_title("Fusion events")\n    axE.set_ylabel("Count")\n    axE.set_xticks(x)\n    axE.set_xticklabels(envs)\n    finalize_axes_labels(axE)\n\n    fig.subplots_adjust(left=0.06, right=0.90, top=0.95, bottom=0.14)\n    return save_figure(fig, outdir, "Figure_3_EII_threshold_robustness")\n\n\ndef figure_4_structural_remodeling(posthoc_root: Path, outdir: Path, logger: Logger):\n    logger.log("Creating Figure 4")\n    rows = read_csv_rows(posthoc_root / "ALL_threshold_environment_refusion_transform_summary.csv")\n    if not rows:\n        rows = read_csv_rows(posthoc_root / "threshold_main" / "environment_refusion_transform_summary.csv")\n    main = [r for r in rows if r.get("threshold_name") == "main"] or rows\n    byenv = {r["environment"]: r for r in main}\n\n    metrics = [\n        ("component_total_volume_delta", "Δvolume"),\n        ("component_vw_mean_B_delta", "Δmean B"),\n        ("component_vw_mean_T_delta", "Δmean T"),\n        ("component_vw_var_T_delta", "Δvar T"),\n        ("component_vw_mean_abs_M_delta", "Δmean |M|"),\n        ("component_vw_std_abs_M_delta", "ΔSD |M|"),\n        ("snapshot_contrast_abs_M_inside_minus_outside_delta", "Δinside–outside |M| contrast"),\n        ("component_max_net_displacement_delta", "Δmax net displacement"),\n    ]\n\n    fig = plt.figure(figsize=(20, 11))\n    gs = GridSpec(2, 4, figure=fig, hspace=0.42, wspace=0.32)\n    envs = [env_label(e) for e in ENV_ORDER]\n    x = np.arange(len(envs))\n\n    for idx, (key, title) in enumerate(metrics):\n        ax = fig.add_subplot(gs[idx // 4, idx % 4])\n        vals = [to_float(byenv.get(e, {}).get(key)) for e in ENV_ORDER]\n        ax.bar(x, vals)\n        ax.axhline(0, linewidth=0.8)\n        ax.set_title(title)\n        ax.set_xticks(x)\n        ax.set_xticklabels(envs)\n        finalize_axes_labels(ax)\n        if idx in (0, 4):\n            ax.set_ylabel("Release-to-re-fusion change")\n        add_panel_label(ax, chr(ord("A") + idx))\n\n    fig.subplots_adjust(left=0.05, right=0.985, top=0.95, bottom=0.14)\n    return save_figure(fig, outdir, "Figure_4_structural_remodeling")\n\n\ndef figure_5_iri(iri_root: Path, outdir: Path, logger: Logger):\n    logger.log("Creating Figure 5")\n    rows = load_iri_summary(iri_root)\n    if not rows:\n        raise FileNotFoundError("Could not find IRI summary for Figure 5")\n\n    main = [r for r in rows if r.get("threshold_name") == "main" or r.get("threshold") == "main"]\n    main = sorted(main, key=lambda r: to_int(r.get("rank", r.get("IRI_retention_rank", 999))))\n    byenv_main = {r["environment"]: r for r in main}\n\n    fig = plt.figure(figsize=(18, 11))\n    gs = GridSpec(2, 3, figure=fig, hspace=0.38, wspace=0.30)\n\n    axA = fig.add_subplot(gs[0, 0])\n    axB = fig.add_subplot(gs[0, 1])\n    axC = fig.add_subplot(gs[0, 2])\n    axD = fig.add_subplot(gs[1, 0])\n    axE = fig.add_subplot(gs[1, 1])\n    axF = fig.add_subplot(gs[1, 2])\n\n    envs = [env_label(e) for e in ENV_ORDER]\n    x = np.arange(len(envs))\n\n    # A\n    add_panel_label(axA, "A")\n    axA.set_title("Imprint Retention Index")\n    axA.set_xlim(0, 1)\n    axA.set_ylim(0, 1)\n    axA.set_xticks([])\n    axA.set_yticks([])\n    for xpos, txt in [(0.15, "Initial"), (0.50, "Re-fusion"), (0.85, "Final")]:\n        axA.add_patch(Circle((xpos, 0.55), 0.055, fill=False, linewidth=1.5))\n        axA.text(xpos, 0.38, txt, ha="center", va="top", fontsize=10)\n    axA.add_patch(FancyArrowPatch((0.23, 0.55), (0.42, 0.55), arrowstyle="->", mutation_scale=14))\n    axA.add_patch(FancyArrowPatch((0.58, 0.55), (0.77, 0.55), arrowstyle="->", mutation_scale=14))\n    axA.text(0.50, 0.16, "IRI = |final − initial| / |re-fusion − initial|", ha="center", fontsize=10)\n\n    # B\n    add_panel_label(axB, "B")\n    axB.bar(x, [to_float(byenv_main.get(e, {}).get("retained score", byenv_main.get(e, {}).get("IRI_retained_imprint_score"))) for e in ENV_ORDER])\n    axB.set_title("Retained-imprint score, main")\n    axB.set_ylabel("Score")\n    axB.set_xticks(x)\n    axB.set_xticklabels(envs)\n    finalize_axes_labels(axB)\n\n    # C\n    add_panel_label(axC, "C")\n    thresholds = ["loose", "main", "strict"]\n    width = 0.24\n    for i, thr in enumerate(thresholds):\n        sub = [r for r in rows if r.get("threshold_name") == thr or r.get("threshold") == thr]\n        byenv = {r["environment"]: r for r in sub}\n        vals = [to_float(byenv.get(e, {}).get("retained score", byenv.get(e, {}).get("IRI_retained_imprint_score"))) for e in ENV_ORDER]\n        axC.bar(np.arange(len(ENV_ORDER)) + (i - 1) * width, vals, width=width, label=thr)\n    axC.set_title("IRI threshold sensitivity")\n    axC.set_ylabel("Retained-imprint score")\n    axC.set_xticks(np.arange(len(ENV_ORDER)))\n    axC.set_xticklabels(envs)\n    finalize_axes_labels(axC)\n    axC.legend(loc="center left", bbox_to_anchor=(1.01, 0.5), frameon=False, borderaxespad=0.)\n\n    # D\n    add_panel_label(axD, "D")\n    axD.bar(x, [to_float(byenv_main.get(e, {}).get("core IRI mean", byenv_main.get(e, {}).get("core_IRI_mean"))) for e in ENV_ORDER])\n    axD.set_title("Core IRI mean")\n    axD.set_ylabel("IRI")\n    axD.set_xticks(x)\n    axD.set_xticklabels(envs)\n    finalize_axes_labels(axD)\n\n    # E\n    add_panel_label(axE, "E")\n    retained = [to_float(byenv_main.get(e, {}).get("retained", byenv_main.get(e, {}).get("retained_metric_count"))) for e in ENV_ORDER]\n    amplified = [to_float(byenv_main.get(e, {}).get("amplified", byenv_main.get(e, {}).get("amplified_metric_count"))) for e in ENV_ORDER]\n    relaxed = [to_float(byenv_main.get(e, {}).get("relaxed", byenv_main.get(e, {}).get("relaxed_metric_count"))) for e in ENV_ORDER]\n    axE.bar(x, retained, label="Retained")\n    axE.bar(x, amplified, bottom=retained, label="Amplified")\n    bottoms = np.asarray(retained) + np.asarray(amplified)\n    axE.bar(x, relaxed, bottom=bottoms, label="Relaxed")\n    axE.set_title("Metric retention classes")\n    axE.set_ylabel("Metric count")\n    axE.set_xticks(x)\n    axE.set_xticklabels(envs)\n    finalize_axes_labels(axE)\n    axE.legend(loc="center left", bbox_to_anchor=(1.01, 0.5), frameon=False, borderaxespad=0.)\n\n    # F\n    add_panel_label(axF, "F")\n    width = 0.18\n    metric_keys = [\n        ("ΔT IRI", "vw_mean_T_IRI"),\n        ("ΔM IRI", "vw_mean_abs_M_IRI"),\n        ("ΔM contrast IRI", "contrast_abs_M_inside_minus_outside_IRI"),\n        ("Δmotion IRI", "max_net_displacement_IRI"),\n    ]\n    for i, (label, key) in enumerate(metric_keys):\n        vals = [to_float(byenv_main.get(e, {}).get(label, byenv_main.get(e, {}).get(key))) for e in ENV_ORDER]\n        axF.bar(np.arange(len(ENV_ORDER)) + (i - 1.5) * width, vals, width=width, label=label)\n    axF.axhline(1.0, linewidth=0.8)\n    axF.set_title("Selected metric-level IRI")\n    axF.set_ylabel("IRI")\n    axF.set_xticks(np.arange(len(ENV_ORDER)))\n    axF.set_xticklabels(envs)\n    finalize_axes_labels(axF)\n    axF.legend(loc="center left", bbox_to_anchor=(1.01, 0.5), frameon=False, borderaxespad=0.)\n\n    fig.subplots_adjust(left=0.06, right=0.88, top=0.95, bottom=0.14)\n    return save_figure(fig, outdir, "Figure_5_IRI_retention")\n\n\ndef load_npz_snapshot(root: Path, env: str, step: int):\n    sp = root / env / "open_sea_snapshots" / f"open_sea_step_{step:06d}.npz"\n    with np.load(sp, allow_pickle=False) as data:\n        B = data["B"].astype(np.float32)\n        T = data["T"].astype(np.float32)\n        M = data["M"].astype(np.float32)\n    return B, T, M\n\n\ndef figure_6_voxel_restructuring(root: Path, posthoc_root: Path, outdir: Path, logger: Logger):\n    logger.log("Creating Figure 6")\n    phase_rows = read_csv_rows(posthoc_root / "ALL_threshold_environment_phase_metrics_long.csv")\n    if not phase_rows:\n        phase_rows = read_csv_rows(posthoc_root / "threshold_main" / "environment_phase_metrics_long.csv")\n    phase_rows = [r for r in phase_rows if r.get("threshold_name", "main") == "main"]\n\n    phase_index: Dict[Tuple[str, str], int] = {}\n    for r in phase_rows:\n        env = r.get("environment")\n        phase = r.get("phase")\n        if env and phase:\n            phase_index[(env, phase)] = to_int(r.get("step"))\n\n    fig = plt.figure(figsize=(20, 13))\n    gs = GridSpec(len(VOXEL_ENVS), 6, figure=fig, hspace=0.18, wspace=0.10)\n    col_titles = ["Initial T", "Re-fusion T", "Final T", "Initial |M|", "Re-fusion |M|", "Final |M|"]\n\n    for row_idx, env in enumerate(VOXEL_ENVS):\n        steps = [\n            phase_index.get((env, "initial"), 0),\n            phase_index.get((env, "refusion"), 0),\n            phase_index.get((env, "final"), 1800),\n        ]\n\n        Bf, Tf, Mf = load_npz_snapshot(root, env, steps[2])\n        z_scores = (Bf + Tf).sum(axis=(0, 1))\n        z = int(np.argmax(z_scores))\n        panels = []\n        for step in steps:\n            B, T, M = load_npz_snapshot(root, env, step)\n            panels.append((T[:, :, z], np.abs(M[:, :, z]), step))\n\n        for col_idx in range(6):\n            ax = fig.add_subplot(gs[row_idx, col_idx])\n            phase_id = col_idx % 3\n            field_id = 0 if col_idx < 3 else 1\n            arr = panels[phase_id][field_id]\n            im = ax.imshow(arr)\n            ax.set_xticks([])\n            ax.set_yticks([])\n            if row_idx == 0:\n                ax.set_title(col_titles[col_idx], pad=8)\n            if col_idx == 0:\n                ax.set_ylabel(env_label(env).replace("\\n", " "), rotation=90, labelpad=14)\n                add_panel_label(ax, chr(ord("A") + row_idx))\n            ax.text(\n                0.02, 0.96, f"step {panels[phase_id][2]}\\nz={z}",\n                transform=ax.transAxes, va="top", ha="left", fontsize=7,\n                bbox=dict(boxstyle="round", facecolor="white", alpha=0.65, linewidth=0.4),\n            )\n            if col_idx in (2, 5):\n                cbar = fig.colorbar(im, ax=ax, fraction=0.046, pad=0.02)\n                cbar.ax.tick_params(labelsize=7)\n\n    fig.subplots_adjust(left=0.05, right=0.985, top=0.96, bottom=0.04)\n    return save_figure(fig, outdir, "Figure_6_voxel_restructuring")\n\n\ndef write_manifest(outdir: Path, created: List[Tuple[str, Path, Path]]):\n    lines = []\n    lines.append("# Figure manifest\\n\\n")\n    lines.append(f"Version: `{VERSION}`\\n\\n")\n    for label, png, pdf in created:\n        lines.append(f"- **{label}**\\n")\n        lines.append(f"  - PNG: `{png.name}`\\n")\n        lines.append(f"  - PDF: `{pdf.name}`\\n")\n    (outdir / "figure_manifest.md").write_text("".join(lines), encoding="utf-8")\n\n\ndef parse_args():\n    p = argparse.ArgumentParser()\n    p.add_argument("--root", type=Path, required=True)\n    p.add_argument("--posthoc-root", type=Path, required=True)\n    p.add_argument("--iri-root", type=Path, required=True)\n    p.add_argument("--outdir", type=Path, required=True)\n    p.add_argument("--skip-voxel", action="store_true")\n    return p.parse_args()\n\n\ndef main() -> int:\n    args = parse_args()\n    root = args.root.expanduser().resolve()\n    posthoc_root = args.posthoc_root.expanduser().resolve()\n    iri_root = args.iri_root.expanduser().resolve()\n    outdir = args.outdir.expanduser().resolve()\n    outdir.mkdir(parents=True, exist_ok=True)\n    logger = Logger(outdir)\n    try:\n        logger.log(f"START paper figure generation :: version={VERSION}")\n        logger.log(f"root: {root}")\n        logger.log(f"posthoc root: {posthoc_root}")\n        logger.log(f"iri root: {iri_root}")\n        logger.log(f"outdir: {outdir}")\n\n        with open(outdir / "figure_generation_parameters.json", "w", encoding="utf-8") as f:\n            json.dump({\n                "version": VERSION,\n                "root": str(root),\n                "posthoc_root": str(posthoc_root),\n                "iri_root": str(iri_root),\n                "outdir": str(outdir),\n                "skip_voxel": bool(args.skip_voxel),\n            }, f, indent=2)\n\n        created = []\n        created.append(("Figure 1", *figure_1_assay_design(outdir, logger)))\n        created.append(("Figure 2", *figure_2_transient_diversity(root, outdir, logger)))\n        created.append(("Figure 3", *figure_3_eii(posthoc_root, outdir, logger)))\n        created.append(("Figure 4", *figure_4_structural_remodeling(posthoc_root, outdir, logger)))\n        created.append(("Figure 5", *figure_5_iri(iri_root, outdir, logger)))\n        if not args.skip_voxel:\n            created.append(("Figure 6", *figure_6_voxel_restructuring(root, posthoc_root, outdir, logger)))\n        write_manifest(outdir, created)\n        logger.log("DONE")\n        return 0\n    except Exception as e:\n        logger.log(f"ERROR: {type(e).__name__}: {e}")\n        (outdir / "ERROR.txt").write_text(traceback.format_exc(), encoding="utf-8")\n        return 1\n    finally:\n        logger.close()\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n'}
ORDER = ['FULL_OPEN_SEA_FIXED10HOLES_ENV_SWEEP.py', 'POSTHOC_FIXED10_ENV_HISTORY_1TO4.py', 'POSTHOC_IMPRINT_RETENTION_IRI.py', 'GENERATE_FIXED10_ENV_HISTORY_PAPER_FIGURES_FIXED_LAYOUT.py']


class Logger:
    def __init__(self, outdir: Path):
        outdir.mkdir(parents=True, exist_ok=True)
        self.t0 = time.time()
        self.path = outdir / "main_analysis_progress.log"
        self.fp = open(self.path, "w", encoding="utf-8")

    def log(self, msg: str) -> None:
        line = f"[{time.time() - self.t0:9.1f}s] {msg}"
        print(line, flush=True)
        self.fp.write(line + "\n")
        self.fp.flush()

    def close(self) -> None:
        try:
            self.fp.close()
        except Exception:
            pass


def write_embedded_scripts(runtime_dir: Path) -> dict[str, Path]:
    runtime_dir.mkdir(parents=True, exist_ok=True)
    paths = {}
    for name in ORDER:
        path = runtime_dir / name
        path.write_text(SCRIPTS[name], encoding="utf-8")
        path.chmod(0o755)
        paths[name] = path
    return paths


def run_cmd(cmd: list[str], log_path: Path, logger: Logger) -> None:
    logger.log("RUN: " + " ".join(str(x) for x in cmd))
    with open(log_path, "w", encoding="utf-8") as fp:
        fp.write("RUN: " + " ".join(str(x) for x in cmd) + "\n\n")
        fp.flush()
        proc = subprocess.run(cmd, stdout=fp, stderr=subprocess.STDOUT)
    if proc.returncode != 0:
        raise RuntimeError(f"command failed with return code {proc.returncode}; see {log_path}")


def write_manifest(outdir: Path, paths: dict[str, Path]) -> None:
    rows = []
    for name, path in paths.items():
        rows.append({
            "filename": name,
            "runtime_path": str(path),
            "size_bytes": path.stat().st_size,
        })
    (outdir / "embedded_manifest.json").write_text(json.dumps(rows, indent=2), encoding="utf-8")



def parse_args() -> argparse.Namespace:
    p = argparse.ArgumentParser()
    p.add_argument("--mode", choices=["smoke", "quick", "full"], default="full")
    p.add_argument("--seed", type=int, default=12345)
    p.add_argument("--outdir", type=Path, required=True)
    p.add_argument("--detect-lumens", action="store_true")
    p.add_argument("--skip-figures", action="store_true")
    p.add_argument("--skip-voxel-figure", action="store_true")
    p.add_argument("--main-extra-args", nargs=argparse.REMAINDER, default=[])
    return p.parse_args()


def main() -> int:
    args = parse_args()
    outdir = args.outdir.expanduser().resolve()
    logger = Logger(outdir)
    try:
        logger.log("START main analysis pipeline")
        runtime_dir = outdir / "_embedded_main_scripts"
        paths = write_embedded_scripts(runtime_dir)
        write_manifest(outdir, paths)

        main_root = outdir / "main_run"
        posthoc_root = outdir / "posthoc_EII_threshold"
        iri_root = outdir / "posthoc_IRI"
        fig_root = outdir / "figures"

        cmd = [
            sys.executable, "-u", str(paths["FULL_OPEN_SEA_FIXED10HOLES_ENV_SWEEP.py"]),
            "--mode", args.mode,
            "--seed", str(args.seed),
            "--outdir", str(main_root),
        ] + list(args.main_extra_args or [])
        run_cmd(cmd, outdir / "01_main_simulation.log", logger)

        cmd = [
            sys.executable, "-u", str(paths["POSTHOC_FIXED10_ENV_HISTORY_1TO4.py"]),
            "--root", str(main_root),
            "--outdir", str(posthoc_root),
        ]
        if args.detect_lumens:
            cmd.append("--detect-lumens")
        run_cmd(cmd, outdir / "02_posthoc_EII_threshold.log", logger)

        cmd = [
            sys.executable, "-u", str(paths["POSTHOC_IMPRINT_RETENTION_IRI.py"]),
            "--posthoc-root", str(posthoc_root),
            "--outdir", str(iri_root),
        ]
        run_cmd(cmd, outdir / "03_posthoc_IRI.log", logger)

        if not args.skip_figures:
            cmd = [
                sys.executable, "-u", str(paths["GENERATE_FIXED10_ENV_HISTORY_PAPER_FIGURES_FIXED_LAYOUT.py"]),
                "--root", str(main_root),
                "--posthoc-root", str(posthoc_root),
                "--iri-root", str(iri_root),
                "--outdir", str(fig_root),
            ]
            if args.skip_voxel_figure:
                cmd.append("--skip-voxel")
            run_cmd(cmd, outdir / "04_generate_figures.log", logger)

        report = outdir / "MAIN_ANALYSIS_REPORT.md"
        report.write_text(
            "# Main analysis pipeline report\n\n"
            f"Mode: `{args.mode}`\n\n"
            f"Seed: `{args.seed}`\n\n"
            "Outputs:\n\n"
            f"- Main simulation: `{main_root}`\n"
            f"- EII / threshold post hoc: `{posthoc_root}`\n"
            f"- IRI post hoc: `{iri_root}`\n"
            f"- Figures: `{fig_root}`\n",
            encoding="utf-8",
        )
        logger.log("DONE main analysis pipeline")
        return 0
    except Exception as e:
        logger.log(f"ERROR: {type(e).__name__}: {e}")
        (outdir / "ERROR.txt").write_text(traceback.format_exc(), encoding="utf-8")
        return 1
    finally:
        logger.close()



if __name__ == "__main__":
    raise SystemExit(main())
